fn show_cheat_archive_context(
    ui: &mut egui::Ui,
    workflow: &CheatWorkflowState,
    live: Option<&LoadedData>,
    cached: Option<&CachedLibrarySnapshot>,
    clipboard: &mut dyn ClipboardBackend,
) {
    let record = live.and_then(|data| {
        data.records
            .iter()
            .find(|record| record.mount_plan.archive.path == workflow.archive_path)
    });
    let persisted = selected_persisted_archive(cached, Some(&workflow.archive_path));
    widgets::section_header(
        ui,
        if record.is_some_and(|record| !record.is_mount_input()) {
            "Selected loose-ROM context"
        } else {
            "Selected archive context"
        },
        Some(
            "This exact library item remains selected; opening this workspace changes no mount, queue, or platform state.",
        ),
    );
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            ui.label(
                egui::RichText::new(&workflow.display_name)
                    .size(19.0)
                    .strong(),
            );
            widgets::status_badge(
                ui,
                persisted
                    .and_then(|archive| archive.platform.as_deref())
                    .or(workflow.platform.as_deref())
                    .unwrap_or("Unknown platform"),
                widgets::StatusTone::Info,
            );
            if let Some(record) = record {
                if !record.is_mount_input() {
                    widgets::status_badge(ui, "Media kind · Loose ROM", widgets::StatusTone::Info);
                }
                widgets::status_badge(
                    ui,
                    mount_validation_label(record.mount_state),
                    match record.mount_state {
                        MountState::Mounted => widgets::StatusTone::Active,
                        MountState::Pending => widgets::StatusTone::Success,
                        MountState::MountPathExists => widgets::StatusTone::Warning,
                        MountState::NotMountable => widgets::StatusTone::Info,
                    },
                );
            }
            if persisted.is_some_and(|archive| {
                archive.platform_source.as_deref() == Some(MANUAL_PLATFORM_SOURCE)
            }) {
                widgets::status_badge(ui, "Manual platform assignment", widgets::StatusTone::Info);
            }
            ui.label(egui::RichText::new(format_size(workflow.size_bytes)).color(theme::muted(ui)));
        });
        if widgets::path_value(
            ui,
            if record.is_some_and(|record| !record.is_mount_input()) {
                "ROM file"
            } else {
                "Archive"
            },
            &workflow.archive_path,
        ) {
            let _ = clipboard.set_text(workflow.archive_path.display().to_string());
        }
        if widgets::path_value(ui, "Source", &workflow.source_root) {
            let _ = clipboard.set_text(workflow.source_root.display().to_string());
        }
        if let Some(record) = record.filter(|record| record.is_mount_input())
            && widgets::path_value(ui, "Mount destination", &record.mount_plan.mount_path)
        {
            let _ = clipboard.set_text(record.mount_plan.mount_path.display().to_string());
        }
    });
}

fn show_recent_cheat_activity(
    ui: &mut egui::Ui,
    history: &OperationHistory,
    archive_path: Option<&Path>,
) {
    let entries: Vec<&HistoryEntry> = history
        .entries()
        .filter(|entry| {
            entry.action == ActivityAction::RetroArchProfileScan
                || entry.action == ActivityAction::Pcsx2ProfileScan
                || (matches!(
                    entry.action,
                    ActivityAction::CheatSourceRetrieval | ActivityAction::Pcsx2PnachInspection
                ) && archive_path.is_some()
                    && entry.archive_path.as_deref() == archive_path)
        })
        .take(4)
        .collect();
    widgets::section_header(
        ui,
        "Recent related activity",
        Some(
            "A compact view of this session's emulator profile scans, local PNACH inspection, and trusted catalogue retrieval.",
        ),
    );
    if entries.is_empty() {
        ui.weak("No related activity has been recorded in this session.");
        return;
    }
    for entry in entries {
        widgets::card(ui, |ui| {
            widgets::activity_row_header(
                ui,
                entry.outcome.to_string(),
                activity_outcome_tone(entry.outcome),
                entry.action.to_string(),
                Some(&format_history_timestamp(entry.timestamp)),
                |_ui| {},
            );
            ui.add(egui::Label::new(&entry.message).truncate())
                .on_hover_text(&entry.message);
        });
        ui.add_space(4.0);
    }
}

fn show_mods_section(ui: &mut egui::Ui, pcsx2_read_only: bool, dolphin_read_only: bool) {
    widgets::section_header(
        ui,
        "Mods",
        Some("A stable future home for verified, emulator-specific mod adapters."),
    );
    widgets::card(ui, |ui| {
        if pcsx2_read_only {
            widgets::status_badge(ui, "Read-only inventory", widgets::StatusTone::Info);
            ui.label("PCSX2 widescreen and other PNACH patch directories can be inspected above. Preview, installation, enabling, disabling, replacement, and rollback are unavailable.");
        } else if dolphin_read_only {
            widgets::status_badge(ui, "Read-only inventory", widgets::StatusTone::Info);
            ui.label("Dolphin frame patches, Action Replay, Gecko, and Riivolution declarations can be inspected above. Installation, enabling, disabling, replacement, and rollback are unavailable.");
        } else {
            widgets::status_badge(ui, "Planned", widgets::StatusTone::Pending);
            ui.label(MODS_UNAVAILABLE_BODY);
        }
    });
}

fn platform_is_ps2(platform: Option<&str>) -> bool {
    platform.is_some_and(|platform| platform.eq_ignore_ascii_case("PS2"))
}

fn platform_is_dolphin(platform: Option<&str>) -> bool {
    platform.is_some_and(|platform| {
        ["GameCube", "Nintendo GameCube", "Wii", "Nintendo Wii"]
            .iter()
            .any(|candidate| platform.eq_ignore_ascii_case(candidate))
    })
}

/// The adapter's short, single-line description shown below the tab row
/// for whichever system is currently selected - the same copy each
/// option's card used to show unconditionally, now shown only for the
/// active choice since the stages below already explain that system in
/// full detail.
fn cheat_emulator_adapter_description(adapter: CheatEmulatorAdapter) -> &'static str {
    match adapter {
        CheatEmulatorAdapter::RetroArch => {
            "Profile discovery, existing cheat-directory inventory, and trusted catalogue retrieval."
        }
        CheatEmulatorAdapter::Pcsx2 => {
            "Discovers local PCSX2 profiles and inspects existing PNACH files with fixed resource limits."
        }
        CheatEmulatorAdapter::Dolphin => {
            "Discovers local Dolphin profiles and inspects existing GameSettings INI files with fixed resource limits."
        }
    }
}

fn show_cheat_emulator_adapter_selector(
    ui: &mut egui::Ui,
    workflow: &CheatWorkflowState,
) -> Option<CheatWorkflowAction> {
    widgets::section_header(
        ui,
        "Choose a system",
        Some(
            "The adapter is separate from the archive, source, profile, destination, and installation state.",
        ),
    );
    let mut options = vec![(CheatEmulatorAdapter::RetroArch, "RetroArch")];
    if platform_is_ps2(workflow.platform.as_deref()) {
        options.push((CheatEmulatorAdapter::Pcsx2, "PCSX2"));
    }
    if platform_is_dolphin(workflow.platform.as_deref()) {
        options.push((CheatEmulatorAdapter::Dolphin, "Dolphin"));
    }
    let clicked = widgets::card(ui, |ui| {
        let clicked = widgets::tab_row(ui, &options, workflow.adapter);
        match workflow.adapter {
            CheatEmulatorAdapter::Pcsx2 => {
                widgets::status_strip(
                    ui,
                    &[
                        ("PS2 only", widgets::StatusTone::Info),
                        ("Read-only", widgets::StatusTone::Success),
                    ],
                );
            }
            CheatEmulatorAdapter::Dolphin => {
                widgets::status_strip(
                    ui,
                    &[
                        ("GameCube / Wii", widgets::StatusTone::Info),
                        ("Read-only", widgets::StatusTone::Success),
                    ],
                );
            }
            CheatEmulatorAdapter::RetroArch => {}
        }
        ui.label(cheat_emulator_adapter_description(workflow.adapter));
        clicked
    });
    clicked
        .filter(|selected| *selected != workflow.adapter)
        .map(CheatWorkflowAction::SelectAdapter)
}

fn show_pcsx2_workflow(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profiles: &Pcsx2ProfilesState,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    widgets::section_header(
        ui,
        "Stage 1 · PCSX2 profile",
        Some(
            "ArchiveFS selects automatically only when exactly one discovered profile is eligible.",
        ),
    );
    match profiles {
        Pcsx2ProfilesState::NotScanned => {
            widgets::banner(
                ui,
                "Profiles not scanned",
                "Run local read-only discovery of documented PCSX2 configuration paths.",
                widgets::StatusTone::Pending,
            );
        }
        Pcsx2ProfilesState::Scanning { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Scanning PCSX2 profiles locally...");
            });
        }
        Pcsx2ProfilesState::Error(message) => {
            widgets::banner(
                ui,
                "PCSX2 discovery failed",
                message,
                widgets::StatusTone::Blocked,
            );
        }
        Pcsx2ProfilesState::Ready(discovery) => {
            let eligible = eligible_pcsx2_profile_ids(discovery);
            if let Some(selected) = workflow.selected_pcsx2_profile_id.clone()
                && !eligible.contains(&selected.as_str())
            {
                workflow.selected_pcsx2_profile_id = None;
                workflow.pcsx2_inventory_profile_id = None;
                workflow.pcsx2_inventory = CheatStepResource::NotLoaded;
            }
            if discovery.profiles.is_empty() {
                widgets::banner(
                    ui,
                    "No PCSX2 profile found",
                    "No documented PCSX2 configuration directory was discovered. Missing cheat directories are not created.",
                    widgets::StatusTone::Pending,
                );
            } else if eligible.len() > 1 && workflow.selected_pcsx2_profile_id.is_none() {
                ui.label(format!(
                    "{} eligible profiles were found. Choose one explicitly.",
                    eligible.len()
                ));
            }
            for profile in &discovery.profiles {
                show_pcsx2_profile_card(ui, workflow, profile, clipboard);
                ui.add_space(6.0);
            }
            for warning in &discovery.warnings {
                widgets::banner(
                    ui,
                    "Discovery limit",
                    &warning.detail,
                    widgets::StatusTone::Warning,
                );
            }
        }
    }
    if widgets::action_button(
        ui,
        "Rescan PCSX2 profiles",
        widgets::ActionStyle::Quiet,
        !matches!(profiles, Pcsx2ProfilesState::Scanning { .. }),
    )
    .clicked()
    {
        action = Some(CheatWorkflowAction::RescanPcsx2Profiles);
    }

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "Stage 2 · Existing PCSX2-managed files",
        Some(
            "Cheats, widescreen patches, and other PNACH categories are inferred only from documented directory locations.",
        ),
    );
    widgets::card(ui, |ui| {
        widgets::status_strip(
            ui,
            &[
                ("Unverified local content", widgets::StatusTone::Warning),
                ("Read-only", widgets::StatusTone::Success),
                ("Uploaded · No", widgets::StatusTone::Info),
                ("Executed · No", widgets::StatusTone::Info),
                ("Changed · No", widgets::StatusTone::Info),
            ],
        );
        ui.label("ArchiveFS inspects PNACH structure locally. It never invokes PCSX2, evaluates directives, or claims that structural inspection proves content is malware-free.");
    });
    let Some(selected_profile_id) = workflow.selected_pcsx2_profile_id.as_deref() else {
        widgets::banner(
            ui,
            "Waiting for profile",
            "Choose an eligible PCSX2 profile before inspecting existing files.",
            widgets::StatusTone::Pending,
        );
        show_pcsx2_installation_unavailable(ui);
        return action;
    };
    if workflow.pcsx2_inventory_profile_id.as_deref() != Some(selected_profile_id) {
        workflow.pcsx2_inventory_profile_id = None;
        workflow.pcsx2_inventory = CheatStepResource::NotLoaded;
    }
    match &workflow.pcsx2_inventory {
        CheatStepResource::NotLoaded => {
            if widgets::action_button(
                ui,
                "Inspect existing PNACH files",
                widgets::ActionStyle::Primary,
                true,
            )
            .clicked()
            {
                action = Some(CheatWorkflowAction::InspectPcsx2Profile);
            }
        }
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Inspecting existing PNACH files locally...");
            });
        }
        CheatStepResource::Failed(message) => {
            widgets::banner(
                ui,
                "PCSX2 inspection failed",
                message,
                widgets::StatusTone::Blocked,
            );
        }
        CheatStepResource::Ready(inventory) => {
            show_pcsx2_inventory(ui, workflow, inventory, clipboard);
        }
    }
    show_pcsx2_installation_unavailable(ui);
    action
}

fn show_dolphin_workflow(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profiles: &DolphinProfilesState,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    widgets::section_header(
        ui,
        "Stage 1 · Dolphin profile",
        Some(
            "ArchiveFS selects automatically only when exactly one discovered profile is eligible.",
        ),
    );
    match profiles {
        DolphinProfilesState::NotScanned => widgets::banner(
            ui,
            "Profiles not scanned",
            "Run local read-only discovery of documented Dolphin user directories.",
            widgets::StatusTone::Pending,
        ),
        DolphinProfilesState::Scanning { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Scanning Dolphin profiles locally...");
            });
        }
        DolphinProfilesState::Error(message) => widgets::banner(
            ui,
            "Dolphin discovery failed",
            message,
            widgets::StatusTone::Blocked,
        ),
        DolphinProfilesState::Ready(discovery) => {
            let eligible = eligible_dolphin_profile_ids(discovery);
            if let Some(selected) = workflow.selected_dolphin_profile_id.clone()
                && !eligible.contains(&selected.as_str())
            {
                workflow.selected_dolphin_profile_id = None;
                workflow.dolphin_inventory_profile_id = None;
                workflow.dolphin_inventory = CheatStepResource::NotLoaded;
            }
            if discovery.profiles.is_empty() {
                widgets::banner(
                    ui,
                    "No Dolphin profile found",
                    "No documented Dolphin user directory was discovered. Missing GameSettings directories are not created.",
                    widgets::StatusTone::Pending,
                );
            } else if eligible.len() > 1 && workflow.selected_dolphin_profile_id.is_none() {
                ui.label(format!(
                    "{} eligible profiles were found. Choose one explicitly.",
                    eligible.len()
                ));
            }
            for profile in &discovery.profiles {
                show_dolphin_profile_card(ui, workflow, profile, clipboard);
                ui.add_space(6.0);
            }
            for warning in &discovery.warnings {
                widgets::banner(
                    ui,
                    "Discovery limit",
                    &warning.detail,
                    widgets::StatusTone::Warning,
                );
            }
        }
    }
    if widgets::action_button(
        ui,
        "Rescan Dolphin profiles",
        widgets::ActionStyle::Quiet,
        !matches!(profiles, DolphinProfilesState::Scanning { .. }),
    )
    .clicked()
    {
        action = Some(CheatWorkflowAction::RescanDolphinProfiles);
    }

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "Stage 2 · Existing Dolphin-managed files",
        Some("GameSettings INI sections are parsed as bounded text and are never evaluated."),
    );
    widgets::card(ui, |ui| {
        widgets::status_strip(
            ui,
            &[
                ("Unverified local content", widgets::StatusTone::Warning),
                ("Read-only", widgets::StatusTone::Success),
                ("Uploaded · No", widgets::StatusTone::Info),
                ("Executed · No", widgets::StatusTone::Info),
                ("Changed · No", widgets::StatusTone::Info),
            ],
        );
        ui.label("ArchiveFS inspects INI structure locally. It never invokes Dolphin, evaluates codes, follows referenced mod paths, or claims that structural inspection proves content is malware-free.");
    });
    let Some(selected_profile_id) = workflow.selected_dolphin_profile_id.as_deref() else {
        widgets::banner(
            ui,
            "Waiting for profile",
            "Choose an eligible Dolphin profile before inspecting existing files.",
            widgets::StatusTone::Pending,
        );
        show_dolphin_installation_unavailable(ui);
        return action;
    };
    if workflow.dolphin_inventory_profile_id.as_deref() != Some(selected_profile_id) {
        workflow.dolphin_inventory_profile_id = None;
        workflow.dolphin_inventory = CheatStepResource::NotLoaded;
    }
    match &workflow.dolphin_inventory {
        CheatStepResource::NotLoaded => {
            if widgets::action_button(
                ui,
                "Inspect existing Game INI files",
                widgets::ActionStyle::Primary,
                true,
            )
            .clicked()
            {
                action = Some(CheatWorkflowAction::InspectDolphinProfile);
            }
        }
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Inspecting GameSettings INI files locally...");
            });
        }
        CheatStepResource::Failed(message) => widgets::banner(
            ui,
            "Dolphin inspection failed",
            message,
            widgets::StatusTone::Blocked,
        ),
        CheatStepResource::Ready(inventory) => {
            show_dolphin_inventory(ui, workflow, inventory, clipboard)
        }
    }
    show_dolphin_installation_unavailable(ui);
    action
}

fn show_dolphin_profile_card(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profile: &DolphinProfile,
    clipboard: &mut dyn ClipboardBackend,
) {
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            if profile.eligible {
                let selected = workflow.selected_dolphin_profile_id.as_deref()
                    == Some(profile.profile_id.as_str());
                if ui.radio(selected, &profile.profile_id).clicked() {
                    workflow.selected_dolphin_profile_id = Some(profile.profile_id.clone());
                    workflow.dolphin_inventory_profile_id = None;
                    workflow.dolphin_inventory = CheatStepResource::NotLoaded;
                }
            } else {
                widgets::status_badge(ui, "Blocked", widgets::StatusTone::Blocked);
                ui.strong(&profile.profile_id);
            }
            ui.label(format!(
                "{} · {}",
                dolphin_installation_label(profile.installation_type),
                dolphin_scope_label(profile.scope)
            ));
        });
        if widgets::path_value(ui, "Configuration", &profile.configuration_path) {
            let _ = clipboard.set_text(profile.configuration_path.display().to_string());
        }
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(
                ui,
                dolphin_directory_state_label(profile.game_settings_state),
                dolphin_directory_state_tone(profile.game_settings_state),
            );
            if widgets::path_value(ui, "GameSettings", &profile.game_settings_path) {
                let _ = clipboard.set_text(profile.game_settings_path.display().to_string());
            }
        });
        if let Some(warning) = &profile.game_settings_warning {
            ui.label(warning);
        }
        for blocker in &profile.blockers {
            ui.label(format!("{:?} — {}", blocker.kind, blocker.detail));
        }
    });
}

fn show_dolphin_inventory(
    ui: &mut egui::Ui,
    workflow: &CheatWorkflowState,
    inventory: &DolphinGameIniInventory,
    clipboard: &mut dyn ClipboardBackend,
) {
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(
                ui,
                if inventory.complete {
                    "Complete"
                } else {
                    "Incomplete"
                },
                if inventory.complete {
                    widgets::StatusTone::Success
                } else {
                    widgets::StatusTone::Warning
                },
            );
            ui.strong(format!("{} Game INI files", inventory.files.len()));
            ui.label(format!("{} bytes inspected", inventory.bytes_inspected));
            ui.label(format!("{} entries visited", inventory.entries_visited));
        });
    });
    let identity = ready_game_identity(workflow);
    let match_result = match_dolphin_inventory(
        inventory,
        identity.and_then(GameIdentityReport::verified_dolphin_game_id),
        identity.and_then(GameIdentityReport::verified_dolphin_revision),
    );
    let (label, tone) = dolphin_match_presentation(match_result.state);
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(ui, label, tone);
            ui.label(&match_result.reason);
        });
        ui.label("Only a verified disc-header Game ID can establish an exact match. Wii outer-header revision remains candidate evidence and cannot establish a revision-aware match.");
    });
    egui::CollapsingHeader::new(format!(
        "Inspected Game INI files ({})",
        inventory.files.len()
    ))
    .default_open(false)
    .show(ui, |ui| {
        const MAX_RENDERED: usize = 100;
        for file in inventory.files.iter().take(MAX_RENDERED) {
            widgets::card(ui, |ui| {
                ui.horizontal_wrapped(|ui| {
                    ui.strong(file.filename_stem.to_string_lossy());
                    if let Some(id) = &file.game_id_candidate {
                        widgets::status_badge(
                            ui,
                            format!("Game ID candidate · {id}"),
                            widgets::StatusTone::Pending,
                        );
                    }
                    if let Some(revision) = file.revision_candidate {
                        ui.label(format!("Revision {revision}"));
                    }
                });
                if widgets::path_value(ui, "INI", &file.path) {
                    let _ = clipboard.set_text(file.path.display().to_string());
                }
                ui.label(format!(
                    "Definitions {} · enabled references {}",
                    file.definition_count(),
                    file.enabled_count()
                ));
                ui.label(format!(
                    "Frame patches {} · Action Replay {} · Gecko {} · Riivolution {}",
                    file.frame_patch_names.len(),
                    file.action_replay_names.len(),
                    file.gecko_names.len(),
                    file.riivolution_names.len()
                ));
                widgets::technical_details(
                    ui,
                    ("dolphin_ini_technical_metadata", &file.sha256),
                    |ui| {
                        widgets::copyable_value(ui, "SHA-256", &file.sha256);
                        if file.duplicate_game_identity
                            || file.duplicate_filename
                            || file.duplicate_content
                        {
                            ui.label(format!(
                                "Duplicate identity: {} · filename: {} · content: {}",
                                file.duplicate_game_identity,
                                file.duplicate_filename,
                                file.duplicate_content
                            ));
                        }
                    },
                );
            });
        }
        if inventory.files.len() > MAX_RENDERED {
            ui.label(format!(
                "{} additional files omitted from this summary.",
                inventory.files.len() - MAX_RENDERED
            ));
        }
    });
    if !inventory.warnings.is_empty() {
        egui::CollapsingHeader::new(format!(
            "Inspection warnings ({})",
            inventory.warnings.len()
        ))
        .default_open(false)
        .show(ui, |ui| {
            for warning in inventory.warnings.iter().take(50) {
                ui.label(format!("{:?}: {}", warning.kind, warning.detail));
            }
            if inventory.warnings.len() > 50 {
                ui.label(format!(
                    "{} additional warnings omitted from this view.",
                    inventory.warnings.len() - 50
                ));
            }
        });
    }
}

fn show_dolphin_installation_unavailable(ui: &mut egui::Ui) {
    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(ui, "Stage 3 · Preview and controlled installation", None);
    widgets::banner(
        ui,
        "Unavailable · read-only milestone",
        "ArchiveFS does not install, apply, enable, disable, replace, fix, delete, generate, or roll back Dolphin files.",
        widgets::StatusTone::Pending,
    );
}

fn dolphin_installation_label(kind: DolphinInstallationType) -> &'static str {
    match kind {
        DolphinInstallationType::Native => "Native",
        DolphinInstallationType::FlatpakUser => "Flatpak user",
        DolphinInstallationType::FlatpakSystem => "Flatpak system",
        DolphinInstallationType::Explicit => "Explicit user directory",
    }
}

fn dolphin_scope_label(scope: DolphinProfileScope) -> &'static str {
    match scope {
        DolphinProfileScope::User => "User profile",
        DolphinProfileScope::SystemInstallationUserProfile => "System install · user profile",
        DolphinProfileScope::Explicit => "Explicit scope",
    }
}

fn dolphin_directory_state_label(state: DolphinSettingsDirectoryState) -> &'static str {
    match state {
        DolphinSettingsDirectoryState::Available => "Exists",
        DolphinSettingsDirectoryState::Missing => "Missing",
        DolphinSettingsDirectoryState::UnsafePath => "Unsafe path",
        DolphinSettingsDirectoryState::NotDirectory => "Not a directory",
        DolphinSettingsDirectoryState::Unreadable => "Unreadable",
    }
}

fn dolphin_directory_state_tone(state: DolphinSettingsDirectoryState) -> widgets::StatusTone {
    match state {
        DolphinSettingsDirectoryState::Available => widgets::StatusTone::Success,
        DolphinSettingsDirectoryState::Missing => widgets::StatusTone::Pending,
        DolphinSettingsDirectoryState::UnsafePath => widgets::StatusTone::Blocked,
        DolphinSettingsDirectoryState::NotDirectory | DolphinSettingsDirectoryState::Unreadable => {
            widgets::StatusTone::Warning
        }
    }
}

fn dolphin_match_presentation(state: DolphinMatchState) -> (&'static str, widgets::StatusTone) {
    match state {
        DolphinMatchState::ExactGameIdMatch | DolphinMatchState::ExactGameIdAndRevisionMatch => (
            "Exact verified identity match",
            widgets::StatusTone::Success,
        ),
        DolphinMatchState::MultipleIniFilesForGame | DolphinMatchState::RevisionMismatch => {
            ("Ambiguous identity", widgets::StatusTone::Warning)
        }
        DolphinMatchState::NoVerifiedGameIdAvailable
        | DolphinMatchState::IdentityExtractionDeferred => {
            ("Verified Game ID unavailable", widgets::StatusTone::Pending)
        }
        DolphinMatchState::NoMatchingIniFound => {
            ("No matching Game INI", widgets::StatusTone::Pending)
        }
        DolphinMatchState::InvalidVerifiedGameId => {
            ("Invalid verified Game ID", widgets::StatusTone::Blocked)
        }
    }
}

fn show_pcsx2_profile_card(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profile: &Pcsx2Profile,
    clipboard: &mut dyn ClipboardBackend,
) {
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            if profile.eligible {
                let selected = workflow.selected_pcsx2_profile_id.as_deref()
                    == Some(profile.profile_id.as_str());
                if ui.radio(selected, &profile.profile_id).clicked() {
                    workflow.selected_pcsx2_profile_id = Some(profile.profile_id.clone());
                    workflow.pcsx2_inventory_profile_id = None;
                    workflow.pcsx2_inventory = CheatStepResource::NotLoaded;
                }
                widgets::status_badge(ui, "Eligible", widgets::StatusTone::Success);
            } else {
                ui.add_enabled(false, egui::Button::selectable(false, &profile.profile_id));
                widgets::status_badge(ui, "Blocked", widgets::StatusTone::Blocked);
            }
            ui.label(format!(
                "{} · {}",
                pcsx2_installation_label(profile.installation_type),
                pcsx2_scope_label(profile.scope)
            ));
        });
        if widgets::path_value(ui, "Configuration", &profile.configuration_path) {
            let _ = clipboard.set_text(profile.configuration_path.display().to_string());
        }
        for directory in &profile.patch_directories {
            ui.horizontal_wrapped(|ui| {
                widgets::status_badge(
                    ui,
                    pcsx2_directory_state_label(directory.state),
                    pcsx2_directory_state_tone(directory.state),
                );
                ui.label(pcsx2_category_label(directory.category));
                if widgets::path_value(ui, "Path", &directory.path) {
                    let _ = clipboard.set_text(directory.path.display().to_string());
                }
            });
        }
        if let Some(blocker) = profile.blockers.first() {
            ui.label(format!("{:?} — {}", blocker.kind, blocker.detail));
        }
        if profile.blockers.len() > 1 {
            egui::CollapsingHeader::new("All technical blockers")
                .default_open(false)
                .show(ui, |ui| {
                    for blocker in &profile.blockers {
                        ui.label(format!("{:?} — {}", blocker.kind, blocker.detail));
                    }
                });
        }
    });
}

fn show_pcsx2_inventory(
    ui: &mut egui::Ui,
    workflow: &CheatWorkflowState,
    inventory: &Pcsx2PnachInventory,
    clipboard: &mut dyn ClipboardBackend,
) {
    let category_count = |category| {
        inventory
            .files
            .iter()
            .filter(|file| file.category == category)
            .count()
    };
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(
                ui,
                if inventory.complete {
                    "Complete"
                } else {
                    "Incomplete"
                },
                if inventory.complete {
                    widgets::StatusTone::Success
                } else {
                    widgets::StatusTone::Warning
                },
            );
            ui.strong(format!("{} PNACH files", inventory.files.len()));
            ui.label(format!("{} bytes inspected", inventory.bytes_inspected));
            ui.label(format!("{} entries visited", inventory.entries_visited));
        });
        ui.horizontal_wrapped(|ui| {
            for (category, label) in [
                (Pcsx2PatchCategory::Cheats, "Cheats"),
                (Pcsx2PatchCategory::WidescreenPatches, "Widescreen"),
                (Pcsx2PatchCategory::OtherPatches, "Other patches"),
                (Pcsx2PatchCategory::Unknown, "Unknown"),
            ] {
                widgets::status_badge(
                    ui,
                    format!("{label} · {}", category_count(category)),
                    widgets::StatusTone::Info,
                );
            }
        });
    });
    let match_result = match_pcsx2_inventory(
        inventory,
        ready_game_identity(workflow).and_then(GameIdentityReport::verified_pcsx2_crc),
        Some(&workflow.display_name),
    );
    let (match_label, match_tone) = pcsx2_match_presentation(match_result.state);
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(ui, match_label, match_tone);
            ui.label(&match_result.reason);
        });
        ui.label("Exact matching requires a verified CRC calculated from the complete bounded boot ELF. Filename CRCs and comment titles remain candidates only.");
        for path in &match_result.matching_files {
            if widgets::path_value(ui, "Candidate", path) {
                let _ = clipboard.set_text(path.display().to_string());
            }
        }
    });
    egui::CollapsingHeader::new(format!("Inspected PNACH files ({})", inventory.files.len()))
        .default_open(false)
        .show(ui, |ui| {
            const MAX_RENDERED_PNACH_FILES: usize = 100;
            for file in inventory.files.iter().take(MAX_RENDERED_PNACH_FILES) {
                widgets::card(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        ui.strong(file.filename_stem.to_string_lossy());
                        widgets::status_badge(
                            ui,
                            pcsx2_category_label(file.category),
                            widgets::StatusTone::Info,
                        );
                        if let Some(crc) = &file.crc_candidate {
                            widgets::status_badge(ui, format!("CRC candidate · {crc}"), widgets::StatusTone::Pending);
                        }
                        ui.label(format!("{} patch entries", file.patch_entry_count));
                    });
                    if widgets::path_value(ui, "PNACH", &file.path) {
                        let _ = clipboard.set_text(file.path.display().to_string());
                    }
                    ui.label(format!(
                        "Enabled syntax {} · disabled syntax {} · unknown syntax {}",
                        file.enabled_patch_count,
                        file.disabled_patch_count,
                        file.unknown_patch_count
                    ));
                    if !file.title_candidates.is_empty() {
                        ui.label(format!("Comment title candidates: {}", file.title_candidates.join("; ")));
                    }
                    if !file.comments.is_empty() {
                        ui.label(format!(
                            "Retained comments: {}",
                            file.comments
                                .iter()
                                .take(3)
                                .cloned()
                                .collect::<Vec<_>>()
                                .join("; ")
                        ));
                    }
                    widgets::technical_details(ui, ("pcsx2_pnach_technical_metadata", &file.sha256), |ui| {
                        widgets::copyable_value(ui, "SHA-256", &file.sha256);
                        if file.duplicate_crc || file.duplicate_filename || file.duplicate_content {
                            ui.label(format!(
                                "Duplicate CRC: {} · filename: {} · content: {}",
                                file.duplicate_crc, file.duplicate_filename, file.duplicate_content
                            ));
                        }
                    });
                });
            }
            if inventory.files.len() > MAX_RENDERED_PNACH_FILES {
                ui.label(format!(
                    "{} additional files are retained in the bounded result but omitted from this summary.",
                    inventory.files.len() - MAX_RENDERED_PNACH_FILES
                ));
            }
        });
    if !inventory.warnings.is_empty() {
        egui::CollapsingHeader::new(format!(
            "Inspection warnings ({})",
            inventory.warnings.len()
        ))
        .default_open(false)
        .show(ui, |ui| {
            for warning in inventory.warnings.iter().take(50) {
                ui.label(format!("{:?}: {}", warning.kind, warning.detail));
            }
            if inventory.warnings.len() > 50 {
                ui.label(format!(
                    "{} additional warnings omitted from this view.",
                    inventory.warnings.len() - 50
                ));
            }
        });
    }
}

fn show_pcsx2_installation_unavailable(ui: &mut egui::Ui) {
    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(ui, "Stage 3 · Preview and controlled installation", None);
    widgets::banner(
        ui,
        "Unavailable · read-only milestone",
        "ArchiveFS does not install, apply, enable, disable, replace, fix, delete, generate, or roll back PCSX2 files.",
        widgets::StatusTone::Pending,
    );
}

fn pcsx2_installation_label(kind: Pcsx2InstallationType) -> &'static str {
    match kind {
        Pcsx2InstallationType::Native => "Native",
        Pcsx2InstallationType::FlatpakUser => "Flatpak user",
        Pcsx2InstallationType::FlatpakSystem => "Flatpak system",
        Pcsx2InstallationType::Portable => "Portable / explicit configuration",
    }
}

fn pcsx2_scope_label(scope: Pcsx2ProfileScope) -> &'static str {
    match scope {
        Pcsx2ProfileScope::User => "User profile",
        Pcsx2ProfileScope::SystemInstallationUserProfile => "System install · user profile",
        Pcsx2ProfileScope::Portable => "Portable scope",
    }
}

fn pcsx2_category_label(category: Pcsx2PatchCategory) -> &'static str {
    match category {
        Pcsx2PatchCategory::Cheats => "Cheats",
        Pcsx2PatchCategory::WidescreenPatches => "Widescreen patches",
        Pcsx2PatchCategory::OtherPatches => "Other PNACH patches",
        Pcsx2PatchCategory::Unknown => "Unknown PNACH category",
    }
}

fn pcsx2_directory_state_label(state: Pcsx2PatchDirectoryState) -> &'static str {
    match state {
        Pcsx2PatchDirectoryState::Available => "Exists",
        Pcsx2PatchDirectoryState::Missing => "Missing",
        Pcsx2PatchDirectoryState::UnsafePath => "Unsafe path",
        Pcsx2PatchDirectoryState::NotDirectory => "Not a directory",
        Pcsx2PatchDirectoryState::Unreadable => "Unreadable",
    }
}

fn pcsx2_directory_state_tone(state: Pcsx2PatchDirectoryState) -> widgets::StatusTone {
    match state {
        Pcsx2PatchDirectoryState::Available => widgets::StatusTone::Success,
        Pcsx2PatchDirectoryState::Missing => widgets::StatusTone::Pending,
        Pcsx2PatchDirectoryState::UnsafePath => widgets::StatusTone::Blocked,
        Pcsx2PatchDirectoryState::NotDirectory | Pcsx2PatchDirectoryState::Unreadable => {
            widgets::StatusTone::Warning
        }
    }
}

fn pcsx2_match_presentation(state: Pcsx2MatchState) -> (&'static str, widgets::StatusTone) {
    match state {
        Pcsx2MatchState::ExactCrcMatch => ("Exact CRC match", widgets::StatusTone::Success),
        Pcsx2MatchState::MultiplePnachFilesForSameCrc => {
            ("Ambiguous CRC match", widgets::StatusTone::Warning)
        }
        Pcsx2MatchState::CandidateByFilenameOrTitleOnly => {
            ("Unverified title candidate", widgets::StatusTone::Warning)
        }
        Pcsx2MatchState::NoVerifiedGameCrcAvailable => (
            "Verified game CRC unavailable",
            widgets::StatusTone::Pending,
        ),
        Pcsx2MatchState::NoMatchingPnachFound => {
            ("No matching PNACH", widgets::StatusTone::Pending)
        }
        Pcsx2MatchState::InvalidVerifiedGameCrc => {
            ("Invalid verified CRC", widgets::StatusTone::Blocked)
        }
        Pcsx2MatchState::IdentityExtractionDeferred => {
            ("Identity extraction deferred", widgets::StatusTone::Pending)
        }
    }
}

fn ready_game_identity(workflow: &CheatWorkflowState) -> Option<&GameIdentityReport> {
    match &workflow.identity {
        CheatStepResource::Ready((request, report))
            if request.archive_path == workflow.archive_path
                && request.platform == workflow.platform
                && request.adapter == workflow.adapter
                && report.archive_path == workflow.archive_path =>
        {
            Some(report)
        }
        _ => None,
    }
}

fn cheat_preview_key(workflow: &CheatWorkflowState) -> CheatPreviewRequestKey {
    let profile_id = match workflow.adapter {
        CheatEmulatorAdapter::RetroArch => workflow.selected_profile_id.clone(),
        CheatEmulatorAdapter::Pcsx2 => workflow.selected_pcsx2_profile_id.clone(),
        CheatEmulatorAdapter::Dolphin => workflow.selected_dolphin_profile_id.clone(),
    };
    CheatPreviewRequestKey {
        archive_path: workflow.archive_path.clone(),
        platform: workflow.platform.clone(),
        adapter: workflow.adapter,
        profile_id,
        source_mode: workflow.source_mode,
        source_id: workflow.selected_source_id.clone(),
        snapshot_id: match &workflow.source_fetch {
            CheatStepResource::Ready(result) => Some(result.manifest.archive_sha256.clone()),
            _ => None,
        },
    }
}

fn preview_identity(
    workflow: &CheatWorkflowState,
    kind: PreviewIdentityKind,
    value: Option<&str>,
    revision: Option<u16>,
) -> PreviewIdentity {
    PreviewIdentity {
        kind,
        state: if value.is_some() {
            PreviewIdentityState::Verified
        } else {
            PreviewIdentityState::Missing
        },
        value: value.map(str::to_owned),
        archive_path: workflow.archive_path.clone(),
        revision,
    }
}

fn build_cheat_preview_request(
    workflow: &CheatWorkflowState,
    retroarch_profiles: &RetroArchProfilesState,
    pcsx2_profiles: &Pcsx2ProfilesState,
    dolphin_profiles: &DolphinProfilesState,
) -> Option<(CheatPreviewRequestKey, CheatPreviewWork)> {
    let key = cheat_preview_key(workflow);
    let identity = ready_game_identity(workflow);
    match workflow.adapter {
        CheatEmulatorAdapter::Pcsx2 => {
            let selected = workflow.selected_pcsx2_profile_id.as_deref()?;
            let Pcsx2ProfilesState::Ready(discovery) = pcsx2_profiles else {
                return None;
            };
            let profile = discovery
                .profiles
                .iter()
                .find(|profile| profile.eligible && profile.profile_id == selected)?;
            let CheatStepResource::Ready(inventory) = &workflow.pcsx2_inventory else {
                return None;
            };
            let verified_crc = identity.and_then(GameIdentityReport::verified_pcsx2_crc);
            let matched =
                match_pcsx2_inventory(inventory, verified_crc, Some(&workflow.display_name));
            let strength = match matched.state {
                Pcsx2MatchState::ExactCrcMatch | Pcsx2MatchState::MultiplePnachFilesForSameCrc => {
                    PreviewMatchStrength::VerifiedExact
                }
                Pcsx2MatchState::CandidateByFilenameOrTitleOnly => PreviewMatchStrength::Candidate,
                Pcsx2MatchState::InvalidVerifiedGameCrc => PreviewMatchStrength::Ambiguous,
                _ => PreviewMatchStrength::Unsupported,
            };
            let source_items = matched
                .matching_files
                .iter()
                .filter_map(|path| {
                    let file = inventory.files.iter().find(|file| file.path == *path)?;
                    let relative = path.strip_prefix(&profile.configuration_path).ok()?;
                    Some(PreviewSourceItem {
                        adapter: PreviewAdapter::Pcsx2,
                        source_path: path.clone(),
                        expected_source_digest: Some(file.sha256.clone()),
                        destination_relative_paths: vec![relative.to_path_buf()],
                        match_strength: strength,
                    })
                })
                .collect();
            Some((
                key,
                CheatPreviewWork::Shared(SharedPreviewRequest {
                    adapter: PreviewAdapter::Pcsx2,
                    selected_archive: workflow.archive_path.clone(),
                    platform: workflow.platform.clone(),
                    identity: preview_identity(
                        workflow,
                        PreviewIdentityKind::Pcsx2ExecutableCrc,
                        verified_crc,
                        None,
                    ),
                    destination_root: profile.configuration_path.clone(),
                    source_items,
                }),
            ))
        }
        CheatEmulatorAdapter::Dolphin => {
            let selected = workflow.selected_dolphin_profile_id.as_deref()?;
            let DolphinProfilesState::Ready(discovery) = dolphin_profiles else {
                return None;
            };
            let profile = discovery
                .profiles
                .iter()
                .find(|profile| profile.eligible && profile.profile_id == selected)?;
            let CheatStepResource::Ready(inventory) = &workflow.dolphin_inventory else {
                return None;
            };
            let game_id = identity.and_then(GameIdentityReport::verified_dolphin_game_id);
            let revision = identity.and_then(GameIdentityReport::verified_dolphin_revision);
            let matched = match_dolphin_inventory(inventory, game_id, revision);
            let strength = match matched.state {
                DolphinMatchState::ExactGameIdMatch
                | DolphinMatchState::ExactGameIdAndRevisionMatch
                | DolphinMatchState::MultipleIniFilesForGame => PreviewMatchStrength::VerifiedExact,
                DolphinMatchState::RevisionMismatch => PreviewMatchStrength::Ambiguous,
                _ => PreviewMatchStrength::Unsupported,
            };
            let source_items = matched
                .matching_files
                .iter()
                .filter_map(|path| {
                    let file = inventory.files.iter().find(|file| file.path == *path)?;
                    let relative = path.strip_prefix(&profile.configuration_path).ok()?;
                    Some(PreviewSourceItem {
                        adapter: PreviewAdapter::Dolphin,
                        source_path: path.clone(),
                        expected_source_digest: Some(file.sha256.clone()),
                        destination_relative_paths: vec![relative.to_path_buf()],
                        match_strength: strength,
                    })
                })
                .collect();
            Some((
                key,
                CheatPreviewWork::Shared(SharedPreviewRequest {
                    adapter: PreviewAdapter::Dolphin,
                    selected_archive: workflow.archive_path.clone(),
                    platform: workflow.platform.clone(),
                    identity: preview_identity(
                        workflow,
                        PreviewIdentityKind::DolphinGameId,
                        game_id,
                        revision,
                    ),
                    destination_root: profile.configuration_path.clone(),
                    source_items,
                }),
            ))
        }
        CheatEmulatorAdapter::RetroArch => {
            if workflow.source_mode != CheatSourceMode::ArchiveFsTrustedCatalogue {
                return None;
            }
            let selected = workflow.selected_profile_id.as_deref()?;
            let RetroArchProfilesState::Ready(discovery) = retroarch_profiles else {
                return None;
            };
            let profile = discovery
                .profiles
                .iter()
                .find(|profile| profile.eligible && profile.profile_id == selected)?;
            let root = profile.cheat_destination_root.as_ref()?;
            let destination_root = (!root.lossy).then(|| PathBuf::from(&root.display))?;
            let CheatStepResource::Ready(fetch) = &workflow.source_fetch else {
                return None;
            };
            if fetch.local_catalogue_path.lossy || fetch.immutable_snapshot_path.lossy {
                return None;
            }
            let platform = workflow.platform.clone()?;
            Some((
                key,
                CheatPreviewWork::RetroArch(RetroArchMaterializationRequest {
                    snapshot_root: PathBuf::from(&fetch.immutable_snapshot_path.display),
                    expected_snapshot_id: fetch.manifest.archive_sha256.clone(),
                    source_id: fetch.source.source_id.clone(),
                    selected_archive: workflow.archive_path.clone(),
                    archive_display_name: workflow.display_name.clone(),
                    archive_normalized_name: workflow.normalized_name.clone(),
                    platform,
                    region: workflow.region.clone(),
                    verified_loose_rom_sha256: identity
                        .and_then(GameIdentityReport::verified_loose_rom_sha256)
                        .map(str::to_owned),
                    destination_root,
                }),
            ))
        }
    }
}

fn identity_status_tone(status: IdentityStatus) -> widgets::StatusTone {
    match status {
        IdentityStatus::Verified => widgets::StatusTone::Success,
        IdentityStatus::Candidate | IdentityStatus::Deferred | IdentityStatus::Missing => {
            widgets::StatusTone::Pending
        }
        IdentityStatus::ResourceLimitReached | IdentityStatus::Ambiguous => {
            widgets::StatusTone::Warning
        }
        IdentityStatus::Invalid | IdentityStatus::Unsupported => widgets::StatusTone::Blocked,
    }
}

fn show_shared_game_identity(
    ui: &mut egui::Ui,
    workflow: &CheatWorkflowState,
    clipboard: &mut dyn ClipboardBackend,
) {
    widgets::section_header(
        ui,
        "Shared game identity",
        Some("Bounded local disc metadata; candidates are never promoted to verified values."),
    );
    match &workflow.identity {
        CheatStepResource::NotLoaded => widgets::banner(
            ui,
            "Identity unavailable",
            "The current archive, adapter, page, or platform context changed. Reopen or reselect the adapter to inspect it.",
            widgets::StatusTone::Pending,
        ),
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Reading bounded disc metadata in the background...");
            });
        }
        CheatStepResource::Failed(message) => widgets::banner(
            ui,
            "Identity inspection failed",
            message,
            widgets::StatusTone::Blocked,
        ),
        CheatStepResource::Ready((_, report)) => {
            widgets::card(ui, |ui| {
                if widgets::path_value(ui, "Selected archive", &report.archive_path) {
                    let _ = clipboard.set_text(report.archive_path.display().to_string());
                }
                ui.horizontal_wrapped(|ui| {
                    widgets::status_badge(ui, report.platform.label(), widgets::StatusTone::Info);
                    if report.format == IdentityImageFormat::LooseCartridgeRom {
                        widgets::status_badge(
                            ui,
                            "Media kind · Loose ROM",
                            widgets::StatusTone::Info,
                        );
                        ui.label(format!("{} bytes hashed", report.bytes_read));
                    } else {
                        ui.label(format!("Format: {:?}", report.format));
                        ui.label(format!("{} bytes read", report.bytes_read));
                    }
                    ui.label(format!(
                        "{} members · {} metadata paths",
                        report.archive_members_inspected, report.metadata_paths_inspected
                    ));
                });
            });
            for item in &report.evidence {
                widgets::card(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        ui.strong(item.kind.to_string());
                        widgets::status_badge(
                            ui,
                            item.status.to_string(),
                            identity_status_tone(item.status),
                        );
                        if let Some(value) = &item.value {
                            widgets::copyable_value(ui, "Value", value);
                        }
                    });
                    widgets::technical_details(
                        ui,
                        (
                            "identity_evidence_technical_provenance",
                            item.kind.to_string(),
                        ),
                        |ui| {
                            ui.label(format!("Method: {}", item.provenance.method));
                            ui.label(format!("Confidence: {:?}", item.confidence));
                            if let Some(index) = item.provenance.member_index {
                                ui.label(format!("ZIP member index: {index}"));
                            }
                            if let Some(member) = &item.provenance.member_path {
                                ui.label(format!(
                                    "ZIP member: {}",
                                    String::from_utf8_lossy(member)
                                ));
                            }
                            ui.label(&item.diagnostic);
                        },
                    );
                });
            }
            if !report.warnings.is_empty() {
                egui::CollapsingHeader::new(format!(
                    "Identity warnings ({})",
                    report.warnings.len()
                ))
                .default_open(false)
                .show(ui, |ui| {
                    for warning in &report.warnings {
                        ui.label(warning);
                    }
                });
            }
            let adapter_match = match workflow.adapter {
                CheatEmulatorAdapter::Pcsx2 => match &workflow.pcsx2_inventory {
                    CheatStepResource::Ready(inventory) => {
                        let result = match_pcsx2_inventory(
                            inventory,
                            report.verified_pcsx2_crc(),
                            Some(&workflow.display_name),
                        );
                        let (label, tone) = pcsx2_match_presentation(result.state);
                        Some((label, tone, result.reason))
                    }
                    _ => None,
                },
                CheatEmulatorAdapter::Dolphin => match &workflow.dolphin_inventory {
                    CheatStepResource::Ready(inventory) => {
                        let result = match_dolphin_inventory(
                            inventory,
                            report.verified_dolphin_game_id(),
                            report.verified_dolphin_revision(),
                        );
                        let (label, tone) = dolphin_match_presentation(result.state);
                        Some((label, tone, result.reason))
                    }
                    _ => None,
                },
                CheatEmulatorAdapter::RetroArch => None,
            };
            widgets::card(ui, |ui| {
                ui.strong("Exact adapter match result");
                if let Some((label, tone, reason)) = adapter_match {
                    ui.horizontal_wrapped(|ui| {
                        widgets::status_badge(ui, label, tone);
                        ui.label(reason);
                    });
                } else {
                    widgets::status_badge(
                        ui,
                        "Adapter inventory not loaded",
                        widgets::StatusTone::Pending,
                    );
                }
            });
        }
    }
}

fn preview_state_label(state: PreviewState) -> &'static str {
    match state {
        PreviewState::InstallNew => "Install new",
        PreviewState::AlreadyInstalled => "Already installed",
        PreviewState::ReplaceDifferent => "Replace different",
        PreviewState::Conflict => "Conflict",
        PreviewState::Ambiguous => "Ambiguous",
        PreviewState::NotEligible => "Not eligible",
        PreviewState::Unsupported => "Unsupported",
        PreviewState::UnsafeDestination => "Unsafe destination",
        PreviewState::DestinationUnavailable => "Destination unavailable",
        PreviewState::SourceUnavailable => "Source unavailable",
        PreviewState::IdentityUnavailable => "Identity unavailable",
        PreviewState::ResourceLimitReached => "Resource limit reached",
    }
}

fn preview_state_tone(state: PreviewState) -> widgets::StatusTone {
    match state {
        PreviewState::InstallNew | PreviewState::AlreadyInstalled => widgets::StatusTone::Success,
        PreviewState::ReplaceDifferent | PreviewState::ResourceLimitReached => {
            widgets::StatusTone::Warning
        }
        PreviewState::Conflict | PreviewState::Ambiguous | PreviewState::UnsafeDestination => {
            widgets::StatusTone::Blocked
        }
        _ => widgets::StatusTone::Pending,
    }
}

fn destination_state_label(state: PreviewDestinationState) -> &'static str {
    match state {
        PreviewDestinationState::Missing => "Missing",
        PreviewDestinationState::RegularFileIdentical => "Regular file · identical",
        PreviewDestinationState::RegularFileDifferent => "Regular file · different",
        PreviewDestinationState::Directory => "Directory",
        PreviewDestinationState::Symlink => "Symlink",
        PreviewDestinationState::SpecialFile => "Special file",
        PreviewDestinationState::Inaccessible => "Inaccessible",
        PreviewDestinationState::ChangedDuringInspection => "Changed during inspection",
        PreviewDestinationState::Unavailable => "Unavailable",
    }
}

fn show_shared_cheat_preview(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    widgets::section_header(
        ui,
        "Shared preview",
        Some("Preview only. No files were changed."),
    );
    widgets::banner(
        ui,
        "Preview only. No files were changed.",
        "ArchiveFS performs bounded local reads. A write can be offered only after an exact materialized source enters the reviewed transaction pipeline.",
        widgets::StatusTone::Info,
    );
    match &workflow.preview {
        CheatStepResource::NotLoaded => widgets::banner(
            ui,
            "Preview waiting",
            "A verified identity, selected profile, and inspected adapter source are required before a source-to-destination preview can run.",
            widgets::StatusTone::Pending,
        ),
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Inspecting preview sources and destinations off the UI thread...");
            });
        }
        CheatStepResource::Failed(message) => widgets::banner(
            ui,
            "Preview worker failed",
            message,
            widgets::StatusTone::Blocked,
        ),
        CheatStepResource::Ready(response) => match &response.outcome {
            CheatPreviewOutcome::Failed(CheatPreviewFailure::Materialization(error))
                if error.kind == RetroArchMaterializationErrorKind::MatchingEntryExcluded =>
            {
                widgets::banner(
                    ui,
                    "Matching catalogue entry excluded",
                    &format!("{}. Nothing can be applied.", error.detail),
                    widgets::StatusTone::Warning,
                )
            }
            CheatPreviewOutcome::Failed(CheatPreviewFailure::Materialization(error))
                if error.kind == RetroArchMaterializationErrorKind::NoEligibleMatch =>
            {
                widgets::banner(
                    ui,
                    "No matching cheat found",
                    "The active verified catalogue contains no exact or approved strong match for this game. Nothing can be applied.",
                    widgets::StatusTone::Pending,
                )
            }
            CheatPreviewOutcome::Failed(error) => widgets::banner(
                ui,
                "Preview unavailable",
                &error.to_string(),
                widgets::StatusTone::Blocked,
            ),
            CheatPreviewOutcome::Ready(report) => {
                if let Some(materialized) = &response.materialized {
                    widgets::card(ui, |ui| {
                        widgets::status_badge(
                            ui,
                            "Trusted source materialized",
                            widgets::StatusTone::Success,
                        );
                        widgets::copyable_value(ui, "Snapshot ID", &materialized.snapshot_id);
                        if let CheatStepResource::Ready(fetch) = &workflow.source_fetch {
                            widgets::copyable_value(
                                ui,
                                "Upstream revision",
                                &fetch.manifest.resolved_revision,
                            );
                        }
                        if widgets::path_value(
                            ui,
                            "Immutable snapshot",
                            &materialized.snapshot_root,
                        ) {
                            let _ = clipboard
                                .set_text(materialized.snapshot_root.display().to_string());
                        }
                        ui.label(format!(
                            "{} exact local source item{}",
                            materialized.sources.len(),
                            if materialized.sources.len() == 1 {
                                ""
                            } else {
                                "s"
                            }
                        ));
                        ui.label(format!(
                            "Catalogue index: {:?} · {} indexed · {} excluded",
                            materialized.catalogue_index_state,
                            materialized.indexed_file_count,
                            materialized.excluded_file_count
                        ));
                    });
                }
                widgets::card(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        widgets::status_badge(
                            ui,
                            format!("Adapter · {:?}", report.adapter),
                            widgets::StatusTone::Info,
                        );
                        ui.strong(format!("{} entries", report.summary.entries));
                        ui.label(format!("{} install new", report.summary.install_new));
                        ui.label(format!(
                            "{} already installed",
                            report.summary.already_installed
                        ));
                        ui.label(format!(
                            "{} replace different",
                            report.summary.replace_different
                        ));
                        ui.label(format!("{} conflicts", report.summary.conflicts));
                        ui.label(format!("{} blocked", report.summary.blocked));
                    });
                    ui.label(format!(
                        "Hashed {} source and {} destination files · {} total bytes · {} paths inspected",
                        report.summary.source_files_hashed,
                        report.summary.destination_files_hashed,
                        report.summary.bytes_hashed,
                        report.summary.destination_paths_inspected
                    ));
                });
                for (index, entry) in report.entries.iter().enumerate() {
                    widgets::card(ui, |ui| {
                        ui.horizontal_wrapped(|ui| {
                            widgets::status_badge(
                                ui,
                                preview_state_label(entry.state),
                                preview_state_tone(entry.state),
                            );
                            widgets::status_badge(
                                ui,
                                if entry.eligibility == PreviewEligibility::Eligible {
                                    "Eligible"
                                } else {
                                    "Blocked"
                                },
                                if entry.eligibility == PreviewEligibility::Eligible {
                                    widgets::StatusTone::Success
                                } else {
                                    widgets::StatusTone::Blocked
                                },
                            );
                            ui.strong(format!("Preview entry {}", index + 1));
                        });
                        if let Some(identity) = &entry.verified_identity {
                            widgets::copyable_value(ui, "Verified identity", identity);
                        } else {
                            ui.label("Verified identity: unavailable");
                        }
                        ui.label(format!("Match strength: {:?}", entry.match_strength));
                        if let Some(source) = &entry.source_path
                            && widgets::path_value(ui, "Source item", source)
                        {
                            let _ = clipboard.set_text(source.display().to_string());
                        }
                        if let Some(destination) = &entry.destination_path
                            && widgets::path_value(ui, "Destination", destination)
                        {
                            let _ = clipboard.set_text(destination.display().to_string());
                        }
                        ui.label(format!(
                            "Current destination state: {}",
                            destination_state_label(entry.destination_state)
                        ));
                        ui.label(format!("Proposed action: {:?}", entry.proposed_action));
                        ui.label(format!(
                            "Backup required: {} · explicit replacement permission required: {}",
                            if entry.backup_required { "Yes" } else { "No" },
                            if entry.explicit_replacement_permission_required {
                                "Yes"
                            } else {
                                "No"
                            }
                        ));
                        if let Some(digest) = &entry.source_digest {
                            widgets::copyable_value(ui, "Source SHA-256", digest);
                        }
                        if let Some(digest) = &entry.existing_destination_digest {
                            widgets::copyable_value(ui, "Destination SHA-256", digest);
                        }
                        widgets::technical_details(
                            ui,
                            ("preview_entry_technical_detail", index),
                            |ui| {
                                if widgets::path_value(
                                    ui,
                                    "Destination root",
                                    &entry.destination_root,
                                ) {
                                    let _ = clipboard
                                        .set_text(entry.destination_root.display().to_string());
                                }
                                if let Some(relative) = &entry.destination_relative_path {
                                    ui.label(format!("Relative path: {}", relative.display()));
                                }
                                for blocker in &entry.blockers {
                                    ui.label(format!(
                                        "Blocker: {:?}{}",
                                        blocker.kind,
                                        blocker
                                            .path
                                            .as_ref()
                                            .map(|path| format!(" · {}", path.display()))
                                            .unwrap_or_default()
                                    ));
                                }
                                for warning in &entry.warnings {
                                    ui.label(format!("Warning: {:?}", warning.kind));
                                }
                            },
                        );
                    });
                }
                if !report.conflicts.is_empty() {
                    egui::CollapsingHeader::new(format!(
                        "Conflict records ({})",
                        report.conflicts.len()
                    ))
                    .default_open(false)
                    .show(ui, |ui| {
                        for conflict in &report.conflicts {
                            ui.label(format!("{:?}", conflict.kind));
                        }
                    });
                }
                action = show_shared_transaction_readiness(
                    ui,
                    report,
                    response.materialized.is_some(),
                    &mut workflow.transaction,
                    clipboard,
                );
            }
        },
    }
    action
}

fn show_shared_transaction_readiness(
    ui: &mut egui::Ui,
    report: &SharedPreviewReport,
    source_materialized: bool,
    transaction: &mut CheatTransactionState,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "Review and controlled apply",
        Some("Preview → Review → Confirm → Apply → Verify → Result"),
    );
    let support = adapter_write_support(report.adapter);
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            for stage in [
                "1 Preview",
                "2 Review",
                "3 Confirm",
                "4 Apply",
                "5 Verify",
                "6 Result",
            ] {
                widgets::status_badge(ui, stage, widgets::StatusTone::Info);
            }
        });
        match support {
            SharedAdapterWriteSupport::ApplyAndRollback => {
                widgets::status_badge(
                    ui,
                    "Transaction engine available",
                    widgets::StatusTone::Success,
                );
                ui.label("RetroArch trusted catalogue files have a reviewed shared apply and rollback contract. This page will not offer confirmation until the selected per-game catalogue source is materialized in this exact preview.");
            }
            SharedAdapterWriteSupport::PreviewOnlySourceNotMaterialized => {
                widgets::status_badge(ui, "Preview only", widgets::StatusTone::Pending);
                ui.label("This adapter currently inventories emulator-managed files but does not provide an independent approved materialized source. Apply and rollback are unavailable; no shortcut is offered.");
            }
        }
        let actionable = report
            .entries
            .iter()
            .filter(|entry| {
                entry.eligibility == PreviewEligibility::Eligible
                    && matches!(
                        entry.proposed_action,
                        archivefs_core::patch_manager::PreviewProposedAction::Install
                            | archivefs_core::patch_manager::PreviewProposedAction::Replace
                    )
            })
            .count();
        ui.label(format!(
            "Actionable materialized entries in this page state: {actionable}"
        ));
        ui.label("General confirmation is operation-scoped. Replacement permission is separate and never preselected. Cancellation before the write phase changes nothing.");
        if actionable == 0 {
            widgets::banner(
                ui,
                "No write is available",
                "There is no eligible materialized source bound to this exact preview, so ArchiveFS shows no Apply control.",
                widgets::StatusTone::Pending,
            );
        }
        match transaction {
            CheatTransactionState::Idle if actionable > 0 && source_materialized => {
                if widgets::action_button(
                    ui,
                    "Review exact apply plan",
                    widgets::ActionStyle::Primary,
                    true,
                )
                .clicked()
                {
                    action = Some(CheatWorkflowAction::ReviewApply);
                }
            }
            CheatTransactionState::Review {
                plan,
                replacement_approved,
                ..
            } => {
                widgets::status_badge(ui, "Review required", widgets::StatusTone::Warning);
                widgets::copyable_value(ui, "Plan ID", &plan.plan_id);
                let replacement_required = plan.entries.iter().any(|entry| {
                    entry.proposed_action
                        == archivefs_core::patch_manager::PreviewProposedAction::Replace
                });
                for entry in &plan.entries {
                    ui.separator();
                    ui.label(format!("Action: {:?}", entry.proposed_action));
                    ui.label(format!("Source: {}", entry.source_path.display));
                    ui.label(format!(
                        "Destination: {}/{}",
                        entry.destination_root.display, entry.destination_relative_path.display
                    ));
                    widgets::copyable_value(ui, "Approved source SHA-256", &entry.source_digest);
                }
                if replacement_required {
                    ui.checkbox(
                        replacement_approved,
                        "I separately approve replacement of the exact different file shown above",
                    );
                }
                ui.horizontal_wrapped(|ui| {
                    if widgets::action_button(
                        ui,
                        "Confirm and apply exact plan",
                        widgets::ActionStyle::Primary,
                        !replacement_required || *replacement_approved,
                    )
                    .clicked()
                    {
                        action = Some(CheatWorkflowAction::ConfirmApply);
                    }
                    if widgets::action_button(ui, "Cancel", widgets::ActionStyle::Quiet, true)
                        .clicked()
                    {
                        action = Some(CheatWorkflowAction::CancelApply);
                    }
                });
            }
            CheatTransactionState::Applying { .. } => {
                ui.horizontal(|ui| {
                    ui.spinner();
                    ui.label("Applying and verifying the exact approved plan off the UI thread…");
                });
            }
            CheatTransactionState::Result { result, .. } => {
                let (label, tone) = match result.journal.status {
                    SharedApplyStatus::Success => ("Apply succeeded", widgets::StatusTone::Success),
                    SharedApplyStatus::PartialFailure => {
                        ("Apply partially succeeded", widgets::StatusTone::Warning)
                    }
                    SharedApplyStatus::Failed => ("Apply failed", widgets::StatusTone::Blocked),
                    SharedApplyStatus::DryRun => ("Dry run", widgets::StatusTone::Info),
                };
                widgets::status_badge(ui, label, tone);
                widgets::copyable_value(ui, "Operation ID", &result.journal.operation_id);
                for entry in &result.journal.entries {
                    ui.label(format!(
                        "{:?} · verification {} · backup {}",
                        entry.outcome,
                        if entry.verification_succeeded {
                            "passed"
                        } else {
                            "not complete"
                        },
                        if entry.backup_path.is_some() {
                            "retained"
                        } else {
                            "not required"
                        }
                    ));
                    for failure in &entry.failures {
                        ui.label(format!("Failure: {:?} · {}", failure.kind, failure.detail));
                    }
                }
                if let Some(failure) = &result.journal_failure {
                    widgets::banner(
                        ui,
                        "Journal failed after transaction work",
                        &failure.detail,
                        widgets::StatusTone::Warning,
                    );
                }
                if let Some(path) = &result.journal_path
                    && widgets::path_value(ui, "Journal", path)
                {
                    let _ = clipboard.set_text(path.display().to_string());
                }
                if widgets::action_button(
                    ui,
                    "Open exact operation in History & Logs",
                    widgets::ActionStyle::Secondary,
                    result.journal_path.is_some(),
                )
                .clicked()
                {
                    action = Some(CheatWorkflowAction::OpenApplyHistory);
                }
            }
            CheatTransactionState::Idle => {}
        }
    });
    action
}

#[allow(clippy::too_many_arguments)]
fn show_cheats_mods_page(
    ui: &mut egui::Ui,
    workflow: Option<&mut CheatWorkflowState>,
    profiles: &RetroArchProfilesState,
    pcsx2_profiles: &Pcsx2ProfilesState,
    dolphin_profiles: &DolphinProfilesState,
    live: Option<&LoadedData>,
    cached: Option<&CachedLibrarySnapshot>,
    history: &OperationHistory,
    busy: bool,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    let activity_archive = workflow
        .as_deref()
        .map(|workflow| workflow.archive_path.clone());
    let pcsx2_read_only = workflow
        .as_deref()
        .is_some_and(|workflow| workflow.adapter == CheatEmulatorAdapter::Pcsx2);
    let dolphin_read_only = workflow
        .as_deref()
        .is_some_and(|workflow| workflow.adapter == CheatEmulatorAdapter::Dolphin);
    widgets::page_header(
        ui,
        "Cheats & Mods",
        "Inspect emulator-managed cheats and patches or retrieve trusted catalogues for one exact archive.",
    );

    // --- Overview: current archive, its readiness, and availability
    // across every supported system - a concise summary, not a deep dive
    // into whichever system happens to be selected right now (that lives
    // in "Selected system workflow" below).
    widgets::section_header(
        ui,
        "Overview",
        Some("The selected archive, its readiness, and what each supported system can do with it."),
    );
    let (integration_label, integration_tone) = match workflow.as_deref() {
        Some(workflow) if workflow.adapter == CheatEmulatorAdapter::Pcsx2 => {
            pcsx2_integration_presentation(pcsx2_profiles)
        }
        Some(workflow) if workflow.adapter == CheatEmulatorAdapter::Dolphin => {
            dolphin_integration_presentation(dolphin_profiles)
        }
        _ => retroarch_integration_presentation(profiles),
    };
    widgets::card(ui, |ui| {
        ui.horizontal_wrapped(|ui| {
            widgets::status_badge(ui, integration_label, integration_tone);
            if let Some(workflow) = workflow.as_deref() {
                ui.strong(format!("Current archive: {}", workflow.display_name));
            } else {
                ui.label("No archive context selected");
            }
            if widgets::action_button(
                ui,
                if workflow.is_some() {
                    "Choose another archive"
                } else {
                    "Choose archive"
                },
                widgets::ActionStyle::Secondary,
                true,
            )
            .clicked()
            {
                action = Some(CheatWorkflowAction::ChooseArchive);
            }
        });
        let mut readiness_items = vec![(
            "Trusted catalogue retrieval available",
            widgets::StatusTone::Success,
        )];
        if workflow.is_none() {
            readiness_items.push(("Matching pending", widgets::StatusTone::Pending));
            readiness_items.push(("Installation gated", widgets::StatusTone::Pending));
        } else if pcsx2_read_only || dolphin_read_only {
            readiness_items.push(("Read-only preview", widgets::StatusTone::Info));
            readiness_items.push(("Preview only", widgets::StatusTone::Pending));
        } else {
            readiness_items.push(("Shared matching available", widgets::StatusTone::Info));
            readiness_items.push((
                "Controlled apply after eligible preview",
                widgets::StatusTone::Info,
            ));
        }
        widgets::status_strip(ui, &readiness_items);

        // Cross-system availability: composed entirely from the existing
        // per-adapter presentation functions (no new detection logic),
        // gated by the same platform checks the "Choose a system"
        // selector below uses, so the two never disagree about which
        // systems apply to this archive.
        let mut system_lines: Vec<(String, widgets::StatusTone)> = Vec::new();
        let (retroarch_label, retroarch_tone) = retroarch_integration_presentation(profiles);
        system_lines.push((format!("RetroArch · {retroarch_label}"), retroarch_tone));
        if workflow
            .as_deref()
            .is_some_and(|workflow| platform_is_ps2(workflow.platform.as_deref()))
        {
            let (label, tone) = pcsx2_integration_presentation(pcsx2_profiles);
            system_lines.push((format!("PCSX2 · {label}"), tone));
        }
        if workflow
            .as_deref()
            .is_some_and(|workflow| platform_is_dolphin(workflow.platform.as_deref()))
        {
            let (label, tone) = dolphin_integration_presentation(dolphin_profiles);
            system_lines.push((format!("Dolphin · {label}"), tone));
        }
        let system_items: Vec<(&str, widgets::StatusTone)> = system_lines
            .iter()
            .map(|(label, tone)| (label.as_str(), *tone))
            .collect();
        widgets::status_strip(ui, &system_items);
    });
    ui.add_space(theme::SECTION_GAP);
    show_cheats_mods_safety_information(ui);
    ui.add_space(theme::SECTION_GAP);

    // --- Choose a system: which adapter's workflow is shown below.
    if let Some(workflow) = workflow.as_deref() {
        action = show_cheat_emulator_adapter_selector(ui, workflow).or(action);
        ui.add_space(theme::SECTION_GAP);
    }

    // --- Selected system workflow: everything specific to the archive
    // and the currently selected adapter.
    widgets::section_header(
        ui,
        "Selected system workflow",
        Some("Profile, source, identity, preview, and installation state for the chosen system."),
    );
    if let Some(workflow) = workflow {
        show_cheats_mods_workflow_states(
            ui,
            Some(workflow),
            profiles,
            pcsx2_profiles,
            dolphin_profiles,
        );
        ui.add_space(theme::SECTION_GAP);
        show_cheat_archive_context(ui, workflow, live, cached, clipboard);
        ui.add_space(theme::SECTION_GAP);
        show_shared_game_identity(ui, workflow, clipboard);
        ui.add_space(theme::SECTION_GAP);
        action = show_shared_cheat_preview(ui, workflow, clipboard).or(action);
        ui.add_space(theme::SECTION_GAP);
        match workflow.adapter {
            CheatEmulatorAdapter::RetroArch => {
                action = show_cheat_workflow_step1(ui, workflow, profiles, busy).or(action);
                action = show_cheat_source_modes(ui, workflow, profiles).or(action);
                let source_action = match workflow.source_mode {
                    CheatSourceMode::ExistingRetroArchLibrary => {
                        show_existing_retroarch_library(ui, workflow, profiles, clipboard)
                    }
                    CheatSourceMode::ArchiveFsTrustedCatalogue => {
                        show_cheat_workflow_step2(ui, workflow, busy)
                    }
                };
                action = action.or(source_action);
            }
            CheatEmulatorAdapter::Pcsx2 => {
                action = show_pcsx2_workflow(ui, workflow, pcsx2_profiles, clipboard).or(action);
            }
            CheatEmulatorAdapter::Dolphin => {
                action =
                    show_dolphin_workflow(ui, workflow, dolphin_profiles, clipboard).or(action);
            }
        }
    } else {
        widgets::card(ui, |ui| {
            widgets::section_header(
                ui,
                "Choose one archive",
                Some("ArchiveFS never fabricates a default archive context."),
            );
            ui.label("Choose an archive here to discover RetroArch profiles and inspect or retrieve a trusted catalogue. Selection alone never mounts, queues, fetches, or changes the archive.");
            ui.horizontal_wrapped(|ui| {
                widgets::status_badge(
                    ui,
                    "Profile discovery available",
                    widgets::StatusTone::Success,
                );
                widgets::status_badge(
                    ui,
                    "Trusted retrieval available",
                    widgets::StatusTone::Success,
                );
                widgets::status_badge(ui, "Matching unavailable", widgets::StatusTone::Pending);
                widgets::status_badge(ui, "Installation unavailable", widgets::StatusTone::Pending);
                widgets::status_badge(ui, "Mods unavailable", widgets::StatusTone::Pending);
            });
            ui.horizontal_wrapped(|ui| {
                if widgets::action_button(ui, "Choose archive", widgets::ActionStyle::Primary, true)
                    .clicked()
                {
                    action = Some(CheatWorkflowAction::ChooseArchive);
                }
                if widgets::action_button(ui, "Open Library", widgets::ActionStyle::Secondary, true)
                    .clicked()
                {
                    action = Some(CheatWorkflowAction::OpenLibrary);
                }
            });
        });
    }

    ui.add_space(theme::SECTION_GAP);
    show_mods_section(ui, pcsx2_read_only, dolphin_read_only);
    ui.add_space(theme::SECTION_GAP);
    show_recent_cheat_activity(ui, history, activity_archive.as_deref());
    action
}

fn show_cheat_source_modes(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    _profiles: &RetroArchProfilesState,
) -> Option<CheatWorkflowAction> {
    widgets::section_header(
        ui,
        "Stage 2 · Cheat source",
        Some(
            "Source choice is independent from the archive, emulator profile, destination, and installation state.",
        ),
    );
    let show_existing = |ui: &mut egui::Ui, selected: bool| {
        let mut clicked = false;
        widgets::card(ui, |ui| {
            clicked = ui.radio(selected, "Existing RetroArch library").clicked();
            widgets::status_badge(ui, "Existing local content", widgets::StatusTone::Info);
            ui.label("Read-only bounded inventory of the selected profile's configured cheat directory. No compatibility claim.");
        });
        clicked
    };
    let show_trusted = |ui: &mut egui::Ui, selected: bool| {
        let mut clicked = false;
        widgets::card(ui, |ui| {
            clicked = ui.radio(selected, "ArchiveFS trusted catalogue").clicked();
            widgets::status_badge(ui, "Trusted reviewed source", widgets::StatusTone::Success);
            ui.label("A validated immutable ArchiveFS cache snapshot. It is not the same as RetroArch installed cheats.");
        });
        clicked
    };
    let existing_selected = workflow.source_mode == CheatSourceMode::ExistingRetroArchLibrary;
    let trusted_selected = workflow.source_mode == CheatSourceMode::ArchiveFsTrustedCatalogue;
    let (existing_clicked, trusted_clicked) = if ui.available_width() >= 760.0 {
        let mut existing_clicked = false;
        let mut trusted_clicked = false;
        ui.columns(2, |columns| {
            existing_clicked = show_existing(&mut columns[0], existing_selected);
            trusted_clicked = show_trusted(&mut columns[1], trusted_selected);
        });
        (existing_clicked, trusted_clicked)
    } else {
        (
            show_existing(ui, existing_selected),
            show_trusted(ui, trusted_selected),
        )
    };
    if existing_clicked {
        workflow.source_mode = CheatSourceMode::ExistingRetroArchLibrary;
    } else if trusted_clicked {
        workflow.source_mode = CheatSourceMode::ArchiveFsTrustedCatalogue;
    }
    let show_planned = |ui: &mut egui::Ui, kind, body| {
        let (label, state) = import_source_presentation(kind);
        widgets::card(ui, |ui| {
            ui.strong(label);
            widgets::status_badge(ui, state, widgets::StatusTone::Pending);
            ui.label(body);
        });
    };
    let local_body =
        "A real bounded local inspection backend is required before selection can be offered.";
    let remote_body = "User-defined remote sources are a future workflow.";
    if ui.available_width() >= 760.0 {
        ui.columns(2, |columns| {
            show_planned(
                &mut columns[0],
                ImportSourceKind::LocalUnverifiedSource,
                local_body,
            );
            show_planned(
                &mut columns[1],
                ImportSourceKind::RemoteUnverifiedSource,
                remote_body,
            );
        });
    } else {
        show_planned(ui, ImportSourceKind::LocalUnverifiedSource, local_body);
        show_planned(ui, ImportSourceKind::RemoteUnverifiedSource, remote_body);
    }
    None
}

fn show_existing_retroarch_library(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profiles: &RetroArchProfilesState,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<CheatWorkflowAction> {
    let selected_profile_id = workflow.selected_profile_id.as_deref();
    if selected_profile_id.is_none() {
        widgets::banner(
            ui,
            "Waiting for profile",
            "Choose an eligible RetroArch profile before inspecting its configured cheat directory.",
            widgets::StatusTone::Pending,
        );
        return None;
    }
    let selected_profile_id = selected_profile_id.unwrap();
    let destination = match profiles {
        RetroArchProfilesState::Ready(discovery) => discovery
            .profiles
            .iter()
            .find(|profile| profile.eligible && profile.profile_id == selected_profile_id)
            .and_then(|profile| profile.cheat_destination_root.as_ref()),
        _ => None,
    };
    let Some(destination) = destination else {
        widgets::banner(
            ui,
            "Destination unavailable",
            "The selected profile does not currently expose a safely resolved cheat destination.",
            widgets::StatusTone::Warning,
        );
        return None;
    };
    if destination.lossy {
        widgets::banner(
            ui,
            "Destination unavailable",
            "The configured path cannot be represented losslessly and will not be inspected.",
            widgets::StatusTone::Blocked,
        );
        return None;
    }
    let path = Path::new(&destination.display);
    widgets::card(ui, |ui| {
        widgets::status_strip(
            ui,
            &[
                ("Unverified local content", widgets::StatusTone::Warning),
                ("Modified by this workspace · No", widgets::StatusTone::Info),
            ],
        );
        if widgets::path_value(ui, "RetroArch cheat directory", path) {
            let _ = clipboard.set_text(destination.display.clone());
        }
        ui.label("Inspection is limited to reviewed platform aliases and plausible game filenames. Local files remain unverified compatibility evidence.");
    });

    if workflow.existing_library_profile_id.as_deref() != Some(selected_profile_id) {
        workflow.existing_library_profile_id = None;
        workflow.existing_library = CheatStepResource::NotLoaded;
    }
    match &workflow.existing_library {
        CheatStepResource::NotLoaded => Some(CheatWorkflowAction::InspectExistingLibrary),
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Inspecting only relevant platform and game paths with fixed limits...");
            });
            None
        }
        CheatStepResource::Failed(message) => {
            widgets::banner(
                ui,
                "Inspection unavailable",
                message,
                widgets::StatusTone::Warning,
            );
            None
        }
        CheatStepResource::Ready(inspection) => {
            let (label, tone) = retroarch_library_state_presentation(inspection.state);
            let (match_label, match_tone) =
                retroarch_local_match_presentation(inspection.match_state);
            widgets::card(ui, |ui| {
                ui.horizontal_wrapped(|ui| {
                    widgets::status_badge(ui, label, tone);
                    widgets::status_badge(ui, match_label, match_tone);
                    ui.label(format!(
                        "{} relevant cheat file{}",
                        inspection.approximate_cheat_file_count,
                        if inspection.approximate_cheat_file_count == 1 {
                            ""
                        } else {
                            "s"
                        }
                    ));
                    ui.label(format!(
                        "{} directories · {} files · {} bytes inspected",
                        inspection.directories_inspected,
                        inspection.entries_examined,
                        inspection.bytes_inspected
                    ));
                });
                for path in &inspection.matching_files {
                    if path.lossy {
                        ui.label(
                            "Matching path retained with non-UTF-8 identity (display is lossy).",
                        );
                    } else if widgets::path_value(ui, "Local candidate", Path::new(&path.display)) {
                        let _ = clipboard.set_text(path.display.clone());
                    }
                }
                if let Some(warning) = &inspection.warning {
                    ui.label(warning);
                }
            });
            None
        }
    }
}

fn retroarch_local_match_presentation(
    state: RetroArchLocalCheatMatchState,
) -> (&'static str, widgets::StatusTone) {
    match state {
        RetroArchLocalCheatMatchState::NotTargeted => {
            ("Not targeted", widgets::StatusTone::Pending)
        }
        RetroArchLocalCheatMatchState::NotFound => {
            ("No local cheat found", widgets::StatusTone::Pending)
        }
        RetroArchLocalCheatMatchState::Candidate => {
            ("Local filename candidate", widgets::StatusTone::Warning)
        }
        RetroArchLocalCheatMatchState::ExactLocalFile => {
            ("Exact local filename", widgets::StatusTone::Success)
        }
        RetroArchLocalCheatMatchState::Ambiguous => {
            ("Ambiguous local files", widgets::StatusTone::Warning)
        }
        RetroArchLocalCheatMatchState::LimitReached => {
            ("Inspection limit reached", widgets::StatusTone::Warning)
        }
        RetroArchLocalCheatMatchState::Unsafe => {
            ("Unsafe local path refused", widgets::StatusTone::Blocked)
        }
        RetroArchLocalCheatMatchState::Unavailable => {
            ("Local inspection unavailable", widgets::StatusTone::Pending)
        }
    }
}

fn retroarch_library_state_presentation(
    state: RetroArchCheatLibraryState,
) -> (&'static str, widgets::StatusTone) {
    match state {
        RetroArchCheatLibraryState::Missing => ("Directory missing", widgets::StatusTone::Pending),
        RetroArchCheatLibraryState::Available => ("Directory exists", widgets::StatusTone::Success),
        RetroArchCheatLibraryState::Inaccessible => {
            ("Directory inaccessible", widgets::StatusTone::Warning)
        }
        RetroArchCheatLibraryState::UnsafePath => {
            ("Unsafe path refused", widgets::StatusTone::Blocked)
        }
        RetroArchCheatLibraryState::LimitReached => {
            ("Inspection limit reached", widgets::StatusTone::Warning)
        }
    }
}

/// Step 2 of the cheat workflow: the built-in trusted source list, the
/// cached snapshot's provenance/digest/freshness, and retrieval
/// actions. Only the fixed trusted list is ever shown - there is no
/// user-supplied URL surface, and every retrieval runs on a background
/// thread through `fetch_retroarch_cheat_source`'s existing size/
/// digest/redirect protections.
fn show_cheat_workflow_step2(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    busy: bool,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "Trusted catalogue details",
        Some("Only reviewed, built-in sources are available. Custom URLs are not accepted."),
    );
    if workflow.selected_profile_id.is_none() {
        widgets::banner(
            ui,
            "Waiting for profile",
            "Choose an eligible RetroArch profile in Stage 1 to continue.",
            widgets::StatusTone::Pending,
        );
        return None;
    }
    match &workflow.source_list {
        CheatStepResource::NotLoaded => {
            ui.label("Trusted sources have not been listed yet.");
            if widgets::action_button(
                ui,
                "List trusted sources",
                widgets::ActionStyle::Primary,
                true,
            )
            .clicked()
            {
                action = Some(CheatWorkflowAction::RefreshSources);
            }
        }
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Reading the trusted-source cache...");
            });
        }
        CheatStepResource::Failed(message) => {
            widgets::banner(
                ui,
                "Could not list trusted sources",
                message,
                widgets::StatusTone::Blocked,
            );
            if widgets::action_button(ui, "Retry", widgets::ActionStyle::Primary, true).clicked() {
                action = Some(CheatWorkflowAction::RefreshSources);
            }
        }
        CheatStepResource::Ready(list) => {
            for entry in &list.entries {
                let source = &entry.source;
                widgets::card(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        if source.enabled {
                            let selected =
                                workflow.selected_source_id.as_deref() == Some(&source.source_id);
                            if ui.radio(selected, &source.display_name).clicked() {
                                workflow.selected_source_id = Some(source.source_id.clone());
                            }
                        } else {
                            ui.add_enabled(
                                false,
                                egui::Button::selectable(false, &source.display_name),
                            );
                            widgets::status_badge(ui, "Disabled", widgets::StatusTone::Pending);
                        }
                        if source.experimental {
                            widgets::status_badge(ui, "Experimental", widgets::StatusTone::Warning);
                        } else {
                            widgets::status_badge(
                                ui,
                                "Trusted built-in",
                                widgets::StatusTone::Success,
                            );
                        }
                        widgets::status_badge(
                            ui,
                            cheat_freshness_label(entry.freshness),
                            cheat_freshness_tone(entry.freshness),
                        );
                    });
                    if workflow.selected_source_id.as_deref() == Some(&source.source_id) {
                        ui.horizontal_wrapped(|ui| {
                            ui.label(format!("Permitted host: {}", source.permitted_host));
                            if let Some(fetched_at) = entry.fetched_at_unix_seconds {
                                ui.label(format!(
                                    "Last retrieval: {}",
                                    format_unix_timestamp_utc(fetched_at as i64)
                                ));
                            }
                        });
                        ui.label(&source.provenance);
                        if !entry.warnings.is_empty() {
                            for warning in summarise_cheat_warnings(&entry.warnings) {
                                widgets::banner(
                                    ui,
                                    "Notice",
                                    &warning,
                                    widgets::StatusTone::Warning,
                                );
                            }
                        }
                        widgets::technical_details(
                            ui,
                            ("cheat_source_technical_details", &source.source_id),
                            |ui| {
                                widgets::copyable_value(ui, "Source identifier", &source.source_id);
                                widgets::copyable_value(ui, "Download URL", &source.download_url);
                                ui.label(format!("Trust status: {}", entry.trust_status));
                                if let Some(licence) = &source.licence_url {
                                    ui.label(format!("Licence: {licence}"));
                                }
                                if let Some(pinned) = &source.pinned_version {
                                    ui.label(format!("Pinned version: {pinned}"));
                                }
                                if let Some(version) = &entry.current_cached_version {
                                    ui.label(format!("Cached version: {version}"));
                                }
                                if let Some(digest) = &entry.archive_sha256 {
                                    widgets::copyable_value(ui, "SHA-256", digest);
                                }
                                if let Some(count) = entry.catalogue_file_count {
                                    ui.label(format!("Catalogue files: {count}"));
                                }
                                ui.label(format!(
                                    "Usable for setup: {}",
                                    if entry.setup_usable { "Yes" } else { "No" }
                                ));
                                for warning in &entry.warnings {
                                    ui.label(warning);
                                }
                            },
                        );
                    }
                });
                ui.add_space(6.0);
            }
            ui.add_space(4.0);
            let fetching = matches!(workflow.source_fetch, CheatStepResource::Loading { .. });
            let selected_entry = workflow.selected_source_id.as_deref().and_then(|id| {
                list.entries
                    .iter()
                    .find(|entry| entry.source.source_id == id)
            });
            ui.horizontal_wrapped(|ui| {
                let can_fetch =
                    !busy && !fetching && selected_entry.is_some_and(|entry| entry.source.enabled);
                if widgets::action_button(
                    ui,
                    "Manage catalogue in Sources",
                    widgets::ActionStyle::Primary,
                    can_fetch,
                )
                .clicked()
                {
                    action = Some(CheatWorkflowAction::ManageCatalogue);
                }
                let cached_available = selected_entry
                    .is_some_and(|entry| entry.freshness != CheatSourceFreshness::Missing);
                if widgets::action_button(
                    ui,
                    "Use cached snapshot",
                    widgets::ActionStyle::Secondary,
                    !busy && !fetching && cached_available,
                )
                .clicked()
                {
                    action = Some(CheatWorkflowAction::UseCachedSnapshot);
                }
                if widgets::action_button(
                    ui,
                    "Refresh source list",
                    widgets::ActionStyle::Quiet,
                    !fetching,
                )
                .clicked()
                {
                    action = Some(CheatWorkflowAction::RefreshSources);
                }
            });
            egui::CollapsingHeader::new("Advanced retrieval options")
                .default_open(false)
                .show(ui, |ui| {
                    ui.checkbox(
                        &mut workflow.fetch_force_refresh,
                        "Force a full refresh instead of reusing a fresh cache",
                    );
                });
        }
    }
    match &workflow.source_fetch {
        CheatStepResource::NotLoaded => {}
        CheatStepResource::Loading { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Retrieving catalogue...");
            });
        }
        CheatStepResource::Failed(message) => {
            widgets::banner(
                ui,
                "Catalogue retrieval failed",
                message,
                widgets::StatusTone::Blocked,
            );
        }
        CheatStepResource::Ready(result) => {
            widgets::card(ui, |ui| {
                ui.horizontal_wrapped(|ui| {
                    widgets::status_badge(ui, "Catalogue ready", widgets::StatusTone::Success);
                    widgets::status_badge(
                        ui,
                        cheat_freshness_label(result.freshness),
                        if result.stale {
                            widgets::StatusTone::Warning
                        } else {
                            widgets::StatusTone::Success
                        },
                    );
                    ui.label(
                        egui::RichText::new(format!(
                            "{} valid cheats",
                            result.manifest.valid_cheat_count
                        ))
                        .strong(),
                    );
                    ui.label(format!(
                        "Retrieved {}",
                        format_unix_timestamp_utc(result.manifest.fetched_at_unix_seconds as i64)
                    ));
                });
                ui.label(cheat_fetch_status_label(result.status));
                if result.stale {
                    widgets::banner(
                        ui,
                        "Stale snapshot",
                        "The cached catalogue remains usable for inspection, but should be updated when online.",
                        widgets::StatusTone::Warning,
                    );
                }
                for warning in summarise_cheat_warnings(&result.warnings) {
                    widgets::banner(
                        ui,
                        "Catalogue notice",
                        &warning,
                        widgets::StatusTone::Warning,
                    );
                }
                widgets::technical_details(
                    ui,
                    (
                        "cheat_catalogue_technical_details",
                        &result.manifest.archive_sha256,
                    ),
                    |ui| {
                        widgets::copyable_value(ui, "SHA-256", &result.manifest.archive_sha256);
                        widgets::copyable_value(
                            ui,
                            "Catalogue path",
                            &result.local_catalogue_path.display,
                        );
                        widgets::copyable_value(
                            ui,
                            "Immutable snapshot",
                            &result.immutable_snapshot_path.display,
                        );
                        for warning in &result.warnings {
                            ui.label(warning);
                        }
                    },
                );
            });
        }
    }
    action
}

/// Why an exact-archive Cheats & Mods entry point is unavailable. Profile
/// readiness is deliberately not a navigation gate: the full page owns
/// profile discovery and truthfully presents blocked states.
fn cheat_entry_blocker(
    selected_archive: Option<&Path>,
    selected_count: usize,
    live_records: Option<&[ArchiveRecord]>,
    _profiles: &RetroArchProfilesState,
) -> Option<&'static str> {
    let Some(path) = selected_archive else {
        return Some("Select exactly one archive in the Library first.");
    };
    if selected_count > 1 {
        return Some(
            "RetroArch cheat setup works on exactly one archive; reduce the selection to one.",
        );
    }
    let Some(records) = live_records else {
        return Some("The live snapshot is still loading.");
    };
    if !records
        .iter()
        .any(|record| record.mount_plan.archive.path == path)
    {
        return Some("The selected archive is no longer present in the live snapshot.");
    }
    None
}

/// The eligible profile IDs in a discovery, in discovery order.
fn eligible_profile_ids(discovery: &RetroArchCheatSetupDiscovery) -> Vec<&str> {
    discovery
        .profiles
        .iter()
        .filter(|profile| profile.eligible)
        .map(|profile| profile.profile_id.as_str())
        .collect()
}

fn eligible_pcsx2_profile_ids(discovery: &Pcsx2ProfileDiscovery) -> Vec<&str> {
    discovery
        .profiles
        .iter()
        .filter(|profile| profile.eligible)
        .map(|profile| profile.profile_id.as_str())
        .collect()
}

fn eligible_dolphin_profile_ids(discovery: &DolphinProfileDiscovery) -> Vec<&str> {
    discovery
        .profiles
        .iter()
        .filter(|profile| profile.eligible)
        .map(|profile| profile.profile_id.as_str())
        .collect()
}

/// Step 1 of the cheat workflow: archive identity plus explicit profile
/// selection. Renders from the shared `RetroArchProfilesState` (the
/// same discovery the Settings page shows) and mutates only the
/// workflow's own `selected_profile_id`. A selection that no longer
/// exists in the current discovery (profile vanished on rescan) is
/// cleared here rather than silently kept.
fn show_cheat_workflow_step1(
    ui: &mut egui::Ui,
    workflow: &mut CheatWorkflowState,
    profiles: &RetroArchProfilesState,
    busy: bool,
) -> Option<CheatWorkflowAction> {
    let mut action = None;
    widgets::section_header(
        ui,
        "Stage 1 · Archive and RetroArch profile",
        Some(
            "The archive context above is fixed. ArchiveFS selects a profile automatically only when exactly one is eligible.",
        ),
    );
    widgets::section_header(ui, "RetroArch profile", None);
    match profiles {
        RetroArchProfilesState::NotScanned => {
            ui.label("Profiles have not been scanned yet.");
        }
        RetroArchProfilesState::Scanning { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Scanning for RetroArch profiles...");
            });
        }
        RetroArchProfilesState::Error(message) => {
            ui.colored_label(
                ui.visuals().error_fg_color,
                format!("Profile discovery failed: {message}"),
            );
        }
        RetroArchProfilesState::Ready(discovery) => {
            let eligible = eligible_profile_ids(discovery);
            if let Some(selected) = workflow.selected_profile_id.clone()
                && !eligible.contains(&selected.as_str())
            {
                workflow.selected_profile_id = None;
                workflow.existing_library_profile_id = None;
                workflow.existing_library = CheatStepResource::NotLoaded;
                ui.colored_label(
                    ui.visuals().warn_fg_color,
                    "The previously selected profile is no longer eligible; choose again.",
                );
            }
            if eligible.is_empty() {
                widgets::banner(
                    ui,
                    "No eligible profile",
                    "The discovered profiles are blocked. Review their concise blocker summaries below or rescan after correcting RetroArch configuration.",
                    widgets::StatusTone::Blocked,
                );
            } else if eligible.len() > 1 && workflow.selected_profile_id.is_none() {
                ui.label(format!(
                    "{} eligible profiles were found. ArchiveFS never silently picks \
                     between them — choose one explicitly.",
                    eligible.len()
                ));
            }
            for profile in &discovery.profiles {
                widgets::card(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        if profile.eligible {
                            let selected = workflow.selected_profile_id.as_deref()
                                == Some(&profile.profile_id);
                            if ui.radio(selected, &profile.profile_id).clicked() {
                                workflow.selected_profile_id = Some(profile.profile_id.clone());
                                workflow.existing_library_profile_id = None;
                                workflow.existing_library = CheatStepResource::NotLoaded;
                            }
                        } else {
                            ui.add_enabled(
                                false,
                                egui::Button::selectable(false, &profile.profile_id),
                            );
                            widgets::status_badge(ui, "Blocked", profile_presentation_tone(false));
                        }
                        ui.label(format!(
                            "{} / {}",
                            profile_kind_label(&profile.installation_type),
                            profile_scope_label(&profile.scope)
                        ));
                    });
                    if let Some(blocker) = profile.blockers.first() {
                        ui.label(format!("{} — {}", blocker.code, blocker.detail));
                    }
                    if profile.blockers.len() > 1 {
                        egui::CollapsingHeader::new(format!(
                            "All technical blockers ({})",
                            profile.blockers.len()
                        ))
                        .default_open(false)
                        .show(ui, |ui| {
                            for blocker in &profile.blockers {
                                ui.label(format!("{} — {}", blocker.code, blocker.detail));
                            }
                        });
                    }
                });
                ui.add_space(6.0);
            }
        }
    }
    ui.add_space(4.0);
    if widgets::action_button(ui, "Rescan profiles", widgets::ActionStyle::Quiet, !busy).clicked() {
        action = Some(CheatWorkflowAction::RescanProfiles);
    }
    action
}
enum RetroArchProfilesState {
    NotScanned,
    Scanning {
        receiver: Receiver<Result<RetroArchCheatSetupDiscovery, String>>,
    },
    Ready(RetroArchCheatSetupDiscovery),
    Error(String),
}

enum Pcsx2ProfilesState {
    NotScanned,
    Scanning {
        receiver: Receiver<Result<Pcsx2ProfileDiscovery, String>>,
    },
    Ready(Pcsx2ProfileDiscovery),
    Error(String),
}

enum DolphinProfilesState {
    NotScanned,
    Scanning {
        receiver: Receiver<Result<DolphinProfileDiscovery, String>>,
    },
    Ready(DolphinProfileDiscovery),
    Error(String),
}

/// Display label for a discovered profile's installation type.
fn profile_kind_label(kind: &ProfileKind) -> &'static str {
    match kind {
        ProfileKind::Native => "Native",
        ProfileKind::AppImage => "AppImage",
        ProfileKind::Flatpak => "Flatpak",
    }
}

/// Display label for a discovered profile's scope.
fn profile_scope_label(scope: &ProfileScope) -> &'static str {
    match scope {
        ProfileScope::User => "User",
        ProfileScope::System => "System",
    }
}

fn profile_presentation_tone(eligible: bool) -> widgets::StatusTone {
    if eligible {
        widgets::StatusTone::Success
    } else {
        widgets::StatusTone::Pending
    }
}

/// What the Settings page asks `update` to do - each maps onto an
/// existing proven workflow (`SetupAction::OpenConfigFolder`, the
/// diagnostics refresh, the Diagnostics overlay, the background
/// profile-discovery scan), never new machinery.
enum SettingsPageAction {
    OpenConfigFolder,
    ValidateConfiguration,
    OpenDiagnostics,
    RescanRetroArchProfiles,
}

fn show_settings_page(
    ui: &mut egui::Ui,
    database_state: &DatabaseState,
    diagnostics: &DiagnosticsState,
    retroarch_profiles: &RetroArchProfilesState,
    mount_root: Option<&Path>,
    busy: bool,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<SettingsPageAction> {
    let mut action = None;
    widgets::page_header(
        ui,
        "Settings",
        "Review ArchiveFS locations, configuration health, and supported integrations.",
    );

    let database_path = database_state_path(database_state).map(|path| path.display().to_string());
    let config_path = match diagnostics {
        DiagnosticsState::Ready { report, .. } => report
            .config_path
            .as_ref()
            .map(|path| path.display().to_string()),
        _ => None,
    };
    let mount_root_text = mount_root.map(|path| path.display().to_string());

    widgets::section_header(
        ui,
        "1. ArchiveFS locations",
        Some("Full paths remain available through hover and Copy without dominating the page."),
    );
    widgets::card(ui, |ui| {
        if let Some(path) = &config_path {
            if widgets::copyable_value(ui, "Configuration", path) {
                let _ = clipboard.set_text(path.clone());
            }
        } else {
            ui.label("Configuration: unknown");
        }
        if let Some(path) = &database_path {
            if widgets::copyable_value(ui, "Database", path) {
                let _ = clipboard.set_text(path.clone());
            }
        } else {
            ui.label("Database: unknown");
        }
        if let Some(path) = mount_root {
            if widgets::path_value(ui, "Mount root", path) {
                let _ = clipboard.set_text(path.display().to_string());
            }
        } else {
            ui.label("Mount root: not loaded");
        }
        ui.label(egui::RichText::new("Mount-root changes apply to new mounts; existing mounts keep their current destinations until remounted.").color(theme::muted(ui)));
    });

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "2. Configuration validation",
        Some("ArchiveFS validates the active configuration without changing it."),
    );
    let (validation_title, validation_detail, validation_tone) = match diagnostics {
        DiagnosticsState::Ready { report, .. } if diagnostics_can_continue(report) => (
            "Ready",
            "No blocking configuration issues were found.",
            widgets::StatusTone::Success,
        ),
        DiagnosticsState::Ready { .. } => (
            "Needs attention",
            "Configuration issues were found. Open diagnostics for the complete checks.",
            widgets::StatusTone::Warning,
        ),
        DiagnosticsState::Loading { .. } => (
            "Checking",
            "Configuration validation is running in the background.",
            widgets::StatusTone::Active,
        ),
        DiagnosticsState::Error { message, .. } => {
            ("Failed", message.as_str(), widgets::StatusTone::Blocked)
        }
    };
    widgets::banner(ui, validation_title, validation_detail, validation_tone);
    ui.horizontal_wrapped(|ui| {
        if widgets::action_button(
            ui,
            "Validate configuration",
            widgets::ActionStyle::Primary,
            !busy,
        )
        .clicked()
        {
            action = Some(SettingsPageAction::ValidateConfiguration);
        }
        if widgets::action_button(
            ui,
            "Open diagnostics",
            widgets::ActionStyle::Secondary,
            true,
        )
        .clicked()
        {
            action = Some(SettingsPageAction::OpenDiagnostics);
        }
        if widgets::action_button(
            ui,
            "Open configuration folder",
            widgets::ActionStyle::Quiet,
            !busy,
        )
        .clicked()
        {
            action = Some(SettingsPageAction::OpenConfigFolder);
        }
    });

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "3. RetroArch integration",
        Some(
            "Eligible profiles are emphasised; blocked discoveries remain available for inspection.",
        ),
    );
    match retroarch_profiles {
        RetroArchProfilesState::NotScanned => {
            if widgets::empty_state(
                ui,
                "Profiles have not been scanned",
                "Scan supported RetroArch locations to find a usable cheat destination.",
                Some("Scan for profiles"),
            ) && !busy
            {
                action = Some(SettingsPageAction::RescanRetroArchProfiles);
            }
        }
        RetroArchProfilesState::Scanning { .. } => {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label("Scanning for RetroArch profiles...");
            });
        }
        RetroArchProfilesState::Error(message) => {
            widgets::banner(
                ui,
                "Profile discovery failed",
                message,
                widgets::StatusTone::Blocked,
            );
            if widgets::action_button(ui, "Rescan profiles", widgets::ActionStyle::Primary, !busy)
                .clicked()
            {
                action = Some(SettingsPageAction::RescanRetroArchProfiles);
            }
        }
        RetroArchProfilesState::Ready(discovery) => {
            if discovery.profiles.is_empty() {
                widgets::empty_state(
                    ui,
                    "No RetroArch profiles found",
                    "No supported installation was discovered in the current environment.",
                    None,
                );
            } else {
                for eligible in [true, false] {
                    for profile in discovery
                        .profiles
                        .iter()
                        .filter(|profile| profile.eligible == eligible)
                    {
                        widgets::card(ui, |ui| {
                            ui.horizontal_wrapped(|ui| {
                                widgets::status_badge(
                                    ui,
                                    if profile.eligible {
                                        "Eligible"
                                    } else {
                                        "Blocked"
                                    },
                                    profile_presentation_tone(profile.eligible),
                                );
                                ui.label(
                                    egui::RichText::new(&profile.profile_id).size(17.0).strong(),
                                );
                                ui.label(format!(
                                    "{} · {}",
                                    profile_kind_label(&profile.installation_type),
                                    profile_scope_label(&profile.scope)
                                ));
                            });
                            if widgets::copyable_value(
                                ui,
                                "Configuration",
                                &profile.configuration_path.display,
                            ) {
                                let _ =
                                    clipboard.set_text(profile.configuration_path.display.clone());
                            }
                            if let Some(destination) = &profile.cheat_destination_root {
                                if widgets::copyable_value(
                                    ui,
                                    "Cheat destination",
                                    &destination.display,
                                ) {
                                    let _ = clipboard.set_text(destination.display.clone());
                                }
                            } else {
                                ui.label("Cheat destination: unresolved");
                            }
                            if !profile.blockers.is_empty() {
                                ui.label(format!(
                                    "{} blocker{}",
                                    profile.blockers.len(),
                                    if profile.blockers.len() == 1 { "" } else { "s" }
                                ));
                                widgets::technical_details(
                                    ui,
                                    ("retroarch_profile_technical_blockers", &profile.profile_id),
                                    |ui| {
                                        for blocker in &profile.blockers {
                                            ui.label(format!(
                                                "{} — {}",
                                                blocker.code, blocker.detail
                                            ));
                                        }
                                    },
                                );
                            }
                        });
                        ui.add_space(6.0);
                    }
                }
            }
            if widgets::action_button(
                ui,
                "Rescan profiles",
                widgets::ActionStyle::Secondary,
                !busy,
            )
            .clicked()
            {
                action = Some(SettingsPageAction::RescanRetroArchProfiles);
            }
        }
    }

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(
        ui,
        "4. Diagnostics and environment report",
        Some("Copy a concise environment report for troubleshooting."),
    );
    widgets::card(ui, |ui| {
        if widgets::action_button(
            ui,
            "Copy environment report",
            widgets::ActionStyle::Secondary,
            true,
        )
        .clicked()
        {
            let _ = clipboard.set_text(system_information_text(
                database_path.as_deref(),
                config_path.as_deref(),
                mount_root_text.as_deref(),
            ));
        }
    });

    ui.add_space(theme::SECTION_GAP);
    widgets::section_header(ui, "5. Intentionally unavailable", None);
    widgets::banner(
        ui,
        "Deferred",
        "Appearance density, reset controls, cache maintenance, and in-app configuration editing have no supported GUI backing today. Source folders remain managed on the Sources page.",
        widgets::StatusTone::Info,
    );
    action
}

fn history_entry_text(entry: &HistoryEntry) -> String {
    let archive = entry
        .archive_path
        .as_deref()
        .map(|path| format!(" · {}", path.display()))
        .unwrap_or_default();
    format!(
        "[{}] {} · {}{} — {}",
        format_history_timestamp(entry.timestamp),
        entry.action,
        entry.outcome,
        archive,
        entry.message
    )
}

fn format_history_timestamp(timestamp: SystemTime) -> String {
    let seconds = timestamp
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
        % 86_400;
    format!(
        "{:02}:{:02}:{:02}",
        seconds / 3_600,
        (seconds % 3_600) / 60,
        seconds % 60
    )
}

/// Which "Library Database" panel button (requirement 3) was clicked.
/// `RefreshStatus` and `RetryLoad` both trigger the same underlying
/// read-only reload (`start_database_action(.., false)`) - they are kept
/// as separate variants only because they are offered from different
/// states and read better as separate buttons to the user.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum DatabasePanelAction {
    ScanLibrary,
    ViewRecentlyFound,
    RefreshStatus,
    RetryLoad,
}

/// The best-known database path regardless of current state - even a
/// database that has never been created yet still has a *planned* path.
/// Shared by `show_database_panel` and the About window so both surfaces
/// can never disagree about which path they mean.
fn database_state_path(state: &DatabaseState) -> Option<PathBuf> {
    match state {
        DatabaseState::NotCreated { database_path } => Some(database_path.clone()),
        DatabaseState::Loading { previous, .. }
        | DatabaseState::Outdated { previous, .. }
        | DatabaseState::Error { previous, .. } => previous
            .as_ref()
            .map(|snapshot| snapshot.database_path.clone()),
        DatabaseState::Ready { snapshot, .. } => Some(snapshot.database_path.clone()),
    }
}

/// Renders the compact "Library Database" status area (requirement 3).
/// Purely informational plus three buttons - never itself authorizes an
/// action, and never blocks the caller (all of its data comes from
/// `state`, already computed off the UI thread).
fn show_database_panel(ui: &mut egui::Ui, state: &DatabaseState) -> Option<DatabasePanelAction> {
    let mut action = None;
    egui::CollapsingHeader::new("Library Database")
        .id_salt("library_database_panel")
        .default_open(!matches!(state, DatabaseState::Ready { .. }))
        .show(ui, |ui| {
            let database_path = database_state_path(state);

            egui::Grid::new("database_status_grid")
                .num_columns(2)
                .show(ui, |ui| {
                    ui.strong("Database path");
                    ui.label(
                        database_path
                            .as_ref()
                            .map(|path| path.display().to_string())
                            .unwrap_or_else(|| "unresolved".to_string()),
                    );
                    ui.end_row();

                    ui.strong("Status");
                    ui.label(state.status_label());
                    ui.end_row();

                    if let Some(snapshot) = state.snapshot() {
                        ui.strong("Schema version");
                        ui.label(snapshot.schema_version.to_string());
                        ui.end_row();

                        ui.strong("Last completed scan");
                        ui.label(
                            snapshot
                                .last_completed_scan
                                .as_ref()
                                .map(|scan| {
                                    scan.finished_at.clone().unwrap_or_else(|| {
                                        format!("{} (in progress)", scan.started_at)
                                    })
                                })
                                .unwrap_or_else(|| "never".to_string()),
                        );
                        ui.end_row();

                        ui.strong("Cached archives");
                        ui.label(snapshot.stats.total_archives.to_string());
                        ui.end_row();

                        ui.strong("Present / missing");
                        ui.label(format!(
                            "{} / {}",
                            snapshot.stats.present_archives, snapshot.stats.missing_archives
                        ));
                        ui.end_row();
                    }

                    if let DatabaseState::Ready {
                        last_scan_summary: Some(summary),
                        ..
                    } = state
                    {
                        ui.strong("Last scan (this session)");
                        ui.label(format_scan_completion(summary));
                        ui.end_row();
                    }

                    ui.strong("Action safety");
                    ui.label(
                        "Cached rows never authorize mount or unmount - only a validated live \
                         snapshot can.",
                    );
                    ui.end_row();
                });

            match state {
                DatabaseState::Outdated { health, .. } => {
                    ui.colored_label(
                        ui.visuals().error_fg_color,
                        format!(
                            "Database schema is outdated (found version {}); run a library scan \
                             to upgrade it.",
                            health
                                .schema_version
                                .map(|version| version.to_string())
                                .unwrap_or_else(|| "unknown".to_string())
                        ),
                    );
                }
                DatabaseState::Error { message, .. } => {
                    ui.colored_label(ui.visuals().error_fg_color, message.as_str());
                }
                DatabaseState::NotCreated { .. } => {
                    ui.label("No library database yet. Run a library scan to create one.");
                }
                DatabaseState::Loading { .. } | DatabaseState::Ready { .. } => {}
            }

            ui.horizontal(|ui| {
                let loading = state.is_loading();
                if ui
                    .add_enabled(!loading, egui::Button::new("Scan library"))
                    .clicked()
                {
                    action = Some(DatabasePanelAction::ScanLibrary);
                }
                if state
                    .snapshot()
                    .and_then(|snapshot| snapshot.recently_found.as_ref())
                    .is_some()
                    && ui.button("View recently found").clicked()
                {
                    action = Some(DatabasePanelAction::ViewRecentlyFound);
                }
                match state {
                    DatabaseState::Ready { .. } => {
                        if ui
                            .add_enabled(!loading, egui::Button::new("Refresh database status"))
                            .clicked()
                        {
                            action = Some(DatabasePanelAction::RefreshStatus);
                        }
                    }
                    DatabaseState::NotCreated { .. }
                    | DatabaseState::Outdated { .. }
                    | DatabaseState::Error { .. } => {
                        if ui
                            .add_enabled(!loading, egui::Button::new("Retry database load"))
                            .clicked()
                        {
                            action = Some(DatabasePanelAction::RetryLoad);
                        }
                    }
                    DatabaseState::Loading { .. } => {}
                }
                if loading {
                    ui.spinner();
                    ui.label(if state.is_scanning() {
                        "Scanning..."
                    } else {
                        "Loading..."
                    });
                }
            });
        });
    action
}

/// Renders the compact "Custom Platform Aliases" section: a collapsible
/// list of persisted aliases (each with a Remove button), plus an
/// alias-text field and a canonical-platform dropdown with an Add Alias
/// button. Purely a view over `aliases` (already loaded off the UI
/// thread as part of the cached database snapshot - see
/// `CachedLibrarySnapshot::platform_aliases`) plus the two caller-owned
/// input fields; never itself opens a database or blocks. `busy` (from
/// `ArchiveFsApp::alias_action`) disables every control here while one
/// alias action is already running, so two cannot overlap - it is
/// deliberately independent of `is_busy()`/mount safety, exactly like
/// the existing per-archive platform assignment controls.
fn show_platform_aliases_panel(
    ui: &mut egui::Ui,
    aliases: &[PlatformAlias],
    new_alias_text: &mut String,
    new_alias_platform_choice: &mut Option<String>,
    busy: bool,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<AliasAction> {
    let mut action = None;
    egui::CollapsingHeader::new("Custom Platform Aliases")
        .id_salt("platform_aliases_panel")
        .default_open(true)
        .show(ui, |ui| {
            ui.label(
                "Map a folder name to a platform (for example \"gc\" -> GameCube). Custom \
                 aliases outrank built-in detection but never a manual archive assignment. \
                 Changes take effect on the next library scan.",
            );
            ui.separator();

            if aliases.is_empty() {
                ui.label("No custom platform aliases defined.");
            } else {
                egui::Grid::new("platform_aliases_grid")
                    .num_columns(3)
                    .show(ui, |ui| {
                        for alias in aliases {
                            ui.label(&alias.alias);
                            ui.label(&alias.platform);
                            if ui.add_enabled(!busy, egui::Button::new("Remove")).clicked() {
                                action = Some(AliasAction::Remove {
                                    alias: alias.alias.clone(),
                                });
                            }
                            ui.end_row();
                        }
                    });
            }

            ui.separator();
            ui.horizontal(|ui| {
                ui.label("Alias:");
                ui.add_enabled_ui(!busy, |ui| {
                    show_text_edit_with_context_menu(ui, new_alias_text, clipboard, |text_edit| {
                        text_edit.desired_width(120.0).hint_text("gc")
                    });
                });
                ui.label("Platform:");
                egui::ComboBox::from_id_salt("platform_alias_choice_combo")
                    .selected_text(
                        new_alias_platform_choice
                            .as_deref()
                            .unwrap_or("Select platform..."),
                    )
                    .show_ui(ui, |ui| {
                        for name in canonical_platform_names() {
                            ui.selectable_value(
                                new_alias_platform_choice,
                                Some(name.to_string()),
                                name,
                            );
                        }
                    });

                let resolved_action =
                    resolved_new_alias_action(new_alias_text, new_alias_platform_choice.as_deref());
                if ui
                    .add_enabled(
                        !busy && resolved_action.is_some(),
                        egui::Button::new("Add Alias"),
                    )
                    .clicked()
                {
                    action = resolved_action;
                }
                if busy {
                    ui.spinner();
                }
            });
        });
    action
}

/// The `AliasAction::Add` the Add Alias button constructs, factored out
/// so it is directly testable (mirrors `resolved_platform_choice`'s
/// existing convention for the per-archive platform editor). `None`
/// exactly when the button itself would be disabled: `alias` trims to
/// empty, or no platform has been chosen from the canonical-platform
/// picker yet.
fn resolved_new_alias_action(alias: &str, platform_choice: Option<&str>) -> Option<AliasAction> {
    let trimmed_alias = alias.trim();
    if trimmed_alias.is_empty() {
        return None;
    }
    let platform = platform_choice?;
    Some(AliasAction::Add {
        alias: trimmed_alias.to_string(),
        platform: platform.to_string(),
    })
}

fn duplicate_visible_entries(
    group: &CatalogueDuplicateGroup,
    include_missing: bool,
) -> Vec<&CatalogueDuplicateArchive> {
    group
        .entries
        .iter()
        .filter(|entry| include_missing || entry.present)
        .collect()
}

fn duplicate_group_matches(
    group: &CatalogueDuplicateGroup,
    filters: &DuplicateReviewFilters,
) -> bool {
    if filters
        .platform
        .as_deref()
        .is_some_and(|platform| platform != group.platform)
    {
        return false;
    }
    let entries = duplicate_visible_entries(group, filters.include_missing);
    if entries.len() < 2 || (filters.more_than_two && entries.len() <= 2) {
        return false;
    }
    let search = filters.search.trim().to_lowercase();
    search.is_empty()
        || group.title.to_lowercase().contains(&search)
        || group.normalized_title.contains(&search)
        || entries.iter().any(|entry| {
            entry
                .path
                .to_string_lossy()
                .to_lowercase()
                .contains(&search)
        })
}

fn visible_duplicate_group_indices(
    report: &CatalogueDuplicateReport,
    filters: &DuplicateReviewFilters,
    sort_field: DuplicateSortField,
    ascending: bool,
) -> Vec<usize> {
    let mut indices = report
        .groups
        .iter()
        .enumerate()
        .filter_map(|(index, group)| duplicate_group_matches(group, filters).then_some(index))
        .collect::<Vec<_>>();
    indices.sort_by(|left, right| {
        let left_group = &report.groups[*left];
        let right_group = &report.groups[*right];
        let left_entries = duplicate_visible_entries(left_group, filters.include_missing);
        let right_entries = duplicate_visible_entries(right_group, filters.include_missing);
        let ordering = match sort_field {
            DuplicateSortField::Title => left_group
                .normalized_title
                .cmp(&right_group.normalized_title),
            DuplicateSortField::Platform => left_group.platform.cmp(&right_group.platform),
            DuplicateSortField::Entries => left_entries.len().cmp(&right_entries.len()),
            DuplicateSortField::KnownSize => {
                visible_known_size(&left_entries).cmp(&visible_known_size(&right_entries))
            }
        }
        .then_with(|| {
            left_group
                .normalized_title
                .cmp(&right_group.normalized_title)
        })
        .then_with(|| left_group.platform.cmp(&right_group.platform));
        if ascending {
            ordering
        } else {
            ordering.reverse()
        }
    });
    indices
}

fn visible_known_size(entries: &[&CatalogueDuplicateArchive]) -> u128 {
    entries
        .iter()
        .filter_map(|entry| entry.size_bytes)
        .map(u128::from)
        .sum()
}

fn prune_duplicate_review_selection(
    selected_group: &mut Option<DuplicateGroupIdentity>,
    selected_archive: &mut Option<PathBuf>,
    report: Option<&CatalogueDuplicateReport>,
) {
    let selected_group_still_exists = selected_group.as_ref().is_some_and(|selected| {
        report.is_some_and(|report| {
            report
                .groups
                .iter()
                .any(|group| DuplicateGroupIdentity::from(group) == *selected)
        })
    });
    if !selected_group_still_exists {
        *selected_group = None;
        *selected_archive = None;
        return;
    }
    let selected_archive_still_exists = selected_archive.as_ref().is_none_or(|path| {
        report.is_some_and(|report| {
            report.groups.iter().any(|group| {
                selected_group.as_ref() == Some(&DuplicateGroupIdentity::from(group))
                    && group.entries.iter().any(|entry| entry.path == *path)
            })
        })
    });
    if !selected_archive_still_exists {
        *selected_archive = None;
    }
}
enum DuplicateReviewAction {
    Close,
    ViewInLibrary(PathBuf),
    Inspect(PathBuf),
}

struct DuplicateReviewViewState<'a> {
    filters: &'a mut DuplicateReviewFilters,
    sort_field: &'a mut DuplicateSortField,
    sort_ascending: &'a mut bool,
    selected_group: &'a mut Option<DuplicateGroupIdentity>,
    selected_archive: &'a mut Option<PathBuf>,
    clipboard: &'a mut dyn ClipboardBackend,
}

/// Reviewed for the Library IA migration: its "Back to Library" button
/// (`DuplicateReviewAction::Close`) is kept rather than removed, even
/// though the unified Library shell's Archives tab is now also one click
/// away via the tab row - the button sits right at the top of this
/// content, above the same internal scroll area the tab row itself is
/// pinned outside of, so it is not meaningfully redundant, and removing
/// a working exit action was judged not worth the small risk for a small
/// convenience gain. Its handler now calls `navigate_to_library_tab`.
fn show_duplicate_review_panel(
    ui: &mut egui::Ui,
    report: &CatalogueDuplicateReport,
    view_state: DuplicateReviewViewState<'_>,
) -> Option<DuplicateReviewAction> {
    let DuplicateReviewViewState {
        filters,
        sort_field,
        sort_ascending,
        selected_group,
        selected_archive,
        clipboard,
    } = view_state;
    let mut action = None;
    widgets::section_header(
        ui,
        "Duplicates",
        Some(
            "Review only — ArchiveFS will not change archive files here. Groups are likely \
             duplicates, not claims that files are byte-identical.",
        ),
    );
    if widgets::action_button(ui, "Back to Library", widgets::ActionStyle::Quiet, true).clicked() {
        action = Some(DuplicateReviewAction::Close);
    }
    ui.add_space(2.0);

    ui.horizontal_wrapped(|ui| {
        ui.label("Search title or exact path:");
        show_text_edit_with_context_menu(ui, &mut filters.search, clipboard, |text_edit| {
            text_edit
                .id_salt("archivefs_duplicate_search")
                .desired_width(260.0)
        });
        ui.checkbox(&mut filters.include_missing, "Include missing entries");
        ui.checkbox(&mut filters.more_than_two, "More than two entries");
    });

    let mut platforms = report
        .groups
        .iter()
        .map(|group| group.platform.as_str())
        .collect::<Vec<_>>();
    platforms.sort_unstable();
    platforms.dedup();
    ui.horizontal(|ui| {
        ui.label("Platform:");
        egui::ComboBox::from_id_salt("duplicate_platform_filter")
            .selected_text(filters.platform.as_deref().unwrap_or("All platforms"))
            .show_ui(ui, |ui| {
                ui.selectable_value(&mut filters.platform, None, "All platforms");
                for platform in platforms {
                    ui.selectable_value(
                        &mut filters.platform,
                        Some(platform.to_string()),
                        platform,
                    );
                }
            });
        ui.label("Sort by:");
        egui::ComboBox::from_id_salt("duplicate_sort")
            .selected_text(sort_field.to_string())
            .show_ui(ui, |ui| {
                for field in [
                    DuplicateSortField::Title,
                    DuplicateSortField::Platform,
                    DuplicateSortField::Entries,
                    DuplicateSortField::KnownSize,
                ] {
                    ui.selectable_value(sort_field, field, field.to_string());
                }
            });
        ui.checkbox(sort_ascending, "Ascending");
    });

    let visible = visible_duplicate_group_indices(report, filters, *sort_field, *sort_ascending);
    let visible_entry_count = visible
        .iter()
        .map(|index| {
            duplicate_visible_entries(&report.groups[*index], filters.include_missing).len()
        })
        .sum::<usize>();
    ui.horizontal_wrapped(|ui| {
        summary_value(ui, "Duplicate groups", visible.len());
        summary_value(ui, "Archive entries involved", visible_entry_count);
        if !filters.include_missing {
            ui.label("Present entries only");
        }
    });
    ui.separator();

    if visible.is_empty() {
        ui.label("No likely duplicate groups match the current review filters.");
        return action;
    }

    ui.strong("Likely duplicate groups");
    egui::ScrollArea::vertical()
        .id_salt("duplicate_group_list")
        .max_height(180.0)
        .show(ui, |ui| {
            for index in &visible {
                let group = &report.groups[*index];
                let identity = DuplicateGroupIdentity::from(group);
                let entry_count = duplicate_visible_entries(group, filters.include_missing).len();
                let selected = selected_group.as_ref() == Some(&identity);
                let label_text = format!(
                    "{} — {} — {} entries",
                    group.title, group.platform, entry_count
                );
                let response = ui
                    .add(egui::Button::selectable(selected, &label_text).truncate())
                    .on_hover_text(&label_text);
                if response.clicked() {
                    *selected_group = Some(identity.clone());
                    *selected_archive = None;
                }
                let group_entries = duplicate_visible_entries(group, filters.include_missing);
                response.context_menu(|ui| {
                    if ui.button("Select duplicate group").clicked() {
                        *selected_group = Some(identity.clone());
                        *selected_archive = None;
                        ui.close();
                    }
                    if ui.button("Copy all paths in this group").clicked() {
                        let text = group_entries
                            .iter()
                            .map(|entry| entry.path.display().to_string())
                            .collect::<Vec<_>>()
                            .join("\n");
                        let _ = clipboard.set_text(text);
                        ui.close();
                    }
                });
            }
        });

    let Some(group) = selected_group.as_ref().and_then(|selected| {
        visible
            .iter()
            .map(|index| &report.groups[*index])
            .find(|group| DuplicateGroupIdentity::from(*group) == *selected)
    }) else {
        ui.label("Select a likely duplicate group to inspect every archive in it.");
        return action;
    };
    let entries = duplicate_visible_entries(group, filters.include_missing);
    if entries.len() < 2 {
        ui.label("The selected group is hidden by the current entry filters.");
        return action;
    }

    ui.separator();
    ui.strong("Likely duplicate group");
    egui::Grid::new("duplicate_group_details")
        .num_columns(2)
        .show(ui, |ui| {
            detail_row(ui, "Title", &group.title);
            detail_row(ui, "Platform", &group.platform);
            detail_row(ui, "Entries", &entries.len().to_string());
            detail_row(ui, "Method", "Filename and platform");
            detail_row(ui, "Reason", &group.reason);
            let known_count = entries
                .iter()
                .filter(|entry| entry.size_bytes.is_some())
                .count();
            detail_row(
                ui,
                "Total known size",
                &format!(
                    "{} ({} of {} entries known)",
                    format_known_size(visible_known_size(&entries)),
                    known_count,
                    entries.len()
                ),
            );
        });

    ui.add_space(4.0);
    for entry in entries {
        let is_selected = selected_archive.as_ref() == Some(&entry.path);
        egui::Frame::group(ui.style()).show(ui, |ui| {
            let entry_path_text = entry.path.display().to_string();
            let response = ui
                .add(egui::Button::selectable(is_selected, &entry_path_text).truncate())
                .on_hover_text(&entry_path_text);
            if response.clicked() {
                *selected_archive = Some(entry.path.clone());
            }
            // Requirement: "No deletion controls. No automatic cleanup." -
            // only navigation, read-only inspection, and clipboard copies
            // are ever offered here.
            response.context_menu(|ui| {
                if ui.button("Show archive in Library").clicked() {
                    action = Some(DuplicateReviewAction::ViewInLibrary(entry.path.clone()));
                    ui.close();
                }
                let inspectable = is_inspectable(&entry.path);
                if ui
                    .add_enabled(inspectable, egui::Button::new("Inspect contents"))
                    .clicked()
                {
                    action = Some(DuplicateReviewAction::Inspect(entry.path.clone()));
                    ui.close();
                }
                if ui.button("Copy archive path").clicked() {
                    let _ = clipboard.set_text(entry_path_text.clone());
                    ui.close();
                }
            });
            let state = if entry.present { "Present" } else { "Missing" };
            let color = if entry.present {
                ui.visuals().text_color()
            } else {
                ui.visuals().warn_fg_color
            };
            ui.colored_label(color, state);
            ui.label(format!("Size: {}", format_duplicate_size(entry.size_bytes)));
            ui.label(format!(
                "Modified time: {}",
                format_modified_time(entry.modified_time_unix_seconds)
            ));
        });
    }

    if let Some(path) = selected_archive.as_ref()
        && let Some(entry) = group.entries.iter().find(|entry| entry.path == *path)
    {
        ui.separator();
        ui.strong("Selected duplicate archive");
        egui::Grid::new("selected_duplicate_archive_details")
            .num_columns(2)
            .show(ui, |ui| {
                detail_row(ui, "Exact archive path", &entry.path.display().to_string());
                detail_row(ui, "Platform", &group.platform);
                detail_row(
                    ui,
                    "State",
                    if entry.present { "Present" } else { "Missing" },
                );
                detail_row(ui, "Size", &format_duplicate_size(entry.size_bytes));
                detail_row(
                    ui,
                    "Modified time",
                    &format_modified_time(entry.modified_time_unix_seconds),
                );
            });
    }
    action
}

fn format_known_size(size_bytes: u128) -> String {
    format_byte_count(size_bytes)
}

fn format_duplicate_size(size_bytes: Option<u64>) -> String {
    size_bytes
        .map(|size| format_byte_count(u128::from(size)))
        .unwrap_or_else(|| "Unknown".to_string())
}

fn format_byte_count(size_bytes: u128) -> String {
    const KIB: u128 = 1024;
    const MIB: u128 = KIB * 1024;
    const GIB: u128 = MIB * 1024;
    const TIB: u128 = GIB * 1024;
    let (unit_size, unit_name) = if size_bytes >= TIB {
        (TIB, "TiB")
    } else if size_bytes >= GIB {
        (GIB, "GiB")
    } else if size_bytes >= MIB {
        (MIB, "MiB")
    } else if size_bytes >= KIB {
        (KIB, "KiB")
    } else {
        return format!("{size_bytes} bytes");
    };
    let whole = size_bytes / unit_size;
    let tenth = (size_bytes % unit_size) * 10 / unit_size;
    format!("{whole}.{tenth} {unit_name} ({size_bytes} bytes)")
}

fn format_modified_time(seconds: Option<i64>) -> String {
    seconds
        .map(format_unix_timestamp_utc)
        .unwrap_or_else(|| "Unknown".to_string())
}

// -----------------------------------------------------------------------
// v0.4.3-alpha: Health and Recovery Dashboard.
// -----------------------------------------------------------------------
fn build_health_issues(
    records: &[ArchiveRecord],
    cached: &CachedLibrarySnapshot,
    lazy_unmount_offers: &HashSet<PathBuf>,
    remount_offers: &HashSet<PathBuf>,
) -> Vec<HealthIssue> {
    let persisted_by_path: HashMap<&Path, &PersistedArchive> = cached
        .archives
        .iter()
        .map(|persisted| (persisted.absolute_path.as_path(), persisted))
        .collect();

    let mut issues = Vec::new();

    for record in records {
        let path = record.mount_plan.archive.path.as_path();
        let persisted = persisted_by_path.get(path).copied();
        // Prefer the persisted effective platform when the database
        // already has an entry for this exact path - the same override
        // `ArchiveRow::with_persisted_platform` applies for display, so
        // this can never disagree with the library table about whether a
        // platform counts as unknown.
        let raw_platform = record
            .metadata
            .platform
            .as_deref()
            .or(record.identity.platform.as_deref());
        let platform = persisted
            .map(|persisted| persisted.platform.as_deref())
            .unwrap_or(raw_platform);
        let recovery_offer = if remount_offers.contains(path) {
            Some(RecoveryOffer::Remount)
        } else if lazy_unmount_offers.contains(path) {
            Some(RecoveryOffer::LazyUnmount)
        } else {
            None
        };
        let modified_time_unix_seconds = record
            .identity
            .modified_time
            .and_then(|time| time.duration_since(UNIX_EPOCH).ok())
            .map(|duration| duration.as_secs() as i64);
        let input = ArchiveHealthInput {
            path,
            platform,
            presence: ArchivePresence::Confirmed,
            mount_state: Some(record.mount_state),
            archive_health: Some(record.health),
            recovery_offer,
            last_seen_at: persisted.map(|persisted| persisted.last_seen_at.as_str()),
            size_bytes: record.identity.size_bytes,
            modified_time_unix_seconds,
        };
        if let Some(issue) = classify_archive_health(&input) {
            issues.push(issue);
        }
    }

    // Archives owned by a source that is itself currently unavailable/
    // permission-denied/scan-failed must never each become their own
    // `HealthIssue` below - that would flood the dashboard with one
    // "cached only"/"awaiting validation" entry per archive merely because
    // the drive is offline. `source_health_issues` (computed by the
    // caller from this same `cached.source_views`) already reports that
    // truthfully as one issue for the whole source; skip these archives
    // here so the two never duplicate the same underlying problem.
    let unavailable_source_ids: HashSet<i64> = cached
        .source_views
        .iter()
        .filter(|view| {
            matches!(
                view.availability,
                SourceAvailability::Unavailable
                    | SourceAvailability::PermissionDenied
                    | SourceAvailability::ScanFailed
            )
        })
        .filter_map(|view| view.id)
        .collect();

    let live_paths: HashSet<&Path> = records
        .iter()
        .map(|record| record.mount_plan.archive.path.as_path())
        .collect();
    for persisted in &cached.archives {
        if live_paths.contains(persisted.absolute_path.as_path()) {
            continue;
        }
        if unavailable_source_ids.contains(&persisted.source_folder_id) {
            continue;
        }
        let presence = if persisted.last_verified_missing_at.is_some() {
            ArchivePresence::Missing
        } else if persisted.absolute_path.exists() {
            ArchivePresence::AwaitingValidation
        } else {
            ArchivePresence::Unreachable
        };
        let input = ArchiveHealthInput {
            path: &persisted.absolute_path,
            platform: persisted.platform.as_deref(),
            presence,
            mount_state: None,
            archive_health: None,
            recovery_offer: None,
            last_seen_at: Some(&persisted.last_seen_at),
            size_bytes: persisted.size_bytes,
            modified_time_unix_seconds: persisted.modified_time_unix_seconds,
        };
        if let Some(issue) = classify_archive_health(&input) {
            issues.push(issue);
        }
    }

    issues.sort_by(|left, right| {
        left.category
            .severity_rank()
            .cmp(&right.category.severity_rank())
            .then_with(|| left.path.cmp(&right.path))
    });
    issues
}

/// A human-readable state label - never `MountState`'s raw `Display`
/// alone for a cache-only row (which has no `MountState` at all), and
/// never a raw database source string. Reuses the exact same "Cached:
/// ..." wording `RowOrigin::label()` already established for the library
/// table, so the two screens never disagree about vocabulary.
fn health_issue_state_text(issue: &HealthIssue) -> String {
    if let Some(state) = issue.mount_state {
        return state.to_string();
    }
    match issue.category {
        HealthCategory::Missing => "Cached: missing".to_string(),
        HealthCategory::AwaitingValidation => "Cached: awaiting validation".to_string(),
        HealthCategory::CachedOnly => "Cached: source unavailable".to_string(),
        _ => (if issue.present { "Present" } else { "Missing" }).to_string(),
    }
}

fn health_issue_matches(issue: &HealthIssue, filters: &HealthDashboardFilters) -> bool {
    if !filters.category.matches(issue.category) {
        return false;
    }
    if let Some(platform) = &filters.platform {
        let issue_platform = issue.platform.as_deref().unwrap_or("Unknown");
        if issue_platform != platform {
            return false;
        }
    }
    let search = filters.search.trim().to_lowercase();
    if search.is_empty() {
        return true;
    }
    let path_text = issue.path.display().to_string().to_lowercase();
    let reason_text = issue.reason.to_lowercase();
    path_text.contains(&search) || reason_text.contains(&search)
}
fn visible_health_issue_indices(
    issues: &[HealthIssue],
    filters: &HealthDashboardFilters,
    sort_field: HealthSortField,
    ascending: bool,
) -> Vec<usize> {
    let mut indices: Vec<usize> = issues
        .iter()
        .enumerate()
        .filter_map(|(index, issue)| health_issue_matches(issue, filters).then_some(index))
        .collect();
    indices.sort_by(|&left, &right| {
        let left_issue = &issues[left];
        let right_issue = &issues[right];
        let ordering = match sort_field {
            HealthSortField::Severity => left_issue
                .category
                .severity_rank()
                .cmp(&right_issue.category.severity_rank()),
            HealthSortField::Path => left_issue.path.cmp(&right_issue.path),
            HealthSortField::Platform => left_issue
                .platform
                .as_deref()
                .unwrap_or("Unknown")
                .cmp(right_issue.platform.as_deref().unwrap_or("Unknown")),
            HealthSortField::State => {
                health_issue_state_text(left_issue).cmp(&health_issue_state_text(right_issue))
            }
            HealthSortField::Reason => left_issue.reason.cmp(&right_issue.reason),
        }
        .then_with(|| left_issue.path.cmp(&right_issue.path));
        if ascending {
            ordering
        } else {
            ordering.reverse()
        }
    });
    indices
}
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct HealthOverview {
    healthy: usize,
    mounted: usize,
    pending: usize,
    missing: usize,
    awaiting_validation: usize,
    cached_only: usize,
    retryable_failures: usize,
    terminal_failures: usize,
    unknown_platform: usize,
    recovery_available: usize,
    diagnostics_errors: usize,
}

fn health_overview(
    issues: &[HealthIssue],
    live_archive_count: usize,
    mounted_count: usize,
    pending_count: usize,
    diagnostics_errors: usize,
) -> HealthOverview {
    let count = |category: HealthCategory| {
        issues
            .iter()
            .filter(|issue| issue.category == category)
            .count()
    };
    let missing = count(HealthCategory::Missing);
    let awaiting_validation = count(HealthCategory::AwaitingValidation);
    let cached_only = count(HealthCategory::CachedOnly);
    let retryable_failures = count(HealthCategory::RetryableFailure);
    let terminal_failures = count(HealthCategory::TerminalFailure);
    let unknown_platform = count(HealthCategory::UnknownPlatform);
    let recovery_available = count(HealthCategory::RecoveryAvailable);
    // Every `UnknownPlatform`/failure/recovery issue is a live archive -
    // `classify_archive_health`'s priority order always classifies a
    // cached-only row as Missing/AwaitingValidation/CachedOnly first, so
    // it can never also count as UnknownPlatform here. This subtraction
    // can therefore never double count or misclassify a cached-only row.
    let unhealthy_live =
        retryable_failures + terminal_failures + recovery_available + unknown_platform;
    let healthy = live_archive_count.saturating_sub(unhealthy_live);
    HealthOverview {
        healthy,
        mounted: mounted_count,
        pending: pending_count,
        missing,
        awaiting_validation,
        cached_only,
        retryable_failures,
        terminal_failures,
        unknown_platform,
        recovery_available,
        diagnostics_errors,
    }
}
enum HealthDashboardAction {
    BackToLibrary,
    Archive(OperationRequest),
    RefreshDiagnostics,
    OpenMissingReview,
    OpenDuplicateReview,
    ViewInLibrary(PathBuf),
    Inspect(PathBuf),
    FilterByCategory(HealthIssueFilter),
}
fn health_issue_filter_for_category(category: HealthCategory) -> HealthIssueFilter {
    match category {
        HealthCategory::TerminalFailure => HealthIssueFilter::Terminal,
        HealthCategory::RetryableFailure => HealthIssueFilter::Retryable,
        HealthCategory::RecoveryAvailable => HealthIssueFilter::RecoveryAvailable,
        HealthCategory::Missing => HealthIssueFilter::Missing,
        HealthCategory::AwaitingValidation => HealthIssueFilter::AwaitingValidation,
        HealthCategory::CachedOnly => HealthIssueFilter::CachedOnly,
        HealthCategory::UnknownPlatform => HealthIssueFilter::UnknownPlatform,
    }
}

struct HealthDashboardViewState<'a> {
    filters: &'a mut HealthDashboardFilters,
    sort_field: &'a mut HealthSortField,
    sort_ascending: &'a mut bool,
    selected_issue: &'a mut Option<PathBuf>,
    busy: bool,
    clipboard: &'a mut dyn ClipboardBackend,
}

/// Reviewed for the Library IA migration: its "Back to Library" button
/// (`HealthDashboardAction::BackToLibrary`) is kept for the same reason
/// `show_duplicate_review_panel`'s is - not meaningfully redundant with
/// the tab row, and removing a working exit action wasn't worth it for a
/// small convenience gain. Its handler now calls
/// `navigate_to_library_tab`.
fn show_health_dashboard_panel(
    ui: &mut egui::Ui,
    live_data: Option<&LoadedData>,
    cached: &CachedLibrarySnapshot,
    issues: &[HealthIssue],
    view_state: HealthDashboardViewState<'_>,
) -> Option<HealthDashboardAction> {
    let HealthDashboardViewState {
        filters,
        sort_field,
        sort_ascending,
        selected_issue,
        busy,
        clipboard,
    } = view_state;

    let mut action = None;
    widgets::section_header(
        ui,
        "Health",
        Some(
            "Read-only overview of archive and catalogue health. Filtering, sorting, and \
             selection here are independent of the ordinary library view and Duplicate Review.",
        ),
    );
    if widgets::action_button(ui, "Back to Library", widgets::ActionStyle::Quiet, true).clicked() {
        action = Some(HealthDashboardAction::BackToLibrary);
    }
    ui.add_space(2.0);

    let Some(data) = live_data else {
        ui.separator();
        ui.label("Health information is unavailable until the library is scanned.");
        return action;
    };

    let diagnostics_errors = data
        .doctor
        .checks
        .iter()
        .filter(|check| check.status == DoctorStatus::Fail)
        .count();
    let overview = health_overview(
        issues,
        data.records.len(),
        data.stats.mounted_count,
        data.stats.pending_count,
        diagnostics_errors,
    );

    let metrics = [
        SummaryMetric {
            label: "Healthy / ready",
            value: overview.healthy,
            tone: widgets::StatusTone::Success,
        },
        SummaryMetric {
            label: "Mounted",
            value: overview.mounted,
            tone: widgets::StatusTone::Active,
        },
        SummaryMetric {
            label: "Pending",
            value: overview.pending,
            tone: widgets::StatusTone::Pending,
        },
        SummaryMetric {
            label: "Missing",
            value: overview.missing,
            tone: widgets::StatusTone::Blocked,
        },
        SummaryMetric {
            label: "Retryable failures",
            value: overview.retryable_failures,
            tone: widgets::StatusTone::Warning,
        },
        SummaryMetric {
            label: "Terminal failures",
            value: overview.terminal_failures,
            tone: widgets::StatusTone::Blocked,
        },
        SummaryMetric {
            label: "Recovery available",
            value: overview.recovery_available,
            tone: widgets::StatusTone::Info,
        },
        SummaryMetric {
            label: "Awaiting validation",
            value: overview.awaiting_validation,
            tone: widgets::StatusTone::Warning,
        },
        SummaryMetric {
            label: "Cached-only",
            value: overview.cached_only,
            tone: widgets::StatusTone::Pending,
        },
        SummaryMetric {
            label: "Unknown platform",
            value: overview.unknown_platform,
            tone: widgets::StatusTone::Info,
        },
        SummaryMetric {
            label: "Diagnostics errors",
            value: overview.diagnostics_errors,
            tone: widgets::StatusTone::Blocked,
        },
    ];
    show_health_metric_cards(ui, &metrics);
    ui.label(
        "Healthy/Mounted/Pending/Retryable/Terminal/Recovery available/Unknown platform: current \
         live snapshot. Missing/Awaiting validation/Cached-only: persisted catalogue. \
         Diagnostics errors: last Doctor check.",
    );
    ui.add_space(4.0);

    ui.horizontal_wrapped(|ui| {
        if ui.button("Refresh diagnostics").clicked() {
            action = Some(HealthDashboardAction::RefreshDiagnostics);
        }
        if ui
            .add_enabled(
                overview.missing > 0,
                egui::Button::new("Open Missing Review"),
            )
            .clicked()
        {
            action = Some(HealthDashboardAction::OpenMissingReview);
        }
        if ui.button("Open Duplicate Review").clicked() {
            action = Some(HealthDashboardAction::OpenDuplicateReview);
        }
    });

    if diagnostics_errors > 0 {
        ui.separator();
        ui.strong("Diagnostics issues");
        for check in data
            .doctor
            .checks
            .iter()
            .filter(|check| check.status == DoctorStatus::Fail)
        {
            ui.colored_label(
                ui.visuals().error_fg_color,
                format!("{}: {}", check.name, check.detail),
            );
        }
    }
    let source_issues = source_health_issues(&cached.source_views);
    if !source_issues.is_empty() {
        ui.separator();
        ui.strong("Source issues");
        for issue in &source_issues {
            ui.colored_label(
                ui.visuals().error_fg_color,
                format!("{}: {}", issue.path.display(), issue.reason),
            );
            ui.label(format!(
                "  {} catalogue entries preserved.",
                issue.archives_preserved
            ));
        }
    }
    ui.separator();

    ui.horizontal_wrapped(|ui| {
        ui.label("Search path or reason:");
        show_text_edit_with_context_menu(ui, &mut filters.search, clipboard, |text_edit| {
            text_edit
                .id_salt("archivefs_health_search")
                .desired_width(260.0)
        });
        ui.label("Filter:");
        egui::ComboBox::from_id_salt("health_category_filter")
            .selected_text(filters.category.label())
            .show_ui(ui, |ui| {
                for option in HealthIssueFilter::ALL {
                    ui.selectable_value(&mut filters.category, option, option.label());
                }
            });
    });

    let mut platforms = issues
        .iter()
        .map(|issue| issue.platform.as_deref().unwrap_or("Unknown"))
        .collect::<Vec<_>>();
    platforms.sort_unstable();
    platforms.dedup();
    ui.horizontal(|ui| {
        ui.label("Platform:");
        egui::ComboBox::from_id_salt("health_platform_filter")
            .selected_text(filters.platform.as_deref().unwrap_or("All platforms"))
            .show_ui(ui, |ui| {
                ui.selectable_value(&mut filters.platform, None, "All platforms");
                for platform in platforms {
                    ui.selectable_value(
                        &mut filters.platform,
                        Some(platform.to_string()),
                        platform,
                    );
                }
            });
        ui.label("Sort by:");
        egui::ComboBox::from_id_salt("health_sort")
            .selected_text(sort_field.to_string())
            .show_ui(ui, |ui| {
                for field in [
                    HealthSortField::Severity,
                    HealthSortField::Path,
                    HealthSortField::Platform,
                    HealthSortField::State,
                    HealthSortField::Reason,
                ] {
                    ui.selectable_value(sort_field, field, field.to_string());
                }
            });
        ui.checkbox(sort_ascending, "Ascending");
    });

    let visible = visible_health_issue_indices(issues, filters, *sort_field, *sort_ascending);
    ui.horizontal_wrapped(|ui| {
        summary_value(ui, "Issues shown", visible.len());
        summary_value(ui, "Total issues", issues.len());
    });
    ui.separator();

    if issues.is_empty() {
        ui.label("No archive health issues were found.");
        return action;
    }
    if visible.is_empty() {
        ui.label("No issues match the current health filters.");
        return action;
    }

    ui.strong("Health issues");
    egui::ScrollArea::vertical()
        .id_salt("health_issue_list")
        .max_height(220.0)
        .show(ui, |ui| {
            for &index in &visible {
                let issue = &issues[index];
                let selected = selected_issue.as_ref() == Some(&issue.path);
                let label_text = format!(
                    "{} — {} — {} — {}",
                    issue.path.display(),
                    issue.platform.as_deref().unwrap_or("Unknown"),
                    issue.category.label(),
                    issue.reason
                );
                // Path + platform + category + reason combined can easily
                // exceed the list's width - `.truncate()` keeps the row
                // itself from stretching the page, and the hover tooltip
                // (this list previously had none at all) always carries
                // every field in full.
                let response = ui
                    .add(egui::Button::selectable(selected, &label_text).truncate())
                    .on_hover_text(&label_text);
                if response.clicked() {
                    *selected_issue = Some(issue.path.clone());
                }
                // Requirement: "Do not invent retry actions for issues
                // that have no safe retry" - reuses `issue.recovery_action`
                // exactly as computed by `build_health_issues`/rendered by
                // the "Selected health issue" panel below, never a second
                // guess at what is safe to retry.
                response.context_menu(|ui| {
                    if ui.button("Show archive in Library").clicked() {
                        action = Some(HealthDashboardAction::ViewInLibrary(issue.path.clone()));
                        ui.close();
                    }
                    let inspectable = is_inspectable(&issue.path);
                    if ui
                        .add_enabled(inspectable, egui::Button::new("Inspect contents"))
                        .clicked()
                    {
                        action = Some(HealthDashboardAction::Inspect(issue.path.clone()));
                        ui.close();
                    }
                    if ui.button("Copy archive path").clicked() {
                        let _ = clipboard.set_text(issue.path.display().to_string());
                        ui.close();
                    }
                    if ui.button("Copy issue reason").clicked() {
                        let _ = clipboard.set_text(issue.reason.clone());
                        ui.close();
                    }
                    match issue.recovery_action {
                        Some(RecoveryAction::RetryMount) => {
                            if ui
                                .add_enabled(!busy, egui::Button::new("Retry mount"))
                                .clicked()
                            {
                                action = Some(HealthDashboardAction::Archive(OperationRequest {
                                    action: ArchiveAction::Mount,
                                    archive_path: issue.path.clone(),
                                    cleanup_after_unmount: false,
                                }));
                                ui.close();
                            }
                        }
                        Some(RecoveryAction::Remount) => {
                            if ui
                                .add_enabled(!busy, egui::Button::new("Remount"))
                                .clicked()
                            {
                                action = Some(HealthDashboardAction::Archive(OperationRequest {
                                    action: ArchiveAction::Remount,
                                    archive_path: issue.path.clone(),
                                    cleanup_after_unmount: false,
                                }));
                                ui.close();
                            }
                        }
                        Some(RecoveryAction::LazyUnmount) | None => {}
                    }
                    ui.separator();
                    if ui.button("Filter by this issue type").clicked() {
                        action = Some(HealthDashboardAction::FilterByCategory(
                            health_issue_filter_for_category(issue.category),
                        ));
                        ui.close();
                    }
                });
            }
        });

    let Some(issue) = selected_issue.as_ref().and_then(|selected| {
        visible
            .iter()
            .map(|&index| &issues[index])
            .find(|issue| issue.path == *selected)
    }) else {
        ui.label("Select a health issue to view details.");
        return action;
    };

    ui.separator();
    ui.strong("Selected health issue");
    let persisted = cached
        .archives
        .iter()
        .find(|persisted| persisted.absolute_path == issue.path);
    egui::Grid::new("selected_health_issue_details")
        .num_columns(2)
        .show(ui, |ui| {
            detail_row(ui, "Archive path", &issue.path.display().to_string());
            detail_row(
                ui,
                "Platform",
                issue.platform.as_deref().unwrap_or("Unknown"),
            );
            if let Some(persisted) = persisted
                && let Some(details) = cached.platform_details.get(&persisted.id)
            {
                for (label, value) in platform_provenance_lines(details) {
                    detail_row(ui, label, &value);
                }
            }
            detail_row(ui, "State", &health_issue_state_text(issue));
            detail_row(ui, "Present", if issue.present { "Yes" } else { "No" });
            detail_row(ui, "Health classification", issue.category.label());
            detail_row(ui, "Reason", &issue.reason);
            detail_row(ui, "Retryable", if issue.retryable { "Yes" } else { "No" });
            detail_row(
                ui,
                "Recovery available",
                if issue.recovery_available() {
                    "Yes"
                } else {
                    "No"
                },
            );
            detail_row(
                ui,
                "Last seen",
                issue.last_seen_at.as_deref().unwrap_or("Unknown"),
            );
            detail_row(ui, "Size", &format_duplicate_size(issue.size_bytes));
            detail_row(
                ui,
                "Modified time",
                &format_modified_time(issue.modified_time_unix_seconds),
            );
        });

    ui.add_space(4.0);
    ui.horizontal(|ui| {
        match issue.recovery_action {
            Some(RecoveryAction::RetryMount) => {
                if ui
                    .add_enabled(!busy, egui::Button::new("Retry mount"))
                    .on_hover_text("Retries mounting this archive, exactly like the Library's own Mount button.")
                    .clicked()
                {
                    action = Some(HealthDashboardAction::Archive(OperationRequest {
                        action: ArchiveAction::Mount,
                        archive_path: issue.path.clone(),
                        cleanup_after_unmount: false,
                    }));
                }
            }
            Some(RecoveryAction::Remount) => {
                if ui
                    .add_enabled(!busy, egui::Button::new("Remount"))
                    .on_hover_text("Remounts this archive, exactly like the Library's own Remount button.")
                    .clicked()
                {
                    action = Some(HealthDashboardAction::Archive(OperationRequest {
                        action: ArchiveAction::Remount,
                        archive_path: issue.path.clone(),
                        cleanup_after_unmount: false,
                    }));
                }
            }
            Some(RecoveryAction::LazyUnmount) | None => {}
        }
        if ui
            .button("View in Library")
            .on_hover_text(
                "Selects this archive in the Library view, where its full details and \
                 actions (including confirmation-guarded ones) are already available.",
            )
            .clicked()
        {
            action = Some(HealthDashboardAction::ViewInLibrary(issue.path.clone()));
        }
    });

    action
}

struct LoadedViewState<'a> {
    filter: &'a mut String,
    filtered_rows: &'a mut Option<Vec<usize>>,
    selected_archive: &'a mut Option<PathBuf>,
    operation: Option<&'a RunningOperation>,
    busy: bool,
    /// Why archive actions (Mount/Unmount/Lazy Unmount/Remount) are
    /// blocked for the selected live archive, if they are - see
    /// `archive_action_block_reason`, the single source of truth this is
    /// always derived from. `None` whenever actions are available.
    block_reason: Option<&'static str>,
    /// The full boolean-by-boolean breakdown behind `block_reason` - see
    /// `action_readiness_debug_lines`. Rendered in an always-present,
    /// collapsed-by-default "Debug: action readiness" section.
    action_readiness_debug_lines: &'a [String],
    feedback: Option<&'a ActionFeedback>,
    confirm_unmount: &'a mut Option<PathBuf>,
    confirm_lazy_unmount: &'a mut Option<PathBuf>,
    confirm_lazy_unmount_final: &'a mut Option<PathBuf>,
    confirm_mount_all: &'a mut Option<MountAllConfirmation>,
    focus_mount_all_cancel: &'a mut bool,
    confirm_unmount_all: &'a mut Option<UnmountAllConfirmation>,
    focus_unmount_all_cancel: &'a mut bool,
    confirm_unmount_selected: &'a mut Option<UnmountSelectedConfirmation>,
    focus_unmount_selected_cancel: &'a mut bool,
    focus_lazy_cancel: &'a mut bool,
    focus_final_lazy_cancel: &'a mut bool,
    lazy_unmount_offers: &'a HashSet<PathBuf>,
    remount_offers: &'a HashSet<PathBuf>,
    cleanup_after_unmount: &'a mut bool,
    mount_all_result: Option<&'a MountAllResult>,
    unmount_all_result: Option<&'a UnmountAllResult>,
    history: &'a mut OperationHistory,
    cached: Option<&'a CachedLibrarySnapshot>,
    library_filters: &'a mut LibraryRowFilters,
    platform_choice: &'a mut Option<String>,
    platform_custom_text: &'a mut String,
    platform_busy: bool,
    /// Shared RetroArch profile discovery state. Navigation itself is
    /// gated only by exact archive identity; the destination page uses
    /// this state to present scan, eligible, and blocked profile states.
    retroarch_profiles: &'a RetroArchProfilesState,
    selected_archives: &'a mut HashSet<PathBuf>,
    bulk_platform_choice: &'a mut Option<String>,
    bulk_platform_busy: bool,
    missing_removal_available: bool,
    missing_removal_busy: bool,
    confirm_remove_missing: &'a mut Option<Vec<PathBuf>>,
    sort_field: &'a mut Option<SortField>,
    sort_ascending: &'a mut bool,
    library_scroll_offset: &'a mut f32,
    clipboard: &'a mut dyn ClipboardBackend,
    /// A one-shot signal from the Library menu's "Select all visible" item;
    /// see `ArchiveFsApp::select_all_visible_requested`'s doc comment.
    /// Consumed and cleared the same frame it is seen.
    select_all_visible_requested: &'a mut bool,
    /// The Library page's Source filter - see
    /// `ArchiveFsApp::library_source_filter`'s doc comment for what each
    /// of the three states means.
    library_source_filter: &'a mut Option<Option<PathBuf>>,
    /// The Library table's resizable Archive path / Mount path column
    /// widths - see `LibraryColumnWidths`.
    library_column_widths: &'a mut LibraryColumnWidths,
    library_views_configured: bool,
    library_view_last_plan: Option<&'a (LibraryViewConfig, LibraryViewPlan)>,
    recent_scan: Option<&'a RecentScanAdditions>,
    recent_view: bool,
}

const REMOVE_MISSING_CANCEL_LABEL: &str = "Cancel";
const REMOVE_MISSING_CONFIRM_LABEL: &str = "Remove Missing Entries";

fn set_missing_review_mode(filters: &mut LibraryRowFilters, enabled: bool) {
    filters.missing = enabled;
    if enabled {
        filters.present = false;
        filters.awaiting_validation = false;
    }
}

fn selected_missing_paths(
    cached: Option<&CachedLibrarySnapshot>,
    selected_archives: &HashSet<PathBuf>,
) -> Result<Vec<PathBuf>, String> {
    if selected_archives.is_empty() {
        return Err("Select one or more missing catalogue entries first.".to_string());
    }
    let cached = cached.ok_or_else(|| "The library database is unavailable.".to_string())?;
    let mut paths: Vec<PathBuf> = selected_archives.iter().cloned().collect();
    paths.sort();
    for path in &paths {
        let archive = cached
            .archives
            .iter()
            .find(|archive| archive.absolute_path == *path)
            .ok_or_else(|| {
                format!(
                    "{} is not an exact stored catalogue path. Nothing was removed.",
                    path.display()
                )
            })?;
        if archive.last_verified_missing_at.is_none() {
            return Err(format!(
                "{} is currently present. Only missing catalogue entries can be removed; nothing was removed.",
                path.display()
            ));
        }
    }
    Ok(paths)
}

fn missing_removal_confirmation_text(count: usize) -> String {
    format!(
        "Remove {count} missing entr{} from the ArchiveFS catalogue?\n\n\
         This removes only ArchiveFS database records.\n\
         It will not delete archive files or mounted contents.\n\
         Entries will return if the archives are found in a later scan.",
        if count == 1 { "y" } else { "ies" }
    )
}

fn show_loaded_data(
    ui: &mut egui::Ui,
    data: &LoadedData,
    view_state: LoadedViewState<'_>,
) -> Option<AppOperationRequest> {
    let LoadedViewState {
        filter,
        filtered_rows,
        selected_archive,
        operation,
        busy,
        block_reason,
        action_readiness_debug_lines,
        feedback,
        confirm_unmount,
        confirm_lazy_unmount,
        confirm_lazy_unmount_final,
        confirm_mount_all,
        focus_mount_all_cancel,
        confirm_unmount_all,
        focus_unmount_all_cancel,
        confirm_unmount_selected,
        focus_unmount_selected_cancel,
        focus_lazy_cancel,
        focus_final_lazy_cancel,
        lazy_unmount_offers,
        remount_offers,
        cleanup_after_unmount,
        mount_all_result,
        unmount_all_result,
        cached,
        library_filters,
        history,
        platform_choice,
        platform_custom_text,
        platform_busy,
        retroarch_profiles,
        selected_archives,
        bulk_platform_choice,
        bulk_platform_busy,
        missing_removal_available,
        missing_removal_busy,
        confirm_remove_missing,
        sort_field,
        sort_ascending,
        library_scroll_offset,
        clipboard,
        select_all_visible_requested,
        library_source_filter,
        library_column_widths,
        library_views_configured,
        library_view_last_plan,
        recent_scan,
        recent_view,
    } = view_state;
    let mut requested_action = None;
    let pending_count = data.stats.pending_count;
    let mounted_count = data.stats.mounted_count;
    if recent_view {
        widgets::page_header(
            ui,
            "Recently Found",
            "Persistent additions from the most recent completed scan.",
        );
    }
    if let Some(recent) = recent_scan {
        widgets::card(ui, |ui| {
            ui.horizontal_wrapped(|ui| {
                ui.strong(format!("Scan {}", recent.scan.scan_run_id));
                ui.label(format!("Added {}", recent.scan.archives_added));
                ui.label(format!("Updated {}", recent.scan.archives_updated));
                ui.label(format!(
                    "Skipped {}",
                    recent.scan.skipped_unsupported_extension
                        + recent.scan.skipped_ambiguous_platform
                ));
                ui.label(format!("Errors {}", recent.scan.errors_count));
            });
            if recent.truncated {
                ui.colored_label(
                    ui.visuals().warn_fg_color,
                    "Recently Found reached its 10,000-entry display bound.",
                );
            }
        });
    }
    // Merged rows are rebuilt fresh every frame (cheap for realistic
    // library sizes, and always exactly consistent with the current
    // self.state/self.database_state - see build_display_rows). Only the
    // *cached* filtered_rows index list is invalidated on the discrete
    // events that actually change this merge (poll_load, poll_database_load),
    // not every frame - see ArchiveFsApp::poll_load/poll_database_load.
    // Hoisted above every other use (including the "Selected archive"
    // panel, which renders higher up the page than the library table
    // itself) so the Source filter/owning-source display and the table
    // below always agree on exactly one merged row list.
    let merged_rows = build_display_rows(&data.records, &data.rows, cached);
    if !recent_view {
        // No `widgets::page_header`/heading here: the only production
        // caller left with `recent_view == false` is the unified Library
        // shell's Archives tab (see `show_library_shell_header`), which
        // already renders the page's one "Library" heading above the tab
        // row - a second "Library" heading here would just repeat it.
        // The archive-table-specific description that used to accompany
        // that heading is kept as a plain label, since it says something
        // the shell's own (more general, four-tab) description doesn't.
        ui.label(
            egui::RichText::new(
                "Search the archive catalogue, review metadata, and use context menus for focused actions.",
            )
            .color(theme::muted(ui)),
        );
        ui.add_space(theme::SECTION_GAP);
    }
    // A resizable top panel (egui's own built-in support - session
    // persistence, drag-handle hover cursor, and min/max clamping all come
    // for free from `ctx.memory`, keyed by this panel id - see
    // `SUMMARY_PANEL_MIN_HEIGHT`'s doc comment) so the summary stays
    // compact by default (`SUMMARY_PANEL_DEFAULT_HEIGHT` fits its ordinary
    // one-line content) while remaining expandable to read a longer
    // feedback/"More information" message without it being clipped.
    egui::TopBottomPanel::top("library_summary_panel")
        .resizable(true)
        .default_height(SUMMARY_PANEL_DEFAULT_HEIGHT)
        .height_range(SUMMARY_PANEL_MIN_HEIGHT..=SUMMARY_PANEL_MAX_HEIGHT)
        .show_inside(ui, |ui| {
            egui::ScrollArea::vertical()
                .id_salt("library_summary_scroll")
                .auto_shrink([false, false])
                .show(ui, |ui| {
                    ui.horizontal_wrapped(|ui| {
                        summary_value(ui, "Total archives", data.stats.total_archives);
                        summary_value(ui, "Mounted", data.stats.mounted_count);
                        summary_value(ui, "Pending", data.stats.pending_count);
                        if widgets::action_button(
                            ui,
                            "Mount all",
                            widgets::ActionStyle::Primary,
                            mount_all_available(pending_count, busy),
                        )
                        .clicked()
                        {
                            *confirm_mount_all = Some(MountAllConfirmation);
                            *focus_mount_all_cancel = true;
                            history.record(HistoryEntry::new(
                                ActivityAction::MountAll,
                                None,
                                ActivityOutcome::Offered,
                                format!(
                                    "Mount All offered for {} pending archives.",
                                    pending_count
                                ),
                            ));
                        }
                        if widgets::action_button(
                            ui,
                            "Unmount all",
                            widgets::ActionStyle::Destructive,
                            mounted_count > 0 && !busy,
                        )
                        .clicked()
                        {
                            *confirm_unmount_all = Some(UnmountAllConfirmation);
                            *focus_unmount_all_cancel = true;
                            history.record(HistoryEntry::new(
                                ActivityAction::UnmountAll,
                                None,
                                ActivityOutcome::Offered,
                                format!(
                                    "Unmount All offered for {mounted_count} mounted archives."
                                ),
                            ));
                        }
                        ui.separator();
                        let (readiness, tone) = if data.doctor.is_ready() {
                            ("Doctor ready", widgets::StatusTone::Success)
                        } else {
                            ("Doctor needs attention", widgets::StatusTone::Warning)
                        };
                        widgets::status_badge(ui, readiness, tone);
                    });

                    if let Some(result) = mount_all_result {
                        show_mount_all_result(ui, result);
                    }
                    if let Some(result) = unmount_all_result {
                        show_unmount_all_result(ui, result);
                    }

                    ui.separator();
                    if let Some(feedback) = feedback {
                        let color = if feedback.succeeded {
                            egui::Color32::from_rgb(70, 170, 90)
                        } else {
                            ui.visuals().error_fg_color
                        };
                        ui.colored_label(color, &feedback.message);
                        if let Some(warning) = &feedback.warning {
                            ui.colored_label(egui::Color32::from_rgb(210, 140, 40), warning);
                        }
                        if let Some(more_information) = &feedback.more_information {
                            widgets::technical_details(
                                ui,
                                (
                                    "action_feedback_more_information",
                                    more_information.as_str(),
                                ),
                                |ui| {
                                    ui.label(more_information);
                                },
                            );
                        }
                        if let Some(cleanup) = &feedback.cleanup {
                            let color = if cleanup.succeeded {
                                egui::Color32::from_rgb(70, 170, 90)
                            } else {
                                ui.visuals().error_fg_color
                            };
                            ui.colored_label(color, &cleanup.message);
                        }
                    }
                });
        });
    if confirm_mount_all.is_some() {
        let actions_available = !busy;
        egui::Window::new("Mount All pending archives?")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label(format!(
                    "{} pending archives will be mounted under {}.",
                    pending_count,
                    data.mount_root.display()
                ));
                ui.label(
                    "Archives are mounted one at a time. Large libraries may take several minutes.",
                );
                ui.label("A failure will be recorded, and later archives will still be attempted.");
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    let cancel = ui.add_enabled(
                        actions_available,
                        egui::Button::new("Cancel").fill(ui.visuals().selection.bg_fill),
                    );
                    if *focus_mount_all_cancel {
                        cancel.request_focus();
                        *focus_mount_all_cancel = false;
                    }
                    if cancel.clicked() {
                        history.record(HistoryEntry::new(
                            ActivityAction::MountAll,
                            None,
                            ActivityOutcome::Cancelled,
                            "Mount All cancelled before starting.",
                        ));
                        *confirm_mount_all = None;
                    }
                    if ui
                        .add_enabled(
                            mount_all_available(pending_count, busy),
                            egui::Button::new("Mount All"),
                        )
                        .clicked()
                    {
                        requested_action = Some(AppOperationRequest::MountAll(
                            pending_mount_items(&data.records),
                        ));
                        *confirm_mount_all = None;
                    }
                });
            });
    }

    if confirm_unmount_all.is_some() {
        let actions_available = !busy;
        egui::Window::new("Unmount All mounted archives?")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label(format!(
                    "{mounted_count} mounted archives under {} will be unmounted one at a time.",
                    data.mount_root.display()
                ));
                ui.label("Close applications using these mounts before continuing. Files that are still open may prevent normal unmounting.");
                ui.label("Close emulators, file managers, terminals, media players, and other applications using mounted files.");
                ui.label("A failure will be recorded, and later archives will still be attempted.");
                ui.label(format!(
                    "Cleanup after each successful unmount: {}.",
                    if *cleanup_after_unmount { "enabled" } else { "disabled" }
                ));
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    let cancel = ui.add_enabled(
                        actions_available,
                        egui::Button::new("Cancel").fill(ui.visuals().selection.bg_fill),
                    );
                    if *focus_unmount_all_cancel {
                        cancel.request_focus();
                        *focus_unmount_all_cancel = false;
                    }
                    if cancel.clicked() {
                        history.record(HistoryEntry::new(
                            ActivityAction::UnmountAll,
                            None,
                            ActivityOutcome::Cancelled,
                            "Unmount All cancelled before starting.",
                        ));
                        *confirm_unmount_all = None;
                    }
                    if ui
                        .add_enabled(mounted_count > 0 && !busy, egui::Button::new("Unmount All"))
                        .clicked()
                    {
                        requested_action = Some(AppOperationRequest::UnmountAll {
                            items: pending_unmount_items(&data.records),
                            cleanup_after_unmount: *cleanup_after_unmount,
                        });
                        *confirm_unmount_all = None;
                    }
                });
            });
    }

    if confirm_unmount_selected.is_some() {
        let mounted_selected = mounted_selected_unmount_items(&data.records, selected_archives);
        let mounted_selected_count = mounted_selected.len();
        let selected_count = selected_archives.len();
        let actions_available = !busy;
        egui::Window::new("Unmount selected mounted archives?")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label(format!(
                    "{mounted_selected_count} of the {selected_count} selected archives are \
                     currently mounted."
                ));
                ui.label(format!(
                    "Only those {mounted_selected_count} mounted archives will be unmounted, \
                     one at a time. The rest of the selection is not currently mounted and will \
                     not be touched."
                ));
                ui.label("Close applications using these mounts before continuing. Files that are still open may prevent normal unmounting.");
                ui.label("A failure will be recorded, and later archives will still be attempted.");
                ui.label(format!(
                    "Cleanup after each successful unmount: {}.",
                    if *cleanup_after_unmount {
                        "enabled"
                    } else {
                        "disabled"
                    }
                ));
                ui.label(
                    "Original archive files will not be deleted or modified - unmounting only \
                     detaches the read-only mount, it never touches the archive itself.",
                );
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    let cancel = ui.add_enabled(
                        actions_available,
                        egui::Button::new("Cancel").fill(ui.visuals().selection.bg_fill),
                    );
                    if *focus_unmount_selected_cancel {
                        cancel.request_focus();
                        *focus_unmount_selected_cancel = false;
                    }
                    if cancel.clicked() {
                        history.record(HistoryEntry::new(
                            ActivityAction::UnmountAll,
                            None,
                            ActivityOutcome::Cancelled,
                            "Unmount selected cancelled before starting.",
                        ));
                        *confirm_unmount_selected = None;
                    }
                    if ui
                        .add_enabled(
                            mounted_selected_count > 0 && !busy,
                            egui::Button::new("Unmount selected"),
                        )
                        .clicked()
                    {
                        requested_action = Some(AppOperationRequest::UnmountAll {
                            items: mounted_selected,
                            cleanup_after_unmount: *cleanup_after_unmount,
                        });
                        *confirm_unmount_selected = None;
                    }
                });
            });
    }

    let selected_persisted = selected_persisted_archive(cached, selected_archive.as_deref());
    let selected_source_path = selected_row_index(&merged_rows, selected_archive.as_deref())
        .and_then(|index| merged_rows[index].source_path.as_deref());
    let selected_actions = egui::TopBottomPanel::top("library_selected_archive_panel")
        .resizable(true)
        .default_height(SELECTED_ARCHIVE_PANEL_DEFAULT_HEIGHT)
        .height_range(SELECTED_ARCHIVE_PANEL_MIN_HEIGHT..=SELECTED_ARCHIVE_PANEL_MAX_HEIGHT)
        .show_inside(ui, |ui| {
            egui::ScrollArea::vertical()
                .id_salt("library_selected_archive_scroll")
                .auto_shrink([false, false])
                .show(ui, |ui| {
                    show_selected_archive(
                        ui,
                        selected_record(&data.records, selected_archive.as_deref()),
                        selected_persisted,
                        selected_platform_details(cached, selected_persisted),
                        selected_source_path,
                        SelectedArchiveViewState {
                            operation,
                            busy,
                            block_reason,
                            action_readiness_debug_lines,
                            confirm_unmount,
                            confirm_lazy_unmount,
                            focus_lazy_cancel,
                            lazy_unmount_offers,
                            remount_offers,
                            cleanup_after_unmount,
                            platform_choice,
                            platform_custom_text,
                            platform_busy,
                            clipboard,
                        },
                    )
                })
                .inner
        })
        .inner;
    if let Some(request) = selected_actions.operation {
        requested_action = Some(AppOperationRequest::Archive(request));
    }
    if let Some((archive_path, action)) = selected_actions.platform {
        requested_action = Some(AppOperationRequest::PlatformAssignment {
            archive_path,
            action,
        });
    }
    if let Some(archive_path) = selected_actions.inspect {
        requested_action = Some(AppOperationRequest::InspectArchive(archive_path));
    }
    if let Some(archive_path) = selected_actions.cheats_mods {
        requested_action = Some(AppOperationRequest::OpenCheatsMods(archive_path));
    }

    if let Some(archive_path) = confirm_lazy_unmount.clone() {
        let actions_available =
            lazy_confirmation_available(&archive_path, lazy_unmount_offers, busy);
        egui::Window::new("Use Lazy Unmount?")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label(LAZY_UNMOUNT_WARNING);
                ui.label(archive_path.display().to_string());
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    let cancel = ui.add_enabled(
                        actions_available,
                        egui::Button::new("Cancel").fill(ui.visuals().selection.bg_fill),
                    );
                    if *focus_lazy_cancel {
                        cancel.request_focus();
                        *focus_lazy_cancel = false;
                    }
                    if cancel.clicked() {
                        record_recovery_activity(
                            history,
                            ActivityAction::LazyUnmount,
                            &archive_path,
                            ActivityOutcome::Cancelled,
                            "User cancelled lazy unmount.",
                        );
                        *confirm_lazy_unmount = None;
                    }
                    if ui
                        .add_enabled(
                            actions_available,
                            egui::Button::new("Try Normal Unmount Again"),
                        )
                        .clicked()
                    {
                        record_recovery_activity(
                            history,
                            ActivityAction::Unmount,
                            &archive_path,
                            ActivityOutcome::Retried,
                            "Normal unmount retried.",
                        );
                        requested_action = Some(AppOperationRequest::Archive(OperationRequest {
                            action: ArchiveAction::Unmount,
                            archive_path: archive_path.clone(),
                            cleanup_after_unmount: *cleanup_after_unmount,
                        }));
                        *confirm_lazy_unmount = None;
                    }
                    if ui
                        .add_enabled(actions_available, egui::Button::new("Lazy Unmount"))
                        .clicked()
                    {
                        advance_to_final_lazy_confirmation(
                            confirm_lazy_unmount,
                            confirm_lazy_unmount_final,
                            focus_final_lazy_cancel,
                            &archive_path,
                        );
                    }
                });
            });
    }

    if let Some(archive_path) = confirm_lazy_unmount_final.clone() {
        let actions_available =
            lazy_confirmation_available(&archive_path, lazy_unmount_offers, busy);
        egui::Window::new("Confirm Lazy Unmount")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label("This is the final confirmation. Close applications using this mount before continuing.");
                ui.label(archive_path.display().to_string());
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    let cancel = ui.add_enabled(
                        actions_available,
                        egui::Button::new("Cancel").fill(ui.visuals().selection.bg_fill),
                    );
                    if *focus_final_lazy_cancel {
                        cancel.request_focus();
                        *focus_final_lazy_cancel = false;
                    }
                    if cancel.clicked() {
                        record_recovery_activity(
                            history,
                            ActivityAction::LazyUnmount,
                            &archive_path,
                            ActivityOutcome::Cancelled,
                            "User cancelled lazy unmount.",
                        );
                        *confirm_lazy_unmount_final = None;
                    }
                    if ui
                        .add_enabled(actions_available, egui::Button::new("Confirm Lazy Unmount"))
                        .clicked()
                    {
                        record_recovery_activity(
                            history,
                            ActivityAction::LazyUnmount,
                            &archive_path,
                            ActivityOutcome::Confirmed,
                            "Lazy unmount confirmed.",
                        );
                        requested_action = Some(AppOperationRequest::Archive(OperationRequest {
                            action: ArchiveAction::LazyUnmount,
                            archive_path: archive_path.clone(),
                            cleanup_after_unmount: *cleanup_after_unmount,
                        }));
                        *confirm_lazy_unmount_final = None;
                    }
                });
            });
    }

    if let Some(archive_path) = confirm_unmount.clone() {
        let actions_available = confirmation_actions_available(busy);
        egui::Window::new("Confirm unmount")
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label("Unmount this archive?");
                ui.label(archive_path.display().to_string());
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    if ui
                        .add_enabled(actions_available, egui::Button::new("Cancel"))
                        .clicked()
                    {
                        *confirm_unmount = None;
                    }
                    if ui
                        .add_enabled(actions_available, egui::Button::new("Unmount"))
                        .clicked()
                    {
                        requested_action = Some(AppOperationRequest::Archive(OperationRequest {
                            action: ArchiveAction::Unmount,
                            archive_path: archive_path.clone(),
                            cleanup_after_unmount: *cleanup_after_unmount,
                        }));
                        *confirm_unmount = None;
                    }
                });
            });
    }

    ui.separator();

    // Requirement: the bulk platform action bar must render immediately
    // above the Search/filter controls, in the CentralPanel's ordinary
    // top-to-bottom flow - never after the table's ScrollAreas. Both
    // ScrollAreas below use `auto_shrink([false, false])`, which makes
    // them greedily claim *all* remaining vertical space in `ui`; a
    // widget placed after them in the same vertical layout would be
    // squeezed into whatever sliver of height (often zero) is left over,
    // which is why the bar previously never appeared despite a correct
    // selection count. Uses the exact same `selected_archives` `HashSet`
    // that `show_archive_rows` highlights rows from - never a second,
    // possibly-stale copy.
    if let Some(action) = show_bulk_platform_action_bar(
        ui,
        selected_archives,
        bulk_platform_choice,
        bulk_platform_busy,
    ) {
        requested_action = Some(AppOperationRequest::BulkPlatformAssignment {
            archive_paths: selected_archives.iter().cloned().collect(),
            kind: action,
        });
    }

    widgets::card(ui, |ui| {
        widgets::section_header(
            ui,
            "Find and filter",
            Some("Search paths and metadata, then narrow the catalogue without changing it."),
        );

        let mut filter_changed = false;
        ui.horizontal_wrapped(|ui| {
            ui.label("Search:");
            let search_width = (ui.available_width() - 72.0).clamp(180.0, 520.0);
            filter_changed |=
                show_text_edit_with_context_menu(ui, filter, clipboard, |text_edit| {
                    text_edit
                        .id(egui::Id::new(SEARCH_FILTER_TEXT_EDIT_ID))
                        .hint_text("archive, mount path, platform, or state")
                        .desired_width(search_width)
                })
                .changed();
            if !filter.is_empty() && ui.small_button("Clear").clicked() {
                filter.clear();
                filter_changed = true;
            }
        });
        if filter_changed {
            *filtered_rows = matching_row_indices(&merged_rows, filter);
        }

        let unknown_count = merged_rows
            .iter()
            .filter(|row| row.unknown_platform)
            .count();
        let mut filters_changed = false;
        ui.horizontal_wrapped(|ui| {
            ui.label("Show:");
            filters_changed |= ui
                .checkbox(&mut library_filters.present, "Present")
                .changed();
            filters_changed |= ui
                .checkbox(&mut library_filters.missing, "Missing")
                .changed();
            filters_changed |= ui
                .checkbox(
                    &mut library_filters.awaiting_validation,
                    "Awaiting validation",
                )
                .changed();
            filters_changed |= ui
                .checkbox(&mut library_filters.known_platform, "Known platform")
                .changed();
            filters_changed |= ui
                .checkbox(
                    &mut library_filters.unknown_platform,
                    format!("Unknown platform ({unknown_count})"),
                )
                .changed();
            if library_filters.is_active() && ui.small_button("Clear filters").clicked() {
                *library_filters = LibraryRowFilters::default();
                filters_changed = true;
            }
        });
        let _ = filters_changed;

        if unknown_platform_banner_visible(library_filters, unknown_count) {
            widgets::banner(
                ui,
                &unknown_platform_aggregate_headline(unknown_count),
                UNKNOWN_PLATFORM_EXPLANATION,
                widgets::StatusTone::Info,
            );
        }

        let configured_sources: &[SourceFolderView] = cached
            .map(|cached| cached.source_views.as_slice())
            .unwrap_or(&[]);
        if !configured_sources.is_empty() {
            ui.horizontal_wrapped(|ui| {
                ui.label("Source:");
                let selected_text = match library_source_filter {
                    None => "All sources".to_string(),
                    Some(None) => "Unassigned / Legacy".to_string(),
                    Some(Some(path)) => path.display().to_string(),
                };
                egui::ComboBox::from_id_salt("library_source_filter")
                    .selected_text(selected_text)
                    .width((ui.available_width() - 16.0).clamp(220.0, 520.0))
                    .show_ui(ui, |ui| {
                        ui.selectable_value(library_source_filter, None, "All sources");
                        for source in configured_sources {
                            ui.selectable_value(
                                library_source_filter,
                                Some(Some(source.path.clone())),
                                source.path.display().to_string(),
                            );
                        }
                        ui.selectable_value(
                            library_source_filter,
                            Some(None),
                            "Unassigned / Legacy",
                        );
                    });
            });
        }

        let missing_count = merged_rows
            .iter()
            .filter(|row| row.origin == RowOrigin::CachedMissing)
            .count();
        let mut missing_only = library_filters.missing
            && !library_filters.present
            && !library_filters.awaiting_validation;
        let selected_missing = selected_missing_paths(cached, selected_archives);
        ui.horizontal_wrapped(|ui| {
            ui.label(format!("Missing catalogue entries: {missing_count}"));
            if ui
                .checkbox(&mut missing_only, "Show missing only")
                .changed()
            {
                set_missing_review_mode(library_filters, missing_only);
            }
            let enabled = missing_removal_available && selected_missing.is_ok();
            let response = ui.add_enabled(enabled, egui::Button::new(REMOVE_MISSING_CONFIRM_LABEL));
            if !enabled && let Err(reason) = &selected_missing {
                response.clone().on_hover_text(reason);
            }
            if response.clicked()
                && let Ok(paths) = &selected_missing
            {
                *confirm_remove_missing = Some(paths.clone());
            }
            if missing_removal_busy {
                ui.spinner();
                ui.label("Removing catalogue entries...");
            }
        });

        if let Some(paths) = confirm_remove_missing.clone() {
            let confirmation_selection: HashSet<PathBuf> = paths.iter().cloned().collect();
            let still_valid = selected_missing_paths(cached, &confirmation_selection).is_ok();
            egui::Window::new(format!(
                "Remove {} missing catalogue entr{}?",
                paths.len(),
                if paths.len() == 1 { "y" } else { "ies" }
            ))
            .collapsible(false)
            .resizable(false)
            .anchor(egui::Align2::CENTER_CENTER, egui::Vec2::ZERO)
            .show(ui.ctx(), |ui| {
                ui.label(missing_removal_confirmation_text(paths.len()));
                ui.add_space(8.0);
                ui.horizontal(|ui| {
                    if ui.button(REMOVE_MISSING_CANCEL_LABEL).clicked() {
                        *confirm_remove_missing = None;
                    }
                    if ui
                        .add_enabled(
                            missing_removal_available && still_valid,
                            egui::Button::new(REMOVE_MISSING_CONFIRM_LABEL),
                        )
                        .clicked()
                    {
                        requested_action = Some(AppOperationRequest::RemoveMissing(paths.clone()));
                        *confirm_remove_missing = None;
                    }
                });
            });
        }
    });
    ui.add_space(8.0);

    let base_indices: Vec<usize> = filtered_rows
        .clone()
        .unwrap_or_else(|| (0..merged_rows.len()).collect());
    let mut visible_indices: Vec<usize> = base_indices
        .into_iter()
        .filter(|&index| {
            !library_filters.is_active() || library_filters.matches(&merged_rows[index])
        })
        .filter(|&index| match library_source_filter {
            None => true,
            Some(wanted) => merged_rows[index].source_path.as_ref() == wanted.as_ref(),
        })
        .filter(|&index| {
            !recent_view
                || recent_scan
                    .is_some_and(|recent| recent_scan_contains(recent, &merged_rows[index].path))
        })
        .collect();
    if let Some(field) = *sort_field {
        sort_visible_indices(&merged_rows, &mut visible_indices, field, *sort_ascending);
    }
    let visible_count = visible_indices.len();

    show_selection_controls_row(ui, &merged_rows, &visible_indices, selected_archives);
    ui.add_space(4.0);
    if *select_all_visible_requested {
        *selected_archives = select_all_visible(&merged_rows, &visible_indices);
        *select_all_visible_requested = false;
    }

    let mut requested_scroll_pos: Option<usize> = None;
    if !keyboard_shortcuts_blocked_by_focus(ui.ctx()) {
        let (escape_pressed, select_all_pressed, arrow_down_pressed, arrow_up_pressed, ctrl_held) =
            ui.input(|input| {
                (
                    input.key_pressed(egui::Key::Escape),
                    input.modifiers.ctrl && input.key_pressed(egui::Key::A),
                    input.key_pressed(egui::Key::ArrowDown),
                    input.key_pressed(egui::Key::ArrowUp),
                    input.modifiers.ctrl,
                )
            });

        if escape_pressed {
            selected_archives.clear();
        }
        if select_all_pressed {
            *selected_archives = select_all_visible(&merged_rows, &visible_indices);
        }
        if arrow_down_pressed || arrow_up_pressed {
            let direction = if arrow_down_pressed {
                ArrowDirection::Down
            } else {
                ArrowDirection::Up
            };
            if let Some(new_focus) = next_focus_in_visible_order(
                &merged_rows,
                &visible_indices,
                selected_archive.as_deref(),
                direction,
            ) {
                apply_arrow_focus_change(
                    selected_archives,
                    selected_archive,
                    new_focus.clone(),
                    ctrl_held,
                );
                requested_scroll_pos = visible_indices
                    .iter()
                    .position(|&index| merged_rows[index].path == new_focus);
            }
        }
    }

    let row_height = fixed_row_height(
        ui.text_style_height(&egui::TextStyle::Body),
        ui.spacing().interact_size.y,
    );
    let horizontal_spacing = ui.spacing().item_spacing.x;
    let selected_index = selected_row_index(&merged_rows, selected_archive.as_deref());
    let table_message = if recent_view && recent_scan.is_none() {
        Some(LibraryTableMessage::NoCompletedScan)
    } else if recent_scan.is_some_and(|recent| recent.archives.is_empty()) {
        Some(LibraryTableMessage::NoRecentAdditions)
    } else {
        library_table_message(merged_rows.is_empty(), visible_count)
    };
    match table_message {
        Some(LibraryTableMessage::NoCompletedScan) => {
            widgets::empty_state(
                ui,
                "No completed scan yet",
                "Run a library scan to populate Recently Found.",
                None,
            );
        }
        Some(LibraryTableMessage::NoRecentAdditions) => {
            widgets::empty_state(
                ui,
                "No newly added files",
                "The most recent completed scan added no new library entries. Updated entries remain in the main Library.",
                None,
            );
        }
        Some(LibraryTableMessage::EmptyLibrary) => {
            widgets::empty_state(ui, "Library is empty", EMPTY_LIBRARY_MESSAGE, None);
        }
        Some(LibraryTableMessage::NoFilterResults) => {
            widgets::empty_state(
                ui,
                "No matching archives",
                ZERO_FILTER_RESULTS_MESSAGE,
                None,
            );
        }
        None => {
            let mut clicked = None;
            let mut menu_action = None;
            let mut displayed_column_widths =
                if *library_column_widths == LibraryColumnWidths::default() {
                    responsive_library_column_widths(ui.available_width(), horizontal_spacing)
                } else {
                    *library_column_widths
                };
            let initial_displayed_column_widths = displayed_column_widths;
            let row_menu_context = RowMenuContext {
                records: &data.records,
                cached,
                busy,
                block_reason,
                platform_busy,
                retroarch_profiles,
                library_views_configured,
                library_view_last_plan,
            };
            egui::ScrollArea::horizontal()
                .id_salt("archive_status_horizontal")
                .auto_shrink([false, false])
                .show(ui, |ui| {
                    let initial_widths = displayed_column_widths.as_array();
                    ui.set_min_width(table_width(horizontal_spacing, &initial_widths));
                    if let Some(clicked_field) = show_header_row(
                        ui,
                        &COLUMN_HEADERS,
                        &COLUMN_SORT_FIELDS,
                        row_height,
                        *sort_field,
                        *sort_ascending,
                        &mut displayed_column_widths,
                    ) {
                        apply_header_click(sort_field, sort_ascending, clicked_field);
                    }
                    ui.separator();
                    // Re-read after `show_header_row`, which may have just
                    // resized a column via its drag handle this very
                    // frame - the rows below must always paint with
                    // *this* frame's widths, never a one-frame-stale copy.
                    let widths = displayed_column_widths.as_array();

                    let body_height = ui.available_height().max(row_height);
                    let mut vertical_scroll_area = egui::ScrollArea::vertical()
                        .id_salt("archive_status_vertical")
                        .max_height(body_height)
                        .auto_shrink([false, false]);
                    if let Some(pos) = requested_scroll_pos {
                        let row_stride = row_height + ui.spacing().item_spacing.y;
                        vertical_scroll_area = vertical_scroll_area.vertical_scroll_offset(
                            compute_scroll_offset_for_focus(
                                pos,
                                row_stride,
                                *library_scroll_offset,
                                body_height,
                            ),
                        );
                    }
                    let scroll_output = vertical_scroll_area.show_rows(
                        ui,
                        row_height,
                        visible_count,
                        |ui, row_range| {
                            let result = show_archive_rows(
                                ui,
                                &merged_rows,
                                Some(&visible_indices),
                                row_range,
                                row_height,
                                selected_index,
                                selected_archives,
                                selected_archive,
                                &widths,
                                &row_menu_context,
                            );
                            clicked = result.clicked;
                            menu_action = result.menu_action;
                        },
                    );
                    *library_scroll_offset = scroll_output.state.offset.y;
                });
            if displayed_column_widths != initial_displayed_column_widths {
                *library_column_widths = displayed_column_widths;
            }
            // Requirement 2: an ordinary click replaces the whole selection
            // with just this row; a Ctrl-click toggles only this row,
            // leaving every other currently-selected row untouched. Either
            // way the details panel's "focused" row (selected_archive)
            // becomes whatever was just clicked, and its platform picker
            // resets - it must never keep showing a choice made for a
            // different, previously-focused archive.
            if let Some((index, ctrl_held)) = clicked {
                let path = merged_rows[index].path.clone();
                apply_row_click(selected_archives, selected_archive, path, ctrl_held);
                *platform_choice = None;
                platform_custom_text.clear();
            }
            // Dispatches every row context-menu action through the exact
            // same `AppOperationRequest`/direct-state paths the existing
            // buttons already use - see `RowContextMenuAction`'s doc
            // comment. `MountSelected`/`UnmountSelected` reuse `MountAll`/
            // `UnmountAll` unchanged (just a selection-scoped item list),
            // so `update()` needs no new match arm at all for those.
            if let Some(action) = menu_action {
                match action {
                    RowContextMenuAction::Operation(request) => {
                        requested_action = Some(AppOperationRequest::Archive(request));
                    }
                    RowContextMenuAction::Inspect(archive_path) => {
                        requested_action = Some(AppOperationRequest::InspectArchive(archive_path));
                    }
                    RowContextMenuAction::Platform(archive_path, platform_action) => {
                        requested_action = Some(AppOperationRequest::PlatformAssignment {
                            archive_path,
                            action: platform_action,
                        });
                    }
                    RowContextMenuAction::MountSelected(paths) => {
                        requested_action = Some(AppOperationRequest::MountAll(
                            mount_all_items_for_paths(&data.records, &paths),
                        ));
                    }
                    RowContextMenuAction::UnmountSelected => {
                        *confirm_unmount_selected = Some(UnmountSelectedConfirmation);
                        *focus_unmount_selected_cancel = true;
                    }
                    RowContextMenuAction::BulkPlatform(archive_paths, kind) => {
                        requested_action = Some(AppOperationRequest::BulkPlatformAssignment {
                            archive_paths,
                            kind,
                        });
                    }
                    RowContextMenuAction::CopyText(text) => {
                        let _ = clipboard.set_text(text);
                    }
                    RowContextMenuAction::ShowOnlySource(source_path) => {
                        *library_source_filter = Some(source_path);
                    }
                    RowContextMenuAction::ShowInLibraryViews(archive_path) => {
                        requested_action =
                            Some(AppOperationRequest::ShowInLibraryViews(archive_path));
                    }
                    RowContextMenuAction::CheatsMods(archive_path) => {
                        requested_action = Some(AppOperationRequest::OpenCheatsMods(archive_path));
                    }
                    RowContextMenuAction::ClearSelection => {
                        selected_archives.clear();
                        *selected_archive = None;
                    }
                }
            }
        }
    }

    requested_action
}

fn recent_scan_contains(recent: &RecentScanAdditions, path: &Path) -> bool {
    recent
        .archives
        .iter()
        .any(|archive| archive.absolute_path == path)
}

fn fixed_row_height(text_height: f32, interact_height: f32) -> f32 {
    text_height.max(interact_height)
}

fn table_width(horizontal_spacing: f32, widths: &[f32; 4]) -> f32 {
    widths.iter().sum::<f32>() + horizontal_spacing * (widths.len().saturating_sub(1) as f32)
}
fn show_column_resize_handle(
    ui: &mut egui::Ui,
    id: egui::Id,
    handle_rect: egui::Rect,
    width: &mut f32,
) {
    let response = ui.interact(handle_rect, id, egui::Sense::drag());
    if response.dragged() {
        *width = (*width + response.drag_delta().x)
            .clamp(MIN_RESIZABLE_COLUMN_WIDTH, MAX_RESIZABLE_COLUMN_WIDTH);
    }
    if response.hovered() || response.dragged() {
        ui.output_mut(|output| output.cursor_icon = egui::CursorIcon::ResizeColumn);
    }
    let stroke_color = if response.dragged() {
        ui.visuals().widgets.active.bg_fill
    } else if response.hovered() {
        ui.visuals().widgets.hovered.bg_fill
    } else {
        ui.visuals().widgets.noninteractive.bg_stroke.color
    };
    ui.painter().vline(
        handle_rect.center().x,
        handle_rect.y_range(),
        egui::Stroke::new(2.0_f32, stroke_color),
    );
}
fn show_header_row(
    ui: &mut egui::Ui,
    cells: &[&str; 4],
    fields: &[SortField; 4],
    row_height: f32,
    sort_field: Option<SortField>,
    sort_ascending: bool,
    column_widths: &mut LibraryColumnWidths,
) -> Option<SortField> {
    let mut clicked_field = None;
    let spacing = ui.spacing().item_spacing.x;
    let widths = column_widths.as_array();
    let total_width = table_width(spacing, &widths);
    let (_, header_rect) = ui.allocate_space(egui::vec2(total_width, row_height));

    let mut x = header_rect.left();
    for (index, ((text, width), field)) in cells
        .iter()
        .zip(widths)
        .zip(fields.iter().copied())
        .enumerate()
    {
        // Resizable columns reserve their own trailing edge for the drag
        // handle (see `COLUMN_RESIZE_HANDLE_WIDTH`), so the button itself
        // never overlaps the handle's own interact rect.
        let is_resizable = index == 2 || index == 3;
        let button_width = if is_resizable {
            width - COLUMN_RESIZE_HANDLE_WIDTH
        } else {
            width
        };
        let cell_rect = egui::Rect::from_min_size(
            egui::pos2(x, header_rect.top()),
            egui::vec2(button_width, row_height),
        );
        let label = if sort_field == Some(field) {
            format!(
                "{text} {}",
                if sort_ascending {
                    "\u{25B2}"
                } else {
                    "\u{25BC}"
                }
            )
        } else {
            (*text).to_string()
        };
        let response = ui
            .put(
                cell_rect,
                egui::Button::new(egui::RichText::new(label).strong()).frame(false),
            )
            .on_hover_text(*text);
        if response.clicked() {
            clicked_field = Some(field);
        }

        if is_resizable {
            let handle_rect = egui::Rect::from_min_size(
                egui::pos2(x + width - COLUMN_RESIZE_HANDLE_WIDTH, header_rect.top()),
                egui::vec2(COLUMN_RESIZE_HANDLE_WIDTH, row_height),
            );
            let handle_id = egui::Id::new("library_column_resize_handle").with(index);
            let target_width = if index == 2 {
                &mut column_widths.archive_path
            } else {
                &mut column_widths.mount_path
            };
            show_column_resize_handle(ui, handle_id, handle_rect, target_width);
        }

        x += width + spacing;
    }
    clicked_field
}

/// Finds which cell rect (laid out left-to-right starting at `row_left`,
/// each `widths[i]` wide with `spacing` between them, matching exactly
/// how `show_data_row`/`show_inspector_row` paint them) contains
/// `pointer_x`, if any. Pure and independent of any live `egui::Context`;
/// see `hovered_cell_full_text`, its only caller, and its own doc
/// comment for why this is kept testable in isolation from real font
/// metrics/hover state. Generic over the number of columns (a slice, not
/// a fixed-size array) so both the four-column Library table and the
/// two-column Archive Inspector row share this one implementation.
fn cell_index_at(pointer_x: f32, row_left: f32, widths: &[f32], spacing: f32) -> Option<usize> {
    let mut x = row_left;
    for (index, width) in widths.iter().enumerate() {
        if pointer_x >= x && pointer_x < x + width {
            return Some(index);
        }
        x += width + spacing;
    }
    None
}
fn hovered_cell_full_text<'a>(
    pointer_x: Option<f32>,
    row_left: f32,
    cells: &[&'a str],
    widths: &[f32],
    spacing: f32,
    mut measure_width: impl FnMut(&str) -> f32,
) -> Option<&'a str> {
    let index = cell_index_at(pointer_x?, row_left, widths, spacing)?;
    let text = cells[index];
    (measure_width(text) > widths[index]).then_some(text)
}

/// Renders one selectable archive table row as a *single* clickable
/// region (`Sense::click()` on one allocated `Rect`, identified by
/// `id_source` - the archive's exact path, never a lossy display string)
/// with the four cells' text painted passively inside it.
///
/// This replaced an earlier version that rendered each of the four cells
/// as its own separate `egui::Button`, with the row's overall
/// clicked-ness computed by OR-ing all four `Response::clicked()` values
/// together. That meant a row had no single, authoritative `Response` of
/// its own: four independent interactive widgets shared the row's
/// hover/press state, with real gaps between them (the `horizontal`
/// layout's item spacing) that belonged to no widget's sense area at
/// all, and Ctrl-click reliability regressed as a direct result - see the
/// fix for the real-world Nobara bug report this was rewritten for.
///
/// Cell text is painted directly with `Painter::text` rather than as
/// separate child `Label` widgets. This was not just a style choice:
/// registering more than one child widget inside the row's own interact
/// `Rect` (even purely non-interactive `Label`s, `Sense::hover()`-only)
/// was empirically confirmed, while fixing the Ctrl-click bug, to make
/// egui's hit-testing stop recognizing the row's *own* `Response` as
/// hovered/clicked at all in some cases - see the headless
/// `simulate_row_click`-based tests below, which reproduce this exact
/// failure mode against the old approach. Direct painting registers no
/// widgets at all, so there is nothing left inside the row that could
/// ever compete with its own click/hover sensing.
///
/// `widths` (added for resizable columns) pushes this pre-existing,
/// tightly-scoped rendering primitive one parameter past clippy's default
/// threshold. Every parameter here is plain, read-only per-row display
/// data with no natural grouping that would not just be `RowVisualState`-
/// style busywork for its own sake - see `show_archive_rows`'s identical
/// justification, its only caller.
#[allow(clippy::too_many_arguments)]
fn show_data_row(
    ui: &mut egui::Ui,
    cells: &[&str; 4],
    row_height: f32,
    id_source: &Path,
    multi_selected: bool,
    focused: bool,
    text_color: Option<egui::Color32>,
    widths: &[f32; 4],
) -> egui::Response {
    let spacing = ui.spacing().item_spacing.x;
    let width = table_width(spacing, widths);
    // Reserve the row's layout space first (advancing the cursor exactly
    // as any other widget would), then sense clicks/hover for that exact
    // `Rect` under a stable `Id` derived from `id_source` - not egui's
    // auto-generated one. `show_rows` virtualizes this list, so the
    // *same* screen position can render a *different* archive across
    // scroll frames; a stable, identity-derived `Id` (rather than one
    // implied only by rendering order/position) means a press-then-scroll
    // gesture can never have its release misattributed to whatever
    // archive now happens to occupy that same position.
    let (_, rect) = ui.allocate_space(egui::vec2(width, row_height));
    let row_id = egui::Id::new("archive_table_row").with(id_source);
    let mut response = ui.interact(rect, row_id, egui::Sense::click());

    // Paint the background *before* the text, so a selected/hovered row
    // gets one clean, contiguous highlight across all four columns
    // (requirement: "a clearly visible selected background", not four
    // separately-tinted buttons with unhighlighted gaps between them).
    // `selection.bg_fill` and `hovered.weak_bg_fill` are egui's own
    // default palette entries - the same colors any ordinary selected or
    // hovered widget would use.
    let visuals = ui.visuals();
    if multi_selected {
        ui.painter()
            .rect_filled(rect, 0.0, visuals.selection.bg_fill);
    } else if response.hovered() {
        ui.painter()
            .rect_filled(rect, 0.0, visuals.widgets.hovered.weak_bg_fill);
    }
    // The Ctrl+Up/Down "focus doesn't visibly move" fix: a *border*, not
    // another fill, so it stays visible whether or not this row is also
    // `multi_selected` - moving focus with Ctrl held between two rows that
    // are both already multi-selected must still show something change.
    // `warn_fg_color` is deliberately a different hue from
    // `selection.bg_fill`/`.stroke` so the two states never look like the
    // same highlight at a glance.
    if focused {
        ui.painter().rect_stroke(
            rect.shrink(1.0),
            0.0,
            egui::Stroke::new(2.0_f32, visuals.warn_fg_color),
            egui::StrokeKind::Inside,
        );
    }

    let font_id = egui::TextStyle::Body.resolve(ui.style());
    let color = text_color.unwrap_or_else(|| ui.visuals().text_color());
    let mut x = rect.left();
    for (text, column_width) in cells.iter().zip(widths.iter().copied()) {
        let cell_rect = egui::Rect::from_min_size(
            egui::pos2(x, rect.top()),
            egui::vec2(column_width, row_height),
        );
        ui.painter().with_clip_rect(cell_rect).text(
            egui::pos2(x + 2.0, rect.center().y),
            egui::Align2::LEFT_CENTER,
            text,
            font_id.clone(),
            color,
        );
        x += column_width + spacing;
    }
    let pointer_x = response.hover_pos().map(|pos| pos.x);
    if let Some(full_text) =
        hovered_cell_full_text(pointer_x, rect.left(), cells, widths, spacing, |text| {
            ui.fonts(|fonts| {
                fonts
                    .layout_no_wrap(text.to_string(), font_id.clone(), color)
                    .size()
                    .x
            })
        })
    {
        response = response.on_hover_text(full_text);
    }

    response
}

/// What a Library row's right-click context menu can request - collected
/// the same way `show_selected_archive` collects its own Mount/Unmount/
/// Inspect/Platform request (a plain returned value; nothing inside the
/// menu closure mutates app state directly), so `show_loaded_data`
/// dispatches every one of these through the exact same
/// `AppOperationRequest`/direct-state paths the existing buttons already
/// use - never a second, independently-drifting execution path.
enum RowContextMenuAction {
    Operation(OperationRequest),
    Inspect(PathBuf),
    Platform(PathBuf, PlatformAction),
    /// Pre-filtered to exactly the selected archives whose `MountState` is
    /// `Pending`/`MountPathExists` (mirrors `pending_mount_items`'s own
    /// filter) - the caller only has to look each path up to build
    /// `MountAllItem`s, never re-derive eligibility.
    MountSelected(Vec<PathBuf>),
    /// A request to *open* the "Unmount selected" confirmation dialog -
    /// carries no item list, unlike `MountSelected`: Mount has no
    /// confirmation step to begin with, but Unmount's eligible set is
    /// deliberately recomputed fresh both while the dialog is open and
    /// again the instant it is confirmed (see `UnmountSelectedConfirmation`'s
    /// doc comment), never captured at the moment this menu item was
    /// clicked.
    UnmountSelected,
    BulkPlatform(Vec<PathBuf>, BulkPlatformActionKind),
    CopyText(String),
    ShowOnlySource(Option<PathBuf>),
    /// "Show in Library View preview" - see
    /// `AppOperationRequest::ShowInLibraryViews`'s doc comment.
    ShowInLibraryViews(PathBuf),
    /// Open the first-class Cheats & Mods workspace for this exact
    /// archive - same gating as the Selected page's entry.
    CheatsMods(PathBuf),
    ClearSelection,
}

/// Read-only state a Library row's context menu needs beyond what
/// `show_archive_rows` already takes - bundled in one struct so adding it
/// doesn't push `show_archive_rows`'s own parameter list further past
/// clippy's threshold (see its existing `#[allow(too_many_arguments)]`).
struct RowMenuContext<'a> {
    records: &'a [ArchiveRecord],
    cached: Option<&'a CachedLibrarySnapshot>,
    busy: bool,
    block_reason: Option<&'static str>,
    platform_busy: bool,
    /// See `LoadedViewState::retroarch_profiles`; profile readiness is
    /// presented on the destination page rather than used to hide it.
    retroarch_profiles: &'a RetroArchProfilesState,
    library_views_configured: bool,
    library_view_last_plan: Option<&'a (LibraryViewConfig, LibraryViewPlan)>,
}
fn apply_row_right_click(
    selected_archives: &mut HashSet<PathBuf>,
    selected_archive: &mut Option<PathBuf>,
    path: PathBuf,
) {
    if !selected_archives.contains(&path) {
        selected_archives.clear();
        selected_archives.insert(path.clone());
        *selected_archive = Some(path);
    }
}

fn cheats_mods_row_action(path: &Path) -> RowContextMenuAction {
    RowContextMenuAction::CheatsMods(path.to_path_buf())
}
fn show_row_context_menu(
    ui: &mut egui::Ui,
    row: &ArchiveRow,
    selected_archives: &HashSet<PathBuf>,
    ctx: &RowMenuContext<'_>,
) -> Option<RowContextMenuAction> {
    if selected_archives.len() > 1 {
        show_bulk_row_context_menu(ui, selected_archives, ctx)
    } else {
        show_single_row_context_menu(ui, row, ctx)
    }
}
fn library_view_planned_entry_for<'a>(
    last_plan: Option<&'a (LibraryViewConfig, LibraryViewPlan)>,
    archive_path: &Path,
) -> Option<&'a LibraryViewPlanEntry> {
    let (_, plan) = last_plan?;
    plan.entries
        .iter()
        .find(|entry| entry.archive_path.as_deref() == Some(archive_path))
}

/// The narrower "does this archive have a real planned destination"
/// question `library_view_planned_entry_for` also answers - `None` for a
/// `Skip*` entry (no destination was ever computed) as well as for "no
/// entry at all", so a caller offering "copy this path" never offers to
/// copy nothing.
fn library_view_planned_destination_for<'a>(
    last_plan: Option<&'a (LibraryViewConfig, LibraryViewPlan)>,
    archive_path: &Path,
) -> Option<&'a Path> {
    library_view_planned_entry_for(last_plan, archive_path)?
        .destination_path
        .as_deref()
}
fn show_single_row_context_menu(
    ui: &mut egui::Ui,
    row: &ArchiveRow,
    ctx: &RowMenuContext<'_>,
) -> Option<RowContextMenuAction> {
    let mut action = None;
    let record = selected_record(ctx.records, Some(&row.path));
    let persisted = selected_persisted_archive(ctx.cached, Some(&row.path));

    if let Some(record) = record.filter(|record| record.is_mount_input()) {
        let archive_action = available_action(record.mount_state);
        let label = match archive_action {
            ArchiveAction::Mount => "Mount",
            ArchiveAction::Unmount => "Unmount",
            ArchiveAction::LazyUnmount | ArchiveAction::Remount => {
                unreachable!("available_action only ever returns Mount or Unmount")
            }
        };
        let enabled = individual_actions_available(ctx.busy);
        let mut button = ui.add_enabled(enabled, egui::Button::new(label));
        if !enabled && let Some(reason) = ctx.block_reason {
            button = button.on_disabled_hover_text(reason);
        }
        if button.clicked() {
            action = Some(RowContextMenuAction::Operation(OperationRequest {
                action: archive_action,
                archive_path: row.path.clone(),
                cleanup_after_unmount: false,
            }));
            ui.close();
        }
        // Same source of truth as the main panel's inline reason label
        // (`show_selected_archive`) - both read the identical `block_reason`
        // `archive_action_block_reason` produced, never a second guess.
        if !enabled && let Some(reason) = ctx.block_reason {
            ui.label(reason);
        }
    } else if record.is_some() {
        ui.add_enabled(false, egui::Button::new("No mount required"))
            .on_disabled_hover_text("Loose ROM · no ArchiveFS mount required");
        ui.label("Loose ROM · no ArchiveFS mount required");
    } else {
        ui.add_enabled(false, egui::Button::new("Mount"))
            .on_disabled_hover_text("Archive is catalogue-only.");
        ui.label("Archive is catalogue-only.");
    }

    let inspectable = is_inspectable(&row.path);
    let inspect_button = ui.add_enabled(inspectable, egui::Button::new("Inspect contents"));
    let inspect_button = if inspectable {
        inspect_button.on_hover_text(
            "Read-only: view this archive's internal entries without extracting them.",
        )
    } else {
        inspect_button.on_disabled_hover_text("Unsupported archive format.")
    };
    if inspect_button.clicked() {
        action = Some(RowContextMenuAction::Inspect(row.path.clone()));
        ui.close();
    }

    // Same gating as the Selected page's entry button - this menu only
    // renders for a single-row selection, so the count is truthfully 1.
    let cheat_blocker = cheat_entry_blocker(
        Some(&row.path),
        1,
        Some(ctx.records),
        ctx.retroarch_profiles,
    );
    let cheat_button = ui.add_enabled(cheat_blocker.is_none(), egui::Button::new("Cheats & Mods"));
    let cheat_button = if let Some(reason) = cheat_blocker {
        cheat_button.on_disabled_hover_text(reason)
    } else {
        cheat_button
    };
    if cheat_button.clicked() {
        action = Some(cheats_mods_row_action(&row.path));
        ui.close();
    }

    ui.separator();
    if ui.button("Copy archive path").clicked() {
        action = Some(RowContextMenuAction::CopyText(row.archive_path.clone()));
        ui.close();
    }
    if ui.button("Copy mount path").clicked() {
        action = Some(RowContextMenuAction::CopyText(row.mount_path.clone()));
        ui.close();
    }
    if ui.button("Copy source path").clicked() {
        let source_text = row
            .source_path
            .as_ref()
            .map(|path| path.display().to_string())
            .unwrap_or_else(|| "Unassigned / Legacy".to_string());
        action = Some(RowContextMenuAction::CopyText(source_text));
        ui.close();
    }

    ui.separator();
    if let Some(persisted) = persisted {
        ui.menu_button("Set platform", |ui| {
            for name in canonical_platform_names() {
                let is_current = persisted.platform.as_deref() == Some(name);
                if ui.selectable_label(is_current, name).clicked() {
                    action = Some(RowContextMenuAction::Platform(
                        row.path.clone(),
                        PlatformAction::Set(name.to_string()),
                    ));
                    ui.close();
                }
            }
        });
        let manual_set = persisted.platform_source.as_deref() == Some(MANUAL_PLATFORM_SOURCE);
        if ui
            .add_enabled(manual_set, egui::Button::new("Clear manual platform"))
            .clicked()
        {
            action = Some(RowContextMenuAction::Platform(
                row.path.clone(),
                PlatformAction::Clear,
            ));
            ui.close();
        }
    } else {
        ui.add_enabled(false, egui::Button::new("Set platform"))
            .on_disabled_hover_text("Not yet in the library database.");
    }

    ui.separator();
    if ui.button("Show only this source").clicked() {
        action = Some(RowContextMenuAction::ShowOnlySource(
            row.source_path.clone(),
        ));
        ui.close();
    }
    if ui.button("Clear selection").clicked() {
        action = Some(RowContextMenuAction::ClearSelection);
        ui.close();
    }

    ui.separator();
    let show_button = ui.add_enabled(
        ctx.library_views_configured,
        egui::Button::new("Show in Library View preview"),
    );
    let show_button = if ctx.library_views_configured {
        show_button
    } else {
        show_button.on_disabled_hover_text("No Library View is configured yet.")
    };
    if show_button.clicked() {
        action = Some(RowContextMenuAction::ShowInLibraryViews(row.path.clone()));
        ui.close();
    }
    let planned_path = library_view_planned_destination_for(ctx.library_view_last_plan, &row.path);
    let copy_planned_button = ui.add_enabled(
        planned_path.is_some(),
        egui::Button::new("Copy planned view path"),
    );
    let copy_planned_button = if planned_path.is_some() {
        copy_planned_button
    } else {
        copy_planned_button
            .on_disabled_hover_text("Preview a Library View to see this archive's planned path.")
    };
    if let Some(path) = planned_path
        && copy_planned_button.clicked()
    {
        action = Some(RowContextMenuAction::CopyText(path.display().to_string()));
        ui.close();
    }

    action
}

/// The multi-selection row context menu. "Mount selected"/"Unmount
/// selected" reuse `MountState` filtering identical to
/// `pending_mount_items`/`pending_unmount_items` (only genuinely eligible
/// archives are ever included), and the caller executes them through
/// `start_mount_all`/`start_unmount_all` - the exact same batch engine
/// `Mount All`/`Unmount All` already use, never a second implementation.
fn show_bulk_row_context_menu(
    ui: &mut egui::Ui,
    selected_archives: &HashSet<PathBuf>,
    ctx: &RowMenuContext<'_>,
) -> Option<RowContextMenuAction> {
    let mut action = None;
    let selected_count = selected_archives.len();

    let mountable: Vec<PathBuf> = ctx
        .records
        .iter()
        .filter(|record| {
            selected_archives.contains(&record.mount_plan.archive.path)
                && record.is_mount_input()
                && matches!(
                    record.mount_state,
                    MountState::Pending | MountState::MountPathExists
                )
        })
        .map(|record| record.mount_plan.archive.path.clone())
        .collect();
    let unmountable: Vec<PathBuf> = ctx
        .records
        .iter()
        .filter(|record| {
            selected_archives.contains(&record.mount_plan.archive.path)
                && record.mount_state == MountState::Mounted
        })
        .map(|record| record.mount_plan.archive.path.clone())
        .collect();

    let mount_enabled = individual_actions_available(ctx.busy) && !mountable.is_empty();
    let mut mount_button = ui.add_enabled(
        mount_enabled,
        egui::Button::new(format!("Mount selected ({})", mountable.len())),
    );
    if !mount_enabled {
        mount_button = mount_button.on_disabled_hover_text(
            ctx.block_reason
                .unwrap_or("No selected archive is ready to mount."),
        );
    }
    if mount_button.clicked() {
        action = Some(RowContextMenuAction::MountSelected(mountable));
        ui.close();
    }

    let unmount_enabled = individual_actions_available(ctx.busy) && !unmountable.is_empty();
    let mut unmount_button = ui.add_enabled(
        unmount_enabled,
        egui::Button::new(format!("Unmount selected ({})", unmountable.len())),
    );
    if !unmount_enabled {
        unmount_button = unmount_button.on_disabled_hover_text(
            ctx.block_reason
                .unwrap_or("No selected archive is currently mounted."),
        );
    }
    if unmount_button.clicked() {
        action = Some(RowContextMenuAction::UnmountSelected);
        ui.close();
    }

    ui.separator();
    ui.add_enabled_ui(!ctx.platform_busy, |ui| {
        ui.menu_button("Set platform for selected", |ui| {
            for name in canonical_platform_names() {
                if ui.button(name).clicked() {
                    action = Some(RowContextMenuAction::BulkPlatform(
                        selected_archives.iter().cloned().collect(),
                        BulkPlatformActionKind::Set(name.to_string()),
                    ));
                    ui.close();
                }
            }
        });
    });

    ui.separator();
    if ui
        .button(format!("Copy selected archive paths ({selected_count})"))
        .clicked()
    {
        let mut paths: Vec<&PathBuf> = selected_archives.iter().collect();
        paths.sort();
        let text = paths
            .iter()
            .map(|path| path.display().to_string())
            .collect::<Vec<_>>()
            .join("\n");
        action = Some(RowContextMenuAction::CopyText(text));
        ui.close();
    }
    if ui.button("Clear selection").clicked() {
        action = Some(RowContextMenuAction::ClearSelection);
        ui.close();
    }

    action
}

/// One frame's outcome from `show_archive_rows`: the row clicked (existing
/// left-click/Ctrl-click handling, unchanged), plus at most one context-
/// menu action requested this frame (at most one menu can be open at a
/// time, so these can never conflict).
struct ArchiveRowsFrameResult {
    clicked: Option<(usize, bool)>,
    menu_action: Option<RowContextMenuAction>,
}

/// Renders one page of table rows. A row can be `multi_selected` (a member
/// of the exact `ArchiveRow::path` identity set), the single "focused" row
/// (`selected_index`), both, or neither - these are rendered as visually
/// distinct states (see `show_data_row`), not collapsed into one "is
/// selected" flag, so that Ctrl+Up/Down moving focus among an existing
/// multi-selection is still visible. Returns `Some((row_index, ctrl_held))`
/// for the row clicked this frame, if any - `ctrl_held` is read once, from
/// the same frame's input state every row in this call shares, so the
/// caller can distinguish an ordinary click (replace the selection) from a
/// Ctrl-click (toggle just this row) without this function needing to know
/// anything about selection semantics itself.
///
/// `widths` (added for resizable columns) pushes this one parameter past
/// clippy's default threshold - see `show_data_row`'s identical
/// justification.
#[allow(clippy::too_many_arguments)]
fn show_archive_rows(
    ui: &mut egui::Ui,
    rows: &[ArchiveRow],
    filtered_rows: Option<&[usize]>,
    row_range: Range<usize>,
    row_height: f32,
    selected_index: Option<usize>,
    selected_archives: &mut HashSet<PathBuf>,
    selected_archive: &mut Option<PathBuf>,
    widths: &[f32; 4],
    menu_context: &RowMenuContext<'_>,
) -> ArchiveRowsFrameResult {
    let mut clicked = None;
    let mut menu_action = None;
    let visuals = ui.visuals().clone();
    let ctrl_held = ui.input(|input| input.modifiers.ctrl);
    for visible_index in row_range {
        let row_index = filtered_rows
            .map(|indices| indices[visible_index])
            .unwrap_or(visible_index);
        let row = &rows[row_index];
        let cells = [
            row.platform.as_str(),
            row.state.as_str(),
            row.archive_path.as_str(),
            row.mount_path.as_str(),
        ];
        let is_multi_selected = selected_archives.contains(&row.path);
        let is_focused = selected_index == Some(row_index);
        let response = show_data_row(
            ui,
            &cells,
            row_height,
            &row.path,
            is_multi_selected,
            is_focused,
            row.row_text_color(&visuals),
            widths,
        );
        if response.clicked() {
            clicked = Some((row_index, ctrl_held));
        }
        if response.secondary_clicked() {
            apply_row_right_click(selected_archives, selected_archive, row.path.clone());
        }
        let selected_ref: &HashSet<PathBuf> = selected_archives;
        response.context_menu(|ui| {
            if let Some(requested) = show_row_context_menu(ui, row, selected_ref, menu_context) {
                menu_action = Some(requested);
            }
        });
    }
    ArchiveRowsFrameResult {
        clicked,
        menu_action,
    }
}

fn selected_record<'a>(
    records: &'a [ArchiveRecord],
    selected_archive: Option<&Path>,
) -> Option<&'a ArchiveRecord> {
    selected_record_index(records, selected_archive).map(|index| &records[index])
}

fn selected_record_index(
    records: &[ArchiveRecord],
    selected_archive: Option<&Path>,
) -> Option<usize> {
    let selected_archive = selected_archive?;
    records
        .iter()
        .position(|record| record.mount_plan.archive.path == selected_archive)
}

/// Like `selected_record_index`, but over the merged live+cache row list
/// via each row's exact-byte `path` identity - never a lossy display
/// string (requirement 5). Used to drive table-row highlighting for both
/// live and cache-only rows; selecting a cache-only row still leaves
/// `selected_record` (which only searches live records) returning `None`,
/// so no action button is ever offered for it.
fn selected_row_index(rows: &[ArchiveRow], selected_archive: Option<&Path>) -> Option<usize> {
    let selected_archive = selected_archive?;
    rows.iter().position(|row| row.path == selected_archive)
}

/// Applies one row click to the selection state - requirement 2's exact
/// semantics. An ordinary click (`ctrl_held = false`) replaces the whole
/// multi-selection with just `path`; a Ctrl-click toggles only `path`,
/// leaving every other currently-selected row untouched. Either way,
/// `selected_archive` (the details panel's "focused" row) becomes
/// `path`. Factored out from `show_loaded_data`'s row-click handling so
/// it is directly testable without an `egui::Ui`.
fn apply_row_click(
    selected_archives: &mut HashSet<PathBuf>,
    selected_archive: &mut Option<PathBuf>,
    path: PathBuf,
    ctrl_held: bool,
) {
    if ctrl_held {
        if !selected_archives.remove(&path) {
            selected_archives.insert(path.clone());
        }
    } else {
        selected_archives.clear();
        selected_archives.insert(path.clone());
    }
    *selected_archive = Some(path);
}

/// Whether the compact bulk platform action bar should be shown -
/// requirement 3: only when more than one row is selected. Factored out
/// as its own pure predicate (mirroring `mount_all_available`) so the
/// condition is directly testable without an `egui::Ui`.
fn bulk_action_bar_visible(selected_archives: &HashSet<PathBuf>) -> bool {
    selected_archives.len() > 1
}

/// Whether "Select all visible" should be enabled - requirement 6:
/// disabled whenever the current search/filters leave zero library rows
/// visible. Factored out as its own pure predicate (mirroring
/// `mount_all_available`/`bulk_action_bar_visible`) so it is directly
/// testable without an `egui::Ui`.
fn select_all_visible_button_enabled(visible_count: usize) -> bool {
    visible_count > 0
}
fn selection_status_text(selected_count: usize) -> String {
    match selected_count {
        0 => "No archives selected".to_string(),
        1 => "1 archive selected".to_string(),
        n => format!("{n} archives selected"),
    }
}

/// Renders the "Showing X of Y archives" / selection-status / "Select all
/// visible" row - the ordinary-library selection controls that sit above
/// the table, next to the always-visible `selection_status_text` label
/// (see that function's doc comment) and near the bulk action bar's
/// "Clear selected"/"Clear selection" (`show_bulk_platform_action_bar`).
/// Factored out from `show_loaded_data` (mirroring
/// `show_bulk_platform_action_bar`) so it can be rendered and click-tested
/// standalone.
///
/// v0.4.2-alpha follow-up requirement: "Select all visible" is a
/// mouse-only equivalent of Ctrl+A. It calls `select_all_visible` with
/// this same frame's own `merged_rows`/`visible_indices` - the exact same
/// helper and inputs the Ctrl+A handler in `show_loaded_data` dispatches
/// to - so there is no second selection implementation to drift out of
/// sync with search/filters/sort. Disabled whenever zero rows are
/// currently visible; clicking it while every visible row is already
/// selected is a no-op rebuild of the identical `HashSet`.
fn show_selection_controls_row(
    ui: &mut egui::Ui,
    merged_rows: &[ArchiveRow],
    visible_indices: &[usize],
    selected_archives: &mut HashSet<PathBuf>,
) {
    let visible_count = visible_indices.len();
    ui.horizontal(|ui| {
        ui.label(format!(
            "Showing {} of {} archives",
            visible_count,
            merged_rows.len()
        ));
        ui.separator();
        ui.label(selection_status_text(selected_archives.len()));
        ui.separator();
        if ui
            .add_enabled(
                select_all_visible_button_enabled(visible_count),
                egui::Button::new("Select all visible"),
            )
            .clicked()
        {
            *selected_archives = select_all_visible(merged_rows, visible_indices);
        }
    });
}

const EMPTY_LIBRARY_MESSAGE: &str =
    "No archives in the library yet. Scan a source folder to add archives.";
const ZERO_FILTER_RESULTS_MESSAGE: &str = "No archives match the current search and filters.";

/// Requirement 4: distinguishes "the library itself has no archives at
/// all" from "the library has archives, but the current search/filters
/// hide every one of them" - factored out as its own pure predicate
/// (mirroring `bulk_action_bar_visible`) so the choice of message is
/// directly testable without an `egui::Ui`, and so the table is never
/// left rendering as an unexplained blank area.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum LibraryTableMessage {
    EmptyLibrary,
    NoFilterResults,
    NoCompletedScan,
    NoRecentAdditions,
}

fn library_table_message(
    merged_rows_is_empty: bool,
    visible_count: usize,
) -> Option<LibraryTableMessage> {
    if merged_rows_is_empty {
        Some(LibraryTableMessage::EmptyLibrary)
    } else if visible_count == 0 {
        Some(LibraryTableMessage::NoFilterResults)
    } else {
        None
    }
}
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum SortField {
    Platform,
    State,
    ArchivePath,
    MountPath,
}

const COLUMN_SORT_FIELDS: [SortField; 4] = [
    SortField::Platform,
    SortField::State,
    SortField::ArchivePath,
    SortField::MountPath,
];

fn sort_field_key(row: &ArchiveRow, field: SortField) -> &str {
    match field {
        SortField::Platform => &row.platform,
        SortField::State => &row.state,
        SortField::ArchivePath => &row.archive_path,
        SortField::MountPath => &row.mount_path,
    }
}

/// Sorts `indices` (a filtered view into `merged_rows`, never the rows
/// themselves - requirement 2: "must not mutate database order or
/// archive identity") by the chosen column. `Vec::sort_by` is a stable
/// sort, and the exact `ArchiveRow::path` is always the final
/// tie-breaker (in fixed ascending order, independent of `ascending`, so
/// ties resolve identically either direction) - together these make the
/// result fully deterministic regardless of `merged_rows`'s incoming
/// order.
fn sort_visible_indices(
    merged_rows: &[ArchiveRow],
    indices: &mut [usize],
    field: SortField,
    ascending: bool,
) {
    indices.sort_by(|&left, &right| {
        let left_row = &merged_rows[left];
        let right_row = &merged_rows[right];
        let primary = sort_field_key(left_row, field).cmp(sort_field_key(right_row, field));
        let primary = if ascending {
            primary
        } else {
            primary.reverse()
        };
        primary.then_with(|| left_row.path.cmp(&right_row.path))
    });
}

/// Applies one header click to the current sort state - requirement 2:
/// clicking a new column selects it (starting ascending); clicking the
/// already-active column toggles its direction. Factored out from
/// `show_loaded_data` so this decision is directly testable without an
/// `egui::Ui`.
fn apply_header_click(
    sort_field: &mut Option<SortField>,
    sort_ascending: &mut bool,
    clicked_field: SortField,
) {
    if *sort_field == Some(clicked_field) {
        *sort_ascending = !*sort_ascending;
    } else {
        *sort_field = Some(clicked_field);
        *sort_ascending = true;
    }
}

/// Requirement 1: Ctrl+A must select exactly the archives currently
/// visible after filters are applied - never a hidden/filtered-out row.
/// Paths are cloned directly out of `merged_rows` at the positions
/// `visible_indices` names, computed fresh this same frame, so this can
/// never select against a stale filter/sort state from an earlier frame.
fn select_all_visible(merged_rows: &[ArchiveRow], visible_indices: &[usize]) -> HashSet<PathBuf> {
    visible_indices
        .iter()
        .map(|&index| merged_rows[index].path.clone())
        .collect()
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ArrowDirection {
    Up,
    Down,
}

/// Requirement 1: computes the next focused archive for Up/Down,
/// stepping strictly through `visible_indices` - the exact filtered *and
/// sorted* order currently on screen - by searching for the current
/// focus's exact path rather than trusting any previously-computed row
/// index. A raw index saved from an earlier frame can be invalidated by
/// a filter or sort change between frames; re-deriving the position from
/// `current_focus`'s `PathBuf` identity every call means there is no
/// stale index to go stale. Clamps at either end rather than wrapping.
fn next_focus_in_visible_order(
    merged_rows: &[ArchiveRow],
    visible_indices: &[usize],
    current_focus: Option<&Path>,
    direction: ArrowDirection,
) -> Option<PathBuf> {
    if visible_indices.is_empty() {
        return None;
    }
    let current_pos = current_focus.and_then(|path| {
        visible_indices
            .iter()
            .position(|&index| merged_rows[index].path == path)
    });
    let next_pos = match (current_pos, direction) {
        (Some(pos), ArrowDirection::Down) => (pos + 1).min(visible_indices.len() - 1),
        (Some(pos), ArrowDirection::Up) => pos.saturating_sub(1),
        (None, _) => 0,
    };
    Some(merged_rows[visible_indices[next_pos]].path.clone())
}
fn apply_arrow_focus_change(
    selected_archives: &mut HashSet<PathBuf>,
    selected_archive: &mut Option<PathBuf>,
    new_focus: PathBuf,
    ctrl_held: bool,
) {
    if !ctrl_held {
        selected_archives.clear();
        selected_archives.insert(new_focus.clone());
    }
    *selected_archive = Some(new_focus);
}

/// Auto-scroll fix for Ctrl+Up/Down: computes the vertical `ScrollArea`
/// offset needed to bring the row at visible position `focus_pos` (rows
/// `row_stride` pixels apart) into view, given the scroll area's
/// `current_offset` (its own offset as of the end of the previous frame)
/// and `viewport_height`. Performs the smallest scroll that satisfies
/// this: if the row is already fully within
/// `current_offset..current_offset + viewport_height`, `current_offset` is
/// returned unchanged (no jump on every keypress); otherwise the offset is
/// clamped to align the row to whichever edge it just crossed.
fn compute_scroll_offset_for_focus(
    focus_pos: usize,
    row_stride: f32,
    current_offset: f32,
    viewport_height: f32,
) -> f32 {
    let row_top = focus_pos as f32 * row_stride;
    let row_bottom = row_top + row_stride;
    if row_top < current_offset {
        row_top
    } else if row_bottom > current_offset + viewport_height {
        (row_bottom - viewport_height).max(0.0)
    } else {
        current_offset
    }
}

/// Requirement 1's last bullet: keyboard shortcuts (Escape, Ctrl+A,
/// arrow navigation) must not fire while a text field or `ComboBox` is
/// actively receiving keyboard input. `mem.focused()` is `Some` exactly
/// when a widget (a `TextEdit`'s cursor, for example) currently holds
/// keyboard focus; `Popup::is_any_open` additionally covers an open
/// `ComboBox` dropdown, which does not itself hold "focus" in that sense
/// but should equally suppress these shortcuts while its own keyboard
/// navigation is active.
fn keyboard_shortcuts_blocked_by_focus(ctx: &egui::Context) -> bool {
    ctx.memory(|memory| memory.focused().is_some()) || egui::Popup::is_any_open(ctx)
}

/// The persisted database row backing the selected archive, if the
/// library database knows about it - live or cache-only alike, unlike
/// `selected_record` (live only). This is what makes manual platform
/// assignment available for a cache-only/missing row: it is metadata
/// only, never a mount action, so it does not need `selected_record`'s
/// live-only restriction. Matches by exact path bytes (`PersistedArchive::absolute_path`),
/// never a lossy display string.
fn selected_persisted_archive<'a>(
    cached: Option<&'a CachedLibrarySnapshot>,
    selected_archive: Option<&Path>,
) -> Option<&'a PersistedArchive> {
    let selected_archive = selected_archive?;
    cached?
        .archives
        .iter()
        .find(|persisted| persisted.absolute_path == selected_archive)
}

fn selected_platform_details<'a>(
    cached: Option<&'a CachedLibrarySnapshot>,
    persisted: Option<&PersistedArchive>,
) -> Option<&'a PlatformProvenanceDetails> {
    cached?.platform_details.get(&persisted?.id)
}

/// Resolves the platform text a "Set Platform" click should apply:
/// `platform_custom_text` (trimmed, rejecting empty) when
/// `CUSTOM_PLATFORM_CHOICE` is selected, otherwise the selected
/// canonical name directly. `None` means nothing valid to apply yet
/// (no selection, or an empty custom field) - the caller uses this to
/// keep "Set Platform" disabled.
fn resolved_platform_choice<'a>(choice: Option<&'a str>, custom_text: &'a str) -> Option<&'a str> {
    match choice {
        Some(CUSTOM_PLATFORM_CHOICE) => {
            let trimmed = custom_text.trim();
            (!trimmed.is_empty()).then_some(trimmed)
        }
        Some(name) => Some(name),
        None => None,
    }
}

fn available_action(mount_state: MountState) -> ArchiveAction {
    match mount_state {
        MountState::Mounted => ArchiveAction::Unmount,
        MountState::Pending | MountState::MountPathExists | MountState::NotMountable => {
            ArchiveAction::Mount
        }
    }
}

fn individual_actions_available(busy: bool) -> bool {
    !busy
}

fn confirmation_actions_available(busy: bool) -> bool {
    individual_actions_available(busy)
}

fn record_recovery_activity(
    history: &mut OperationHistory,
    action: ActivityAction,
    archive_path: &Path,
    outcome: ActivityOutcome,
    message: &'static str,
) {
    history.record(HistoryEntry::new(
        action,
        Some(archive_path.to_path_buf()),
        outcome,
        message,
    ));
}

fn advance_to_final_lazy_confirmation(
    warning_confirmation: &mut Option<PathBuf>,
    final_confirmation: &mut Option<PathBuf>,
    focus_final_cancel: &mut bool,
    archive_path: &Path,
) {
    *final_confirmation = Some(archive_path.to_path_buf());
    *warning_confirmation = None;
    *focus_final_cancel = true;
}

fn lazy_confirmation_available(
    confirmed_archive: &Path,
    offered_archives: &HashSet<PathBuf>,
    busy: bool,
) -> bool {
    !busy && offered_archives.contains(confirmed_archive)
}

fn lazy_unmount_available(
    record: &ArchiveRecord,
    offered_archives: &HashSet<PathBuf>,
    busy: bool,
) -> bool {
    !busy
        && record.mount_state == MountState::Mounted
        && offered_archives.contains(&record.mount_plan.archive.path)
}

fn remount_available(
    record: &ArchiveRecord,
    offered_archives: &HashSet<PathBuf>,
    busy: bool,
) -> bool {
    !busy
        && record.mount_state != MountState::Mounted
        && offered_archives.contains(&record.mount_plan.archive.path)
}

fn remount_is_offered(record: &ArchiveRecord, offered_archives: &HashSet<PathBuf>) -> bool {
    record.mount_state != MountState::Mounted
        && offered_archives.contains(&record.mount_plan.archive.path)
}

struct SelectedArchiveViewState<'a> {
    operation: Option<&'a RunningOperation>,
    busy: bool,
    block_reason: Option<&'static str>,
    action_readiness_debug_lines: &'a [String],
    confirm_unmount: &'a mut Option<PathBuf>,
    confirm_lazy_unmount: &'a mut Option<PathBuf>,
    focus_lazy_cancel: &'a mut bool,
    lazy_unmount_offers: &'a HashSet<PathBuf>,
    remount_offers: &'a HashSet<PathBuf>,
    cleanup_after_unmount: &'a mut bool,
    platform_choice: &'a mut Option<String>,
    platform_custom_text: &'a mut String,
    platform_busy: bool,
    clipboard: &'a mut dyn ClipboardBackend,
}

#[derive(Default)]
struct SelectedArchiveActions {
    operation: Option<OperationRequest>,
    platform: Option<(PathBuf, PlatformAction)>,
    inspect: Option<PathBuf>,
    cheats_mods: Option<PathBuf>,
}

fn show_selected_archive(
    ui: &mut egui::Ui,
    record: Option<&ArchiveRecord>,
    persisted: Option<&PersistedArchive>,
    platform_details: Option<&PlatformProvenanceDetails>,
    source_path: Option<&Path>,
    view_state: SelectedArchiveViewState<'_>,
) -> SelectedArchiveActions {
    let SelectedArchiveViewState {
        operation,
        busy,
        block_reason,
        action_readiness_debug_lines,
        confirm_unmount,
        confirm_lazy_unmount,
        focus_lazy_cancel,
        lazy_unmount_offers,
        remount_offers,
        cleanup_after_unmount,
        platform_choice,
        platform_custom_text,
        platform_busy,
        clipboard,
    } = view_state;
    let mut request = None;
    let mut platform_request = None;
    let mut inspect_request = None;
    let mut cheats_mods_request = None;
    widgets::card(ui, |ui| {
        widgets::section_header(
            ui,
            "Selected archive",
            Some("Inspect identity, mount state, health, and metadata for the focused row."),
        );
        if record.is_none() && persisted.is_none() {
            ui.label("Select an archive row to view details.");
            return;
        }

        let Some(record) = record else {
            if let Some(persisted) = persisted {
                let archive_path_text = persisted.absolute_path.display().to_string();
                if widgets::copyable_value(ui, "Archive path", &archive_path_text) {
                    let _ = clipboard.set_text(archive_path_text.clone());
                }
                let source_text = source_path
                    .map(|path| path.display().to_string())
                    .unwrap_or_else(|| "Unassigned / Legacy".to_string());
                ui.label(format!("Source: {source_text}"));
                if persisted.last_verified_missing_at.is_some() {
                    ui.colored_label(
                        ui.visuals().error_fg_color,
                        "Status: Missing from the latest successful source-folder scan",
                    );
                    ui.label(format!("Last seen: {}", persisted.last_seen_at));
                }
                ui.label(
                    "Known to the library database, not confirmed by the latest live snapshot. \
                     Mount/unmount actions are unavailable until it is - platform assignment \
                     below is metadata only and unaffected.",
                );
                if ui
                    .add_enabled(
                        is_inspectable(&persisted.absolute_path),
                        egui::Button::new("Inspect contents"),
                    )
                    .on_hover_text(
                        "Read-only: view this archive's internal entries without extracting them.",
                    )
                    .clicked()
                {
                    inspect_request = Some(persisted.absolute_path.clone());
                }
            }
            let action = show_platform_section(
                ui,
                persisted,
                platform_details,
                platform_choice,
                platform_custom_text,
                platform_busy,
                clipboard,
            );
            if let (Some(persisted), Some(action)) = (persisted, action) {
                platform_request = Some((persisted.absolute_path.clone(), action));
            }
            return;
        };

        egui::Grid::new("selected_archive_details")
            .num_columns(2)
            .striped(true)
            .show(ui, |ui| {
                detail_row_with_copy(
                    ui,
                    "Archive path",
                    &record.mount_plan.archive.path.display().to_string(),
                    clipboard,
                );
                detail_row_with_copy(
                    ui,
                    "Mount path",
                    &record.mount_plan.mount_path.display().to_string(),
                    clipboard,
                );
                detail_row_with_copy(
                    ui,
                    "Source",
                    &source_path
                        .map(|path| path.display().to_string())
                        .unwrap_or_else(|| "Unassigned / Legacy".to_string()),
                    clipboard,
                );
                detail_row(
                    ui,
                    "Platform",
                    record
                        .metadata
                        .platform
                        .as_deref()
                        .or(record.identity.platform.as_deref())
                        .unwrap_or("Unknown"),
                );
                detail_row(
                    ui,
                    "Archive format",
                    archive_kind_name(record.mount_plan.archive.kind),
                );
                detail_row(ui, "Size", &format_size(record.identity.size_bytes));
                detail_row(ui, "Mount state", &record.mount_state.to_string());
                detail_row(ui, "Health", &record.health.to_string());
                optional_detail_row(ui, "Title", record.metadata.title.as_deref());
                optional_detail_row(ui, "Region", record.metadata.region.as_deref());
                optional_detail_row(ui, "Version", record.metadata.version.as_deref());
                optional_detail_row(ui, "Disc", record.metadata.disc.as_deref());
                optional_detail_row(ui, "Publisher", record.metadata.publisher.as_deref());
                optional_detail_row(ui, "Developer", record.metadata.developer.as_deref());
                optional_detail_row(ui, "Genre", record.metadata.genre.as_deref());
                optional_detail_row(ui, "Notes", record.metadata.notes.as_deref());
                optional_detail_row(ui, "Metadata source", record.metadata.source.as_deref());
                if let Some(year) = record.metadata.release_year {
                    detail_row(ui, "Release year", &year.to_string());
                }
                if let Some(languages) = &record.metadata.languages {
                    detail_row(ui, "Languages", &languages.join(", "));
                }
            });

        ui.add_space(6.0);
        let can_lazy_unmount = lazy_unmount_available(record, lazy_unmount_offers, busy);
        let remount_offered = remount_is_offered(record, remount_offers);
        let action = if remount_offered {
            ArchiveAction::Remount
        } else {
            available_action(record.mount_state)
        };
        ui.strong("Options");
        ui.horizontal_wrapped(|ui| {
            if ui
                .add_enabled(
                    is_inspectable(&record.mount_plan.archive.path),
                    egui::Button::new("Inspect contents"),
                )
                .on_hover_text(
                    "Read-only: view this archive's internal entries without extracting them.",
                )
                .clicked()
            {
                inspect_request = Some(record.mount_plan.archive.path.clone());
            }
            if widgets::action_button(ui, "Cheats & Mods", widgets::ActionStyle::Secondary, true)
                .clicked()
            {
                cheats_mods_request = Some(record.mount_plan.archive.path.clone());
            }
        });
        if !record.is_mount_input() {
            widgets::banner(
                ui,
                "No mount required",
                "Loose ROM · no ArchiveFS mount required. Inspect, Cheats & Mods, copy-path, and library metadata actions remain available.",
                widgets::StatusTone::Info,
            );
            return;
        }
        ui.add_enabled_ui(!busy, |ui| {
            ui.checkbox(
                cleanup_after_unmount,
                "Clean empty mount directories after unmount",
            );
        });
        ui.add_space(4.0);
        if remount_offered {
            ui.colored_label(egui::Color32::from_rgb(210, 140, 40), REMOUNT_GUIDANCE);
        }
        let label = match action {
            ArchiveAction::Mount => "Mount",
            ArchiveAction::Unmount => "Unmount",
            ArchiveAction::LazyUnmount => "Lazy Unmount",
            ArchiveAction::Remount => "Remount",
        };
        let primary_enabled = match action {
            ArchiveAction::Remount => remount_available(record, remount_offers, busy),
            ArchiveAction::Mount | ArchiveAction::Unmount | ArchiveAction::LazyUnmount => {
                individual_actions_available(busy)
            }
        };
        ui.horizontal(|ui| {
            let mut button = ui.add_enabled(primary_enabled, egui::Button::new(label));
            if !primary_enabled && let Some(reason) = block_reason {
                button = button.on_disabled_hover_text(reason);
            }
            if button.clicked() {
                let archive_path = record.mount_plan.archive.path.clone();
                match action {
                    ArchiveAction::Mount => {
                        request = Some(OperationRequest {
                            action,
                            archive_path,
                            cleanup_after_unmount: false,
                        })
                    }
                    ArchiveAction::Unmount => *confirm_unmount = Some(archive_path),
                    ArchiveAction::LazyUnmount => unreachable!("lazy unmount uses recovery button"),
                    ArchiveAction::Remount => {
                        request = Some(OperationRequest {
                            action,
                            archive_path,
                            cleanup_after_unmount: false,
                        })
                    }
                }
            }
            if can_lazy_unmount
                && ui
                    .add(egui::Button::new("Lazy Unmount"))
                    .on_hover_text(
                        "Emergency recovery option available because normal unmount failed.",
                    )
                    .clicked()
            {
                *confirm_lazy_unmount = Some(record.mount_plan.archive.path.clone());
                *focus_lazy_cancel = true;
            }
            if let Some(operation) = operation {
                ui.spinner();
                ui.label(match operation.action {
                    ArchiveAction::Mount => "Mounting...",
                    ArchiveAction::Unmount => "Unmounting...",
                    ArchiveAction::LazyUnmount => "Lazy unmounting...",
                    ArchiveAction::Remount => "Remounting...",
                });
            }
        });
        if !primary_enabled && let Some(reason) = block_reason {
            ui.colored_label(ui.visuals().weak_text_color(), reason);
        }
        // Always present (not just when blocked) so its mere presence
        // proves the running binary actually contains this code - see
        // `action_readiness_debug_lines`'s doc comment for why this exists
        // (the "Doctor: Ready" summary above can legitimately disagree
        // with this gate, and previously gave no way to see why).
        egui::CollapsingHeader::new("Debug: action readiness")
            .default_open(false)
            .show(ui, |ui| {
                for line in action_readiness_debug_lines {
                    ui.label(line);
                }
            });

        let action = show_platform_section(
            ui,
            persisted,
            platform_details,
            platform_choice,
            platform_custom_text,
            platform_busy,
            clipboard,
        );
        if let Some(action) = action {
            platform_request = Some((record.mount_plan.archive.path.clone(), action));
        }
    });
    SelectedArchiveActions {
        operation: request,
        platform: platform_request,
        inspect: inspect_request,
        cheats_mods: cheats_mods_request,
    }
}

/// Renders the "Set platform" / "Clear manual platform" controls tucked
/// into the selected-archive details - available whenever `persisted` is
/// `Some` (the library database knows this archive), live or cache-only
/// row alike, since this is metadata only, never a mount action (see
/// `show_selected_archive`'s two call sites above). Uses
/// `canonical_platform_names` (the same central list the CLI's
/// `library-set-platform` validates against - never a second,
/// independently-drifting list here), with `CUSTOM_PLATFORM_CHOICE` as
/// the escape hatch for a platform not in that list, mirroring the CLI's
/// `--custom` flag.
fn show_platform_section(
    ui: &mut egui::Ui,
    persisted: Option<&PersistedArchive>,
    platform_details: Option<&PlatformProvenanceDetails>,
    platform_choice: &mut Option<String>,
    platform_custom_text: &mut String,
    platform_busy: bool,
    clipboard: &mut dyn ClipboardBackend,
) -> Option<PlatformAction> {
    ui.add_space(6.0);
    ui.separator();
    ui.strong("Platform");
    let Some(persisted) = persisted else {
        ui.label(
            "Not yet in the library database. Run a library scan to enable platform assignment.",
        );
        return None;
    };

    let fallback_details;
    let details = if let Some(details) = platform_details {
        details
    } else {
        fallback_details = PlatformProvenanceDetails {
            platform: persisted.platform.clone(),
            source: persisted.platform_source.clone(),
            matched_component: None,
            automatic_fallback: None,
        };
        &fallback_details
    };
    for (label, value) in platform_provenance_lines(details) {
        ui.label(format!("{label}: {value}"));
    }
    if details.platform.is_none() {
        widgets::banner(
            ui,
            "Why is this Unknown?",
            UNKNOWN_PLATFORM_EXPLANATION,
            widgets::StatusTone::Info,
        );
    }
    ui.horizontal(|ui| {
        egui::ComboBox::from_id_salt("platform_choice_combo")
            .selected_text(platform_choice.as_deref().unwrap_or("Select platform..."))
            .show_ui(ui, |ui| {
                for name in canonical_platform_names() {
                    ui.selectable_value(platform_choice, Some(name.to_string()), name);
                }
                ui.selectable_value(
                    platform_choice,
                    Some(CUSTOM_PLATFORM_CHOICE.to_string()),
                    CUSTOM_PLATFORM_CHOICE,
                );
            });
        if platform_choice.as_deref() == Some(CUSTOM_PLATFORM_CHOICE) {
            show_text_edit_with_context_menu(ui, platform_custom_text, clipboard, |text_edit| {
                text_edit
            });
        }
    });
    let resolved = resolved_platform_choice(platform_choice.as_deref(), platform_custom_text)
        .map(str::to_string);
    let mut platform_request = None;
    ui.horizontal(|ui| {
        if ui
            .add_enabled(
                !platform_busy && resolved.is_some(),
                egui::Button::new("Set Platform"),
            )
            .clicked()
            && let Some(platform) = resolved
        {
            platform_request = Some(PlatformAction::Set(platform));
        }
        if persisted.platform_source.as_deref() == Some(MANUAL_PLATFORM_SOURCE)
            && ui
                .add_enabled(!platform_busy, egui::Button::new("Clear Manual Platform"))
                .clicked()
        {
            platform_request = Some(PlatformAction::Clear);
        }
        if platform_busy {
            ui.spinner();
            ui.label("Updating platform...");
        }
    });
    platform_request
}

/// Renders the compact bulk platform action bar - shown only when more
/// than one row is selected (requirement 3): a single selected row
/// already has its own platform picker in the details panel
/// (`show_platform_section`), and showing both for one row would be
/// redundant and ambiguous about which one actually applies. Uses
/// `canonical_platform_names()` (the same central list
/// `show_platform_section`/the CLI validate against) with no free-form
/// custom-text escape hatch - deliberately narrower than the single-row
/// picker, matching the bulk feature's "simple by default" scope
/// (requirement 4).
/// Renders the compact bulk platform action bar - shown only when more
/// than one row is selected (requirement 3): a single selected row
/// already has its own platform picker in the details panel
/// (`show_platform_section`), and showing both for one row would be
/// redundant and ambiguous about which one actually applies. Uses
/// `canonical_platform_names()` (the same central list
/// `show_platform_section`/the CLI validate against) with no free-form
/// custom-text escape hatch - deliberately narrower than the single-row
/// picker, matching the bulk feature's "simple by default" scope
/// (requirement 4).
///
/// Takes `selected_archives` by `&mut` - not because this function
/// starts any database write itself (it only ever returns the requested
/// `BulkPlatformActionKind` for the caller to dispatch asynchronously,
/// exactly as before), but because "Clear selection" is a purely local,
/// synchronous UI action with nothing to dispatch: it just empties the
/// *same* `HashSet` `show_archive_rows` highlights rows from, directly.
fn show_bulk_platform_action_bar(
    ui: &mut egui::Ui,
    selected_archives: &mut HashSet<PathBuf>,
    bulk_platform_choice: &mut Option<String>,
    bulk_platform_busy: bool,
) -> Option<BulkPlatformActionKind> {
    if !bulk_action_bar_visible(selected_archives) {
        return None;
    }

    let mut action = None;
    egui::Frame::group(ui.style())
        .fill(ui.visuals().extreme_bg_color)
        .show(ui, |ui| {
            ui.strong(format!("{} archives selected", selected_archives.len()));
            ui.horizontal(|ui| {
                ui.label("Platform:");
                egui::ComboBox::from_id_salt("bulk_platform_choice_combo")
                    .selected_text(
                        bulk_platform_choice
                            .as_deref()
                            .unwrap_or("Select platform..."),
                    )
                    .show_ui(ui, |ui| {
                        for name in canonical_platform_names() {
                            ui.selectable_value(bulk_platform_choice, Some(name.to_string()), name);
                        }
                    });
                if ui
                    .add_enabled(
                        !bulk_platform_busy && bulk_platform_choice.is_some(),
                        egui::Button::new("Set selected"),
                    )
                    .clicked()
                    && let Some(platform) = bulk_platform_choice.clone()
                {
                    action = Some(BulkPlatformActionKind::Set(platform));
                }
                if ui
                    .add_enabled(!bulk_platform_busy, egui::Button::new("Clear selected"))
                    .clicked()
                {
                    action = Some(BulkPlatformActionKind::Clear);
                }
                if ui.button("Clear selection").clicked() {
                    selected_archives.clear();
                }
                if bulk_platform_busy {
                    ui.spinner();
                    ui.label("Updating...");
                }
            });
        });
    ui.add_space(4.0);
    action
}
#[derive(Debug, Clone, PartialEq, Eq)]
enum ClipboardTextStatus {
    /// Usable, non-empty text is available to paste.
    Ready(String),
    /// The clipboard was reachable and read successfully, but has no
    /// text (empty, or holds a non-text format such as an image).
    Empty,
    /// The clipboard backend could not be reached at all, or the read
    /// itself failed for a reason other than "no text".
    Unavailable(String),
}

/// Clipboard access, isolated behind one small trait so the production
/// path (the real OS clipboard) and tests (a deterministic in-memory
/// stand-in) share every byte of the actual Cut/Copy/Paste logic above
/// it. Neither egui nor eframe exposes a way to read or write the
/// clipboard *synchronously*, at the moment a context-menu item is
/// clicked - `ViewportCommand::RequestPaste`/`RequestCopy`/`RequestCut`
/// are the only public hooks, and they are asynchronous round-trips
/// through eframe's platform backend that (per live testing) cannot be
/// relied on to land back on the field the user actually clicked. Direct
/// clipboard access was explicitly permitted for exactly this case.
trait ClipboardBackend {
    fn get_text_status(&mut self) -> ClipboardTextStatus;
    /// `Err` carries a short, safe error summary - never the text that
    /// failed to be written.
    fn set_text(&mut self, text: String) -> Result<(), String>;
}
fn clipboard_environment_summary() -> String {
    let session_type = std::env::var("XDG_SESSION_TYPE").unwrap_or_else(|_| "unset".to_string());
    let display = if std::env::var_os("DISPLAY").is_some() {
        "present"
    } else {
        "absent"
    };
    let wayland_display = if std::env::var_os("WAYLAND_DISPLAY").is_some() {
        "present"
    } else {
        "absent"
    };
    format!("XDG_SESSION_TYPE={session_type} DISPLAY={display} WAYLAND_DISPLAY={wayland_display}")
}

/// The real OS clipboard via `arboard` - the same crate eframe's own
/// "clipboard" feature already links in transitively (see
/// `egui-winit`'s `Clipboard`, which every keyboard Ctrl+X/C/V in this
/// app already goes through); this only opens a second, independent
/// handle to the identical native mechanism; it does not add a
/// competing implementation. `archivefs-gui`'s own `Cargo.toml` enables
/// arboard's `wayland-data-control` feature explicitly - without it,
/// arboard's Linux backend is unconditionally X11 regardless of session
/// type (confirmed by reading arboard's own source), which is exactly
/// why Paste failed to see text copied from a native-Wayland Firefox on
/// the real Nobara session this was live-tested against.
///
/// Constructed once and kept for the app's entire lifetime (see
/// `ArchiveFsApp::clipboard`), never per-click: on X11, the application
/// that last copied something must keep its clipboard connection alive
/// to serve paste requests from other apps, so recreating and dropping a
/// connection on every click risks silently discarding what was just
/// copied.
///
/// `inner` is `None` if the platform clipboard could not be reached at
/// all (headless environment, no display server, etc.) - `init_error`
/// then holds *why*, so a broken clipboard is never silently reported as
/// merely empty. Every operation safely reports `Unavailable` instead of
/// panicking. Diagnostics (the environment summary, whether init
/// succeeded, and the exact init error if it failed) are printed to
/// stderr exactly once, at construction - never on every frame, and
/// never including clipboard content.
struct NativeClipboard {
    inner: Option<arboard::Clipboard>,
    init_error: Option<String>,
    /// The last `Unavailable` reason actually printed to stderr, so a
    /// repeated identical failure (e.g. the context menu re-checking
    /// Paste's enabled state on every frame it stays open) is logged
    /// once, not every frame - while a *new* or *changed* failure is
    /// still always visible.
    last_logged_error: Option<String>,
}

impl NativeClipboard {
    fn new() -> Self {
        eprintln!(
            "archivefs-gui: clipboard environment: {}",
            clipboard_environment_summary()
        );
        match arboard::Clipboard::new() {
            Ok(clipboard) => {
                eprintln!("archivefs-gui: clipboard backend initialised");
                Self {
                    inner: Some(clipboard),
                    init_error: None,
                    last_logged_error: None,
                }
            }
            Err(error) => {
                let message = error.to_string();
                eprintln!("archivefs-gui: clipboard backend initialisation failed: {message}");
                Self {
                    inner: None,
                    init_error: Some(message),
                    last_logged_error: None,
                }
            }
        }
    }

    /// Logs `message` to stderr, but only the first time (or the first
    /// time it changes) - see `last_logged_error`'s doc comment.
    fn log_error_once(&mut self, message: &str) {
        if self.last_logged_error.as_deref() != Some(message) {
            eprintln!("archivefs-gui: clipboard error: {message}");
            self.last_logged_error = Some(message.to_string());
        }
    }
}

impl ClipboardBackend for NativeClipboard {
    fn get_text_status(&mut self) -> ClipboardTextStatus {
        let Some(clipboard) = self.inner.as_mut() else {
            let message = self
                .init_error
                .clone()
                .unwrap_or_else(|| "clipboard backend not initialised".to_string());
            self.log_error_once(&message);
            return ClipboardTextStatus::Unavailable(message);
        };
        match clipboard.get_text() {
            Ok(text) if !text.is_empty() => ClipboardTextStatus::Ready(text),
            Ok(_) => ClipboardTextStatus::Empty,
            // `ContentNotAvailable` is arboard's own way of reporting "the
            // clipboard is empty or holds a non-text format" - a normal,
            // expected outcome, not a failure worth logging.
            Err(arboard::Error::ContentNotAvailable) => ClipboardTextStatus::Empty,
            Err(error) => {
                let message = error.to_string();
                self.log_error_once(&message);
                ClipboardTextStatus::Unavailable(message)
            }
        }
    }

    fn set_text(&mut self, text: String) -> Result<(), String> {
        let Some(clipboard) = self.inner.as_mut() else {
            let message = self
                .init_error
                .clone()
                .unwrap_or_else(|| "clipboard backend not initialised".to_string());
            self.log_error_once(&message);
            return Err(message);
        };
        clipboard.set_text(text).map_err(|error| {
            let message = error.to_string();
            self.log_error_once(&message);
            message
        })
    }
}

/// One item in the shared text-field context menu - see
/// `show_text_edit_with_context_menu`. Deliberately just these four:
/// exactly what a normal desktop text field's right-click menu offers,
/// nothing more.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum TextEditContextMenuAction {
    Cut,
    Copy,
    Paste,
    SelectAll,
}

impl TextEditContextMenuAction {
    const ALL: [Self; 4] = [Self::Cut, Self::Copy, Self::Paste, Self::SelectAll];

    fn label(self) -> &'static str {
        match self {
            Self::Cut => "Cut",
            Self::Copy => "Copy",
            Self::Paste => "Paste",
            Self::SelectAll => "Select all",
        }
    }
}
fn text_edit_context_menu_action_available(
    action: TextEditContextMenuAction,
    has_selection: bool,
    is_empty: bool,
    has_clipboard_text: bool,
) -> bool {
    match action {
        TextEditContextMenuAction::Cut | TextEditContextMenuAction::Copy => has_selection,
        TextEditContextMenuAction::Paste => has_clipboard_text,
        TextEditContextMenuAction::SelectAll => !is_empty,
    }
}
fn text_edit_selected_char_range(ctx: &egui::Context, id: egui::Id) -> Option<Range<usize>> {
    let range = egui::widgets::text_edit::TextEditState::load(ctx, id)?
        .cursor
        .char_range()?;
    (!range.is_empty()).then(|| range.as_sorted_char_range())
}

/// The field's current cursor position as a character range - a
/// selection if one exists, otherwise an empty range at the caret. Unlike
/// `text_edit_selected_char_range`, this always returns *something*:
/// Paste needs an insertion point even with no selection, falling back to
/// the end of `text` if the field has no persisted cursor state at all
/// (never out of bounds, and the only reasonable default with zero other
/// information).
fn text_edit_cursor_char_range(ctx: &egui::Context, id: egui::Id, text: &str) -> Range<usize> {
    egui::widgets::text_edit::TextEditState::load(ctx, id)
        .and_then(|state| state.cursor.char_range())
        .map(|range| range.as_sorted_char_range())
        .unwrap_or_else(|| {
            let end = text.chars().count();
            end..end
        })
}

/// Moves the field's cursor to a single position (no selection) and gives
/// it keyboard focus, so the edit this always follows is visible
/// immediately and further typing continues from the right place.
fn set_text_edit_caret(ctx: &egui::Context, id: egui::Id, char_index: usize) {
    let mut state = egui::widgets::text_edit::TextEditState::load(ctx, id).unwrap_or_default();
    state
        .cursor
        .set_char_range(Some(egui::text::CCursorRange::one(
            egui::text::CCursor::new(char_index),
        )));
    state.store(ctx, id);
    ctx.memory_mut(|memory| memory.request_focus(id));
}
fn apply_select_all(ctx: &egui::Context, id: egui::Id, text: &str) {
    let mut state = egui::widgets::text_edit::TextEditState::load(ctx, id).unwrap_or_default();
    let full_range = egui::text::CCursorRange::two(
        egui::text::CCursor::new(0),
        egui::text::CCursor::new(text.chars().count()),
    );
    state.cursor.set_char_range(Some(full_range));
    state.store(ctx, id);
    ctx.memory_mut(|memory| memory.request_focus(id));
}

/// Copy - writes exactly the selected substring (char-index sliced via
/// `TextBuffer::char_range`, so a selection ending mid-multi-byte
/// character is impossible) to the clipboard. A no-op if nothing is
/// selected; never clears or overwrites the clipboard in that case. A
/// clipboard write failure is safely discarded here (already logged by
/// `ClipboardBackend::set_text`); there is no field mutation to roll
/// back for Copy.
fn apply_copy(ctx: &egui::Context, id: egui::Id, text: &str, clipboard: &mut dyn ClipboardBackend) {
    if let Some(range) = text_edit_selected_char_range(ctx, id) {
        let _ = clipboard.set_text(text.char_range(range).to_string());
    }
}

/// Cut - copies exactly the selected substring, then removes exactly
/// that same range from `text` (via `TextBuffer::delete_char_range`, the
/// identical method `TextEdit`'s own Ctrl+X handling uses), leaving the
/// caret where the removed text started. A no-op if nothing is selected.
/// If the clipboard write fails, `text` is left completely untouched -
/// removing text the user could not actually cut anywhere would be a
/// silent data loss, not a safe degradation.
fn apply_cut(
    ctx: &egui::Context,
    id: egui::Id,
    text: &mut String,
    clipboard: &mut dyn ClipboardBackend,
) {
    let Some(range) = text_edit_selected_char_range(ctx, id) else {
        return;
    };
    if clipboard
        .set_text(text.char_range(range.clone()).to_string())
        .is_err()
    {
        return;
    }
    text.delete_char_range(range.clone());
    set_text_edit_caret(ctx, id, range.start);
}

/// Paste - inserts the clipboard's text at the caret (no selection), or
/// replaces exactly the selected range (a selection, partial or the
/// entire field) via `TextBuffer::insert_text`/`delete_char_range`, the
/// same char-index-safe methods `TextEdit`'s own Ctrl+V handling uses. A
/// no-op if the clipboard is empty *or* unavailable - both cases already
/// disable the Paste menu item (see `text_edit_context_menu_action_available`),
/// but this defends against being called anyway (e.g. a stale click).
fn apply_paste(
    ctx: &egui::Context,
    id: egui::Id,
    text: &mut String,
    clipboard: &mut dyn ClipboardBackend,
) {
    let clip_text = match clipboard.get_text_status() {
        ClipboardTextStatus::Ready(text) => text,
        ClipboardTextStatus::Empty | ClipboardTextStatus::Unavailable(_) => return,
    };
    let range = text_edit_cursor_char_range(ctx, id, text);
    if !range.is_empty() {
        text.delete_char_range(range.clone());
    }
    let inserted = text.insert_text(&clip_text, range.start);
    set_text_edit_caret(ctx, id, range.start + inserted);
}
fn clipboard_status_label(status: &ClipboardTextStatus) -> String {
    match status {
        ClipboardTextStatus::Ready(_) => "Clipboard ready".to_string(),
        ClipboardTextStatus::Empty => "Clipboard contains no text".to_string(),
        ClipboardTextStatus::Unavailable(reason) => format!("Clipboard unavailable: {reason}"),
    }
}

fn show_text_edit_with_context_menu(
    ui: &mut egui::Ui,
    text: &mut String,
    clipboard: &mut dyn ClipboardBackend,
    configure: impl FnOnce(egui::TextEdit<'_>) -> egui::TextEdit<'_>,
) -> egui::Response {
    let is_empty = text.is_empty();
    let text_edit = configure(egui::TextEdit::singleline(text));
    let output = text_edit.show(ui);
    let response = output.response;
    let id = response.id;
    let has_selection = output.cursor_range.is_some_and(|range| !range.is_empty());

    // Right-clicking to open this field's context menu also gives it
    // keyboard focus, exactly like a real desktop text field - so the
    // field visibly looks active even before any menu item is clicked.
    // This is cosmetic only now: every action below reaches the correct
    // field via its `id`, captured once above, regardless of whether
    // focus is still there by the time the user actually clicks.
    if response.secondary_clicked() {
        ui.memory_mut(|memory| memory.request_focus(id));
    }

    response.context_menu(|ui| {
        // One read per menu-open frame, shared by the status line and
        // Paste's enabled state - never a second clipboard read.
        let clipboard_status = clipboard.get_text_status();
        ui.small(clipboard_status_label(&clipboard_status));
        ui.separator();
        let has_clipboard_text = matches!(clipboard_status, ClipboardTextStatus::Ready(_));
        for action in TextEditContextMenuAction::ALL {
            let enabled = text_edit_context_menu_action_available(
                action,
                has_selection,
                is_empty,
                has_clipboard_text,
            );
            if ui
                .add_enabled(enabled, egui::Button::new(action.label()))
                .clicked()
            {
                match action {
                    TextEditContextMenuAction::Cut => apply_cut(ui.ctx(), id, text, clipboard),
                    TextEditContextMenuAction::Copy => apply_copy(ui.ctx(), id, text, clipboard),
                    TextEditContextMenuAction::Paste => apply_paste(ui.ctx(), id, text, clipboard),
                    TextEditContextMenuAction::SelectAll => apply_select_all(ui.ctx(), id, text),
                }
                ui.close();
            }
        }
    });

    response
}
fn detail_row(ui: &mut egui::Ui, label: &str, value: &str) {
    ui.strong(label);
    ui.add(egui::Label::new(value).selectable(true).wrap());
    ui.end_row();
}

fn optional_detail_row(ui: &mut egui::Ui, label: &str, value: Option<&str>) {
    if let Some(value) = value {
        detail_row(ui, label, value);
    }
}
fn detail_row_with_copy(
    ui: &mut egui::Ui,
    label: &str,
    value: &str,
    clipboard: &mut dyn ClipboardBackend,
) {
    ui.strong(label);
    ui.vertical(|ui| {
        let response = ui
            .add(
                egui::Label::new(value)
                    .selectable(true)
                    .truncate()
                    .sense(egui::Sense::click()),
            )
            .on_hover_text(value);
        if ui.small_button("Copy").clicked() {
            let _ = clipboard.set_text(value.to_string());
        }
        response.context_menu(|ui| {
            if ui.button("Copy").clicked() {
                let _ = clipboard.set_text(value.to_string());
                ui.close();
            }
            if ui.button("Select all").clicked() {
                let _ = clipboard.set_text(value.to_string());
                ui.close();
            }
            if ui.button("Show containing folder").clicked() {
                let folder = Path::new(value).parent().unwrap_or(Path::new(value));
                let _ = open_folder_in_file_manager(folder);
                ui.close();
            }
        });
    });
    ui.end_row();
}

fn archive_kind_name(kind: ArchiveKind) -> &'static str {
    match kind {
        ArchiveKind::Zip => "ZIP",
        ArchiveKind::SevenZip => "7z",
        ArchiveKind::Rar => "RAR",
        ArchiveKind::MegaDriveRom => "Mega Drive ROM",
    }
}

fn format_size(size_bytes: Option<u64>) -> String {
    size_bytes
        .map(|size| format!("{size} bytes"))
        .unwrap_or_else(|| "Unknown".to_string())
}

fn summary_value(ui: &mut egui::Ui, label: &str, value: usize) {
    // Explicit tighter vertical margin than `egui::Frame::group`'s default
    // (6px all sides): with the app-wide readability item_spacing bump
    // (see `apply_readability_style`), the Health and Duplicates pages'
    // multi-card summary rows read as having excessive empty space around
    // each card's small text. Horizontal margin is left roomier for
    // legibility; only the vertical footprint is tightened.
    egui::Frame::group(ui.style())
        .inner_margin(egui::Margin::symmetric(10, 3))
        .show(ui, |ui| {
            ui.vertical_centered(|ui| {
                ui.strong(value.to_string());
                ui.small(label);
            });
        });
}

#[derive(Clone, Copy)]
struct SummaryMetric<'a> {
    label: &'a str,
    value: usize,
    tone: widgets::StatusTone,
}

fn show_health_metric_card(ui: &mut egui::Ui, width: f32, metric: SummaryMetric<'_>) {
    let color = metric.tone.color(ui);
    let content_width = (width - 20.0).max(64.0);
    let fill = if metric.value == 0 {
        theme::card_fill(ui)
    } else {
        color.gamma_multiply(0.10)
    };
    egui::Frame::new()
        .fill(fill)
        .stroke(theme::border(ui))
        .corner_radius(7)
        .inner_margin(egui::Margin::symmetric(10, 5))
        .show(ui, |ui| {
            ui.set_min_size(egui::vec2(content_width, HEALTH_METRIC_HEIGHT - 10.0));
            ui.set_max_width(content_width);
            ui.vertical_centered(|ui| {
                let value = egui::RichText::new(metric.value.to_string()).strong();
                ui.label(if metric.value == 0 {
                    value.color(ui.visuals().weak_text_color())
                } else {
                    value.color(color)
                });
                ui.add_sized(
                    [content_width, ui.text_style_height(&egui::TextStyle::Small)],
                    egui::Label::new(egui::RichText::new(metric.label).small()).truncate(),
                )
                .on_hover_text(metric.label);
            });
        });
}

fn show_health_metric_cards(ui: &mut egui::Ui, metrics: &[SummaryMetric<'_>]) {
    let spacing = ui.spacing().item_spacing.x;
    let columns = responsive_card_columns(
        ui.available_width(),
        HEALTH_METRIC_MIN_WIDTH,
        spacing,
        metrics.len(),
    );
    if columns == 0 {
        return;
    }
    for row in metrics.chunks(columns) {
        let width = ((ui.available_width() - spacing * (columns.saturating_sub(1) as f32))
            / columns as f32)
            .max(1.0);
        ui.horizontal(|ui| {
            for metric in row {
                show_health_metric_card(ui, width, *metric);
            }
        });
    }
}

fn matching_row_indices(rows: &[ArchiveRow], filter: &str) -> Option<Vec<usize>> {
    let normalized_filter = filter.trim().to_lowercase();
    if normalized_filter.is_empty() {
        return None;
    }

    Some(
        rows.iter()
            .enumerate()
            .filter_map(|(index, row)| row.matches(&normalized_filter).then_some(index))
            .collect(),
    )
}

