    /// Mirrors `show_primary_navigation`'s exact layout (same widgets, same
    /// order, same enabled predicate, same selected predicate) purely to
    /// discover each button's rendered `Rect` for click simulation. The
    /// production function itself only returns `Option<MainView>`, not
    /// per-button geometry; egui's vertical layout is fully deterministic
    /// from widget order and size alone, so this mirror's rects match the
    /// real function's. Iterates the same `PRIMARY_NAVIGATION_DESTINATIONS`
    /// const production uses, so the mirror cannot drift from the real
    /// destination list - now just one section since sidebar consolidation
    /// removed the secondary "LIBRARY TOOLS" section entirely.
    /// The actual click below is driven through the real production
    /// function, not this mirror.
    fn primary_nav_rects(
        ctx: &egui::Context,
        current: MainView,
        has_database: bool,
    ) -> Vec<(MainView, egui::Rect)> {
        let mut rects = Vec::new();
        let _ = ctx.run(egui::RawInput::default(), |ctx| {
            egui::CentralPanel::default().show(ctx, |ui| {
                ui.vertical(|ui| {
                    ui.label(egui::RichText::new("ArchiveFS").size(23.0).strong());
                    ui.label(
                        egui::RichText::new("Archive library manager").color(theme::muted(ui)),
                    );
                    ui.add_space(18.0);
                    ui.label(
                        egui::RichText::new("WORKFLOWS")
                            .small()
                            .strong()
                            .color(theme::muted(ui)),
                    );
                    for (view, label) in PRIMARY_NAVIGATION_DESTINATIONS {
                        let enabled = navigation_destination_enabled(view, has_database);
                        let selected = navigation_destination_selected(current, view);
                        let button = egui::Button::selectable(selected, label)
                            .min_size(egui::vec2(ui.available_width(), 34.0));
                        let resp = ui.add_enabled(enabled, button);
                        rects.push((view, resp.rect));
                    }
                });
            });
        });
        rects
    }

    #[test]
    fn all_navigation_destinations_are_reachable_via_a_real_click() {
        let ctx = egui::Context::default();

        let all_destinations = PRIMARY_NAVIGATION_DESTINATIONS
            .iter()
            .map(|(view, _)| *view);
        for target in all_destinations {
            let rects = primary_nav_rects(&ctx, MainView::Library, true);
            let target_rect = rects
                .iter()
                .find(|(view, _)| *view == target)
                .map(|(_, rect)| *rect)
                .unwrap_or_else(|| panic!("{target:?} must be one of the rendered nav labels"));

            let clicked_view: std::rc::Rc<std::cell::RefCell<Option<MainView>>> =
                std::rc::Rc::new(std::cell::RefCell::new(None));
            let captured = std::rc::Rc::clone(&clicked_view);
            let render = move |ui: &mut egui::Ui| -> egui::Response {
                let inner = ui.scope(|ui| show_primary_navigation(ui, MainView::Library, true));
                if let Some(view) = inner.inner {
                    *captured.borrow_mut() = Some(view);
                }
                inner.response
            };
            simulate_row_click(
                &ctx,
                target_rect.center(),
                egui::Modifiers::default(),
                render,
            );

            assert_eq!(
                *clicked_view.borrow(),
                Some(target),
                "clicking the {target:?} label must select it as the primary destination"
            );
        }
    }
    fn rendered_text_contains(output: &egui::FullOutput, needle: &str) -> bool {
        fn shape_contains(shape: &egui::Shape, needle: &str) -> bool {
            match shape {
                egui::Shape::Text(text_shape) => text_shape.galley.text().contains(needle),
                egui::Shape::Vec(nested) => nested.iter().any(|s| shape_contains(s, needle)),
                _ => false,
            }
        }
        output
            .shapes
            .iter()
            .any(|clipped| shape_contains(&clipped.shape, needle))
    }

    /// Finds the screen-space center of the first `Shape::Text` whose
    /// laid-out string *exactly matches* `needle` (unlike
    /// `rendered_text_contains`'s substring search, an exact match is
    /// required here so e.g. "Cancel" never matches a longer label that
    /// happens to contain it) - used to click a real button inside an
    /// already-rendered `egui::Window`, where the button's position
    /// cannot be predicted by rendering an identical standalone widget
    /// (unlike a fresh panel's first widget, a window's content depends
    /// on everything painted before it and the window's own computed
    /// size/anchor).
    fn find_exact_text_center(output: &egui::FullOutput, needle: &str) -> Option<egui::Pos2> {
        fn find_in_shape(shape: &egui::Shape, needle: &str) -> Option<egui::Pos2> {
            match shape {
                egui::Shape::Text(text_shape) => (text_shape.galley.text() == needle)
                    .then(|| text_shape.pos + text_shape.galley.size() / 2.0),
                egui::Shape::Vec(nested) => nested.iter().find_map(|s| find_in_shape(s, needle)),
                _ => None,
            }
        }
        output
            .shapes
            .iter()
            .find_map(|clipped| find_in_shape(&clipped.shape, needle))
    }

    /// Counts every `Shape::Text` whose laid-out string *exactly matches*
    /// `needle` - the exact-match counterpart of `rendered_text_contains`,
    /// used where "present" isn't precise enough (e.g. confirming a
    /// heading renders exactly once, not zero or two times).
    fn count_exact_text_occurrences(output: &egui::FullOutput, needle: &str) -> usize {
        fn count_in_shape(shape: &egui::Shape, needle: &str) -> usize {
            match shape {
                egui::Shape::Text(text_shape) => usize::from(text_shape.galley.text() == needle),
                egui::Shape::Vec(nested) => nested.iter().map(|s| count_in_shape(s, needle)).sum(),
                _ => 0,
            }
        }
        output
            .shapes
            .iter()
            .map(|clipped| count_in_shape(&clipped.shape, needle))
            .sum()
    }

    /// Renders the real `show_loaded_data` (what the Library page actually
    /// dispatches to) with only `selected_archives` and
    /// `select_all_visible_requested` under the caller's control - every
